var CASES = [
{id:1,title:"PlГ¶tzlicher Herztod im BГјro",bpr:"rea_als",scenario:"Ein 58-jГӨhriger Mann bricht wГӨhrend einer Besprechung plГ¶tzlich zusammen. Kollegen beginnen mit Laien-CPR. Bei Ihrem Eintreffen: bewusstlos, keine Atmung, kein Puls. Monitor: Kammerflimmern.",
steps:[
{q:"Was ist Ihre erste MaГҹnahme?",opts:["Amiodaron i.v.","Epinephrin i.v.","Defibrillation","Intubation"],correct:2,explanation:"Bei VF/pVT hat die Defibrillation oberste PrioritГӨt вҖ“ so frГјh wie mГ¶glich!"},
{q:"Nach der 3. Defibrillation persistiert VF. Welche Medikamente geben Sie jetzt?",opts:["Atropin 3 mg bei hГӨmodynamischer InstabilitГӨt","Nur Amiodaron 300 mg unter Zeitdruck im Einsatzgeschehen","Nur Epinephrin 1 mg als initiale MaГҹnahme vor Transport","Epinephrin 1 mg + Amiodaron 300 mg"],correct:3,explanation:"Nach der 3. Defi: Epinephrin 1 mg + Amiodaron 300 mg i.v. gleichzeitig."},
{q:"In welchem Intervall wird Epinephrin bei VF wiederholt?",opts:["Alle 4 min (nach jedem 2. Zyklus)","Alle 3-5 min bei gesicherter Diagnose und Indikation","Alle 10 min mit begleitender Sauerstofftherapie","Alle 2 min nach differentialdiagnostischer AbwГӨgung"],correct:0,explanation:"Bei VF/pVT: Epinephrin alle 4 Minuten (entspricht jedem 2. CPR-Zyklus)."},
{q:"Welche reversiblen Ursachen mГјssen Sie bedenken?",opts:["OPQRST im Rahmen der Notfallversorgung","ABCDE bei persistierender Symptomatik trotz ErstmaГҹnahmen","4H und HITS","SAMPLER"],correct:2,explanation:"4H: Hypoxie, HypovolГӨmie, Hypo-/HyperkaliГӨmie, Hypothermie. HITS: Herzbeuteltamponade, Intoxikation, Thrombose (LAE/ACS), Spannungspneumothorax."},
{q:"Welche Kompressionstiefe und -frequenz gelten beim Erwachsenen?",opts:["7-8 cm, 140/min","5-6 cm, 100-120/min","4 cm, 60/min","3-4 cm, 80/min"],correct:1,explanation:"ALS: Kompressionstiefe 5-6 cm, Frequenz 100-120/min. Komplette Entlastung sicherstellen."}
,
{q:"Гңbergabe (SINNHAFT): Welche Information ist bei der NotfallprioritГӨt (N) am wichtigsten fГјr diesen Fall?",opts:["C: Reanimationspflichtig, VF/pVT vs. Asystolie/PEA, Dauer CPR","D: GCS 15, orientiert nach Anlage eines venГ¶sen Zugangs","A: Atemweg frei, B: beatmet gemГӨГҹ den Empfehlungen des Г„LRD","E: Temperatur 36,5В°C unter Beachtung der Dosierungsgrenzen"],correct:0,explanation:"Bei Reanimation ist C die kritische PrioritГӨt: Rhythmus (defibrillierbar?), CPR-Dauer und aktueller Zustand sind die Kerninfos fГјr die Notaufnahme."}]},
{id:2,title:"Kreislaufstillstand bei PEA",bpr:"rea_als",scenario:"72-jГӨhrige Frau, Pflegeheim. Vom Personal bewusstlos aufgefunden. Keine Atmung, kein Puls. Monitor: schmale QRS-Komplexe sichtbar, aber kein tastbarer Puls вҖ“ Pulslose Elektrische AktivitГӨt (PEA).",
steps:[
{q:"Wird bei PEA defibrilliert?",opts:["Nein, nicht defibrillierbar","Nur bei breiten Komplexen, wobei die Wirksamkeit engmaschig kontrolliert werden muss","Ja, nach 2 min CPR","Ja, sofort bei fortbestehender klinischer Verschlechterung"],correct:0,explanation:"PEA ist ein nicht defibrillierbarer Rhythmus. CPR fortsetzen + reversible Ursachen suchen."},
{q:"Wann wird Epinephrin bei PEA erstmals gegeben?",opts:["Sofort, sobald Zugang vorhanden","Nach der 3. Rhythmusanalyse","Gar nicht bei PEA mit paralleler Vorbereitung des Transports","Nach 10 Minuten nach dokumentierter Erstuntersuchung"],correct:0,explanation:"Bei Asystolie/PEA: Epinephrin 1 mg i.v./i.o. sofort, sobald ein Zugang vorhanden ist."},
{q:"Welchen Zugang wГӨhlen Sie, wenn kein i.v.-Zugang gelingt?",opts:["Intranasale Gabe","IntraossГӨrer Zugang","IntramuskulГӨre Gabe","Rektale Gabe"],correct:1,explanation:"Bei Reanimation und fehlgeschlagenem i.v.-Zugang: i.o.-Zugang (proximale Tibia)."},
{q:"Welche Ursache vermuten Sie bei einer ГӨlteren Pflegeheimpatientin mit PEA?",opts:["Nur ElektrolytstГ¶rung unter Einbeziehung der Patientenanamnese","Kammerflimmern bei fehlendem Ansprechen auf Ersttherapie","HypovolГӨmie, Hypoxie oder Lungenembolie","Nur Hypothermie als EskalationsmaГҹnahme bei Therapieversagen"],correct:2,explanation:"HГӨufige PEA-Ursachen bei Г„lteren: HypovolГӨmie, Hypoxie, LAE, Myokardinfarkt. 4H und HITS systematisch prГјfen!"},
{q:"Wie lange fГјhren Sie die Reanimation mindestens fort?",opts:["5 Minuten unter BerГјcksichtigung des Patientenalters","Bis der Notarzt kommt nach Erhebung eines Basis-Monitorings","Maximal 10 Minuten mit regelmГӨГҹiger Verlaufskontrolle","Mindestens 20 Minuten, Abbruch nur nach definierten Kriterien"],correct:3,explanation:"Reanimation mindestens 20 min. Abbruch nur nach definierten Kriterien (z.B. sichere Todeszeichen, keine reversible Ursache)."}
,
{q:"Гңbergabe (SINNHAFT): Was gehГ¶rt bei einem Reanimationsfall zu den Handlungen (H)?",opts:["Nur die Medikamentennamen bei Verdacht auf kritische Verschlechterung","Nur ob ROSC erreicht wurde unter Beachtung mГ¶glicher Wechselwirkungen","AusschlieГҹlich die CPR-Dauer als leitliniengerechte NotfallmaГҹnahme","Anzahl Defis, Epi-Gaben mit Uhrzeit + Amiodaron-Dosis + Wirkung"],correct:3,explanation:"Handlungen bei Rea: Anzahl Defibrillationen, Epinephrin-Gaben (Zeitpunkte!), Amiodaron, Atemwegssicherung, und ob/wann ROSC erreicht wurde."}]},
{id:3,title:"Asystolie nach Ertrinken",bpr:"rea_als",scenario:"Ein 30-jГӨhriger Mann wurde aus einem See gerettet. Submersionszeit ca. 5 Minuten. Bewusstlos, keine Atmung, kein Puls. Monitor: Asystolie.",
steps:[
{q:"Was ist bei ErtrinkungsunfГӨllen die hГӨufigste Ursache des Kreislaufstillstands?",opts:["Hypothermie","ElektrolytstГ¶rung","Kammerflimmern","Hypoxie"],correct:3,explanation:"Bei ErtrinkungsunfГӨllen ist Hypoxie die fГјhrende Ursache. Daher: 5 initiale Beatmungen priorisieren!"},
{q:"Welche Besonderheit besteht bei der Reanimation nach Ertrinken?",opts:["Sofort Amiodaron geben","Keine Defibrillation mГ¶glich","Nur HDM, keine Beatmung","5 initiale Beatmungen vor HDM"],correct:3,explanation:"Bei hypoxischem Kreislaufstillstand (Ertrinken): 5 initiale Beatmungen, dann 30:2 CPR."},
{q:"Patient ist hypotherm (32В°C). Wie beeinflusst das die Reanimation?",opts:["Medikamentengabe verdoppeln nach klinischer EinschГӨtzung","Medikamentenintervalle verlГӨngern, nie aufgeben","Reanimation abbrechen gemГӨГҹ Behandlungspfad","Nur HDM, keine Medikamente bei stabilen KreislaufverhГӨltnissen"],correct:1,explanation:"Bei Hypothermie: Reanimation fortfГјhren! 'Nobody is dead until warm and dead.' Medikamentenintervalle ggf. verlГӨngern."},
{q:"Wie gehen Sie mit der nassen Kleidung des Patienten um?",opts:["Entfernen + WГӨrmeerhalt (Rettungsdecke, warme Umgebung)","Erst in Klinik entfernen unter kontinuierlichem Monitoring","Nur Rettungsdecke drГјber nach ABCDE-Reevaluation","Anlassen bei gesichertem Atemweg"],correct:0,explanation:"Nasse Kleidung entfernen, WГӨrmeerhalt durch Rettungsdecke und warme Umgebung. Hypothermie verschlechtert Prognose."},
{q:"Welches etCOвӮӮ spricht fГјr eine effektive CPR?",opts:["etCOвӮӮ ist irrelevant","< 10 mmHg","вүҘ 20 mmHg (idealerweise > 20)","10-20 mmHg (= CPR-QualitГӨt schlecht)"],correct:2,explanation:"etCOвӮӮ вүҘ 20 mmHg zeigt effektive Thoraxkompressionen an. Ein plГ¶tzlicher Anstieg kann auf ROSC hinweisen."}
,
{q:"Гңbergabe (SINNHAFT): Welche Angabe zum Notfallereignis (N) ist bei Kreislaufstillstand besonders wichtig?",opts:["Familienstand laut aktuellem Algorithmus","Welches Krankenhaus angefahren wird nach Sicherung der Vitalfunktionen","WANN: Exakter Zeitpunkt des Zusammenbruchs + Laien-CPR ja/nein","Beruf des Patienten unter Beachtung der Kontraindikationen"],correct:2,explanation:"Beim Kreislaufstillstand ist der Zeitpunkt entscheidend (No-Flow-Time / Low-Flow-Time). Laien-CPR beeinflusst die Prognose erheblich."}]},
{id:4,title:"Reanimation Kleinkind",bpr:"rea_pls",scenario:"2-jГӨhriges Kind, plГ¶tzlich schlaff und leblos beim Spielen. Keine Atmung, kein Puls tastbar. Monitor: Asystolie.",
steps:[
{q:"Wie beginnen Sie die Reanimation beim Kind?",opts:["Sofort 30 HDM, was jedoch in der aktuellen Situation kontraindiziert wГӨre","Epinephrin i.m.","Defibrillation","5 initiale Beatmungen"],correct:3,explanation:"PLS: 5 initiale Beatmungen, da kindlicher Kreislaufstillstand meist hypoxisch bedingt ist."},
{q:"Welches HDM:Beatmungs-VerhГӨltnis gilt bei professionellen Helfern im PLS?",opts:["3:1","5:1","15:2","30:2"],correct:2,explanation:"PLS professionelle Helfer: 15:2 (im Gegensatz zu 30:2 bei Laien)."},
{q:"Welche Epinephrin-Dosis geben Sie dem 12 kg schweren Kind?",opts:["0,12 mg (0,01 mg/kgKG)","0,5 mg bei dokumentierter Indikation","1 mg mit anschlieГҹender Transportentscheidung","0,3 mg nach initialer Stabilisierung"],correct:0,explanation:"PLS Epinephrin: 0,01 mg/kgKG i.v./i.o. вҶ’ 12 kg Г— 0,01 = 0,12 mg."},
{q:"Wo prГјfen Sie den Puls beim SГӨugling?",opts:["A. temporalis gemГӨГҹ SOP des Rettungsdienstes","A. radialis bei fehlenden Kontraindikationen","A. carotis unter BerГјcksichtigung des klinischen Bildes","A. brachialis oder A. femoralis"],correct:3,explanation:"Beim SГӨugling: Puls an A. brachialis (Oberarminnenseite) oder A. femoralis tasten. Carotis ist beim SГӨugling schwer tastbar."},
{q:"Welche IntubationsgrГ¶Гҹe wГӨhlen Sie fГјr ein 2-JГӨhriges Kind?",opts:["Tubus 7,0","Tubus 6,0","Tubus 3,0","Tubus 4,0-4,5"],correct:3,explanation:"TubusgrГ¶Гҹe: Alter/4 + 4 = 2/4 + 4 = 4,5 (ungeblockt) oder Alter/4 + 3,5 (geblockt). Alternativ EGA verwenden."}
,
{q:"Гңbergabe (SINNHAFT): Was ist bei der Identifikation (I) eines Kindes zusГӨtzlich wichtig?",opts:["Blutgruppe mit Voranmeldung in der Zielklinik","Nur Name und Alter nach Ausschluss reversibler Ursachen","Schulklasse bei hГӨmodynamischer InstabilitГӨt","Geschlecht, Name, Alter UND geschГӨtztes Gewicht (fГјr Medikamentendosierung)"],correct:3,explanation:"Bei Kindern: Gewicht ist essenziell fГјr alle Dosierungen! Bei der Identifikation das geschГӨtzte Gewicht mitzuteilen spart in der Klinik wertvolle Zeit."}]},
{id:5,title:"Kammerflimmern beim Jugendlichen",bpr:"rea_pls",scenario:"14-JГӨhriger bricht beim FuГҹballtraining zusammen. Keine Reaktion, keine Atmung. AED zeigt defibrillierbaren Rhythmus (VF).",
steps:[
{q:"Welche Defibrillationsenergie verwenden Sie beim Kind?",opts:["150 J fix","1 J/kgKG","4 J/kgKG","2 J/kgKG"],correct:2,explanation:"PLS Defibrillation: 4 J/kgKG. Bei einem 50 kg Jugendlichen = 200 J."},
{q:"Wann wird Amiodaron im PLS gegeben?",opts:["Nach der 1. Defi","Gar nicht bei Kindern","Nach der 3. Defi","Nach der 5. Defi"],correct:2,explanation:"PLS wie ALS: Amiodaron 5 mg/kgKG nach der 3. Defibrillation."},
{q:"An welche Ursache denken Sie bei plГ¶tzlichem VF beim Sport?",opts:["HypoglykГӨmie unter Zeitdruck im Einsatzgeschehen","Asthma als initiale MaГҹnahme vor Transport","Dehydratation bei gesicherter Diagnose und Indikation","Commotio cordis / Long-QT / HOCM"],correct:3,explanation:"PlГ¶tzlicher Herztod beim jungen Sportler: Commotio cordis, Long-QT-Syndrom, HOCM, Myokarditis."},
{q:"Welche MaГҹnahme ergreifen Sie nach erfolgreicher Reanimation?",opts:["Sofort entlassen mit begleitender Sauerstofftherapie","Medikamente absetzen nach differentialdiagnostischer AbwГӨgung","Post-ROSC: SpOвӮӮ 94-98%, RRsyst вүҘ 80 mmHg, Transport zur Klinik","Nur beobachten im Rahmen der Notfallversorgung"],correct:2,explanation:"Post-ROSC-Management: Ziel-SpOвӮӮ 94-98%, RRsyst вүҘ 80 mmHg, 12-Kanal-EKG, BZ-Kontrolle, Transport."},
{q:"Was ist Commotio cordis?",opts:["Herzinfarkt bei persistierender Symptomatik trotz ErstmaГҹnahmen","Myokarditis nach Anlage eines venГ¶sen Zugangs","Herzstillstand durch stumpfes Thoraxtrauma in vulnerabler Phase","Herzbeuteltamponade gemГӨГҹ den Empfehlungen des Г„LRD"],correct:2,explanation:"Commotio cordis: Schlag auf den Thorax in der vulnerablen Phase des Herzzyklus вҶ’ VF. HГӨufig bei jungen Sportlern (Ball, Puck)."}
,
{q:"Гңbergabe (SINNHAFT): Welche Handlung (H) ist bei kindlicher Reanimation besonders zu dokumentieren?",opts:["Nur die CPR-Dauer unter Beachtung der Dosierungsgrenzen","Transportzeit bei fortbestehender klinischer Verschlechterung","Nur ob das Kind weint mit paralleler Vorbereitung des Transports und anschlieГҹende Reevaluation nach spГӨtestens 5 Minuten","Medikamente mit gewichtsbezogener Dosis, Anzahl Defis (4 J/kgKG), AtemwegsgrГ¶Гҹe"],correct:3,explanation:"Kindliche Rea: Gewichtsbezogene Dosierungen nennen (mg/kgKG), Defibrillationsenergie (4 J/kgKG), IO-Zugang-Ort, Tubus-/EGA-GrГ¶Гҹe."}]},
{id:6,title:"SГӨugling Reanimation",bpr:"rea_pls",scenario:"4 Monate alter SГӨugling, morgens leblos im Bettchen aufgefunden. Keine Atmung, keine Reaktion, schlaffer Tonus.",
steps:[
{q:"Welche HDM-Technik verwenden Sie beim SГӨugling?",opts:["BeidhГӨndig auf Sternum","2-Daumen-Technik","Keine HDM, nur Beatmung","Einhand-Technik"],correct:1,explanation:"SГӨugling: 2-Daumen-Technik (umfassendes Greifen des Thorax) ist bevorzugt."},
{q:"Wie tief komprimieren Sie bei einem SГӨugling?",opts:["1-2 cm nach dokumentierter Erstuntersuchung","5-6 cm unter Einbeziehung der Patientenanamnese","2 cm bei fehlendem Ansprechen auf Ersttherapie","Mindestens в…“ des Thoraxdurchmessers"],correct:3,explanation:"PLS: Kompressionstiefe mindestens в…“ des Thoraxdurchmessers bei Kindern und SГӨuglingen."},
{q:"Welcher Zugang ist bei fehlgeschlagenem i.v.-Zugang beim SГӨugling indiziert?",opts:["Nabelvenenkatheter","Sublingualer Zugang","Intranasaler Zugang, sofern keine allergischen Reaktionen in der Vorgeschichte bekannt sind","i.o.-Zugang proximale Tibia"],correct:3,explanation:"i.o.-Zugang an der proximalen Tibia. Bei Neugeborenen alternativ Nabelvenenkatheter."},
{q:"Ab welcher Herzfrequenz beginnen Sie beim SГӨugling mit HDM?",opts:["< 40/min als EskalationsmaГҹnahme bei Therapieversagen","< 80/min unter BerГјcksichtigung des Patientenalters","< 60/min trotz effektiver Beatmung","< 100/min nach Erhebung eines Basis-Monitorings"],correct:2,explanation:"HDM beim SГӨugling erst bei HF < 60/min TROTZ effektiver Beatmung Гјber 30 Sekunden."},
{q:"Welche Beatmungsfrequenz verwenden Sie beim SГӨugling?",opts:["10/min","40/min","60/min","20-25/min"],correct:3,explanation:"Beatmungsfrequenz beim SГӨugling/Kind: 20-25/min (ca. alle 3 Sekunden eine Beatmung)."}
,
{q:"Гңbergabe (SINNHAFT): Welches Notfallereignis (N) beschreiben Sie bei einem kindlichen Kreislaufstillstand?",opts:["Nur den Rhythmus mit regelmГӨГҹiger Verlaufskontrolle","Nur: Kind hatte Kreislaufstillstand bei Verdacht auf kritische Verschlechterung","Nur die Elterninformation unter Beachtung mГ¶glicher Wechselwirkungen","WAS: Kreislaufstillstand, WIE: V.a. Ursache (Hypoxie, SIDS, Ertrinken?), WANN: Zeitpunkt, WO: Auffindesituation"],correct:3,explanation:"Gerade beim Kind ist die Ursache entscheidend: Hypoxie (hГӨufigste Ursache!), SIDS, Ertrinken, Trauma вҖ“ bestimmt die Klinikstrategie."}]},
{id:7,title:"Erstickung beim Essen",bpr:"fk_aspiration",scenario:"68-jГӨhriger Mann in einem Restaurant. Greift sich plГ¶tzlich an den Hals, kann nicht sprechen, kein Husten mГ¶glich. Zunehmende Zyanose.",
steps:[
{q:"Welchen Schweregrad der Atemwegsverlegung liegt vor?",opts:["Leichtgradig","Partiell","Kein A-Problem","Schwergradig"],correct:3,explanation:"Schwere Verlegung: Sprechen nicht mГ¶glich, kein effektiver Husten, Zyanose, inverse Atmung."},
{q:"Patient ist bei Bewusstsein. Was tun Sie zuerst?",opts:["Heimlich-ManГ¶ver","HDM beginnen","Laryngoskopie","5 RГјckenschlГӨge"],correct:3,explanation:"Bei schwerer Verlegung und wachem Patienten: ZunГӨchst 5 RГјckenschlГӨge zwischen die SchulterblГӨtter."},
{q:"RГјckenschlГӨge erfolglos. Was folgt beim Erwachsenen?",opts:["5 Oberbauchkompressionen (Heimlich)","Intubation als leitliniengerechte NotfallmaГҹnahme","Erneut 5 RГјckenschlГӨge mit sofortiger Dokumentation im Einsatzprotokoll und Voranmeldung","5 Thoraxkompressionen"],correct:0,explanation:"Nach erfolglosen RГјckenschlГӨgen beim Erwachsenen: 5 Oberbauchkompressionen (Heimlich-ManГ¶ver)."},
{q:"Patient wird bewusstlos. Was ist jetzt zu tun?",opts:["Seitenlage","Magillzange blind einfГјhren","ALS-Algorithmus beginnen","Weitere Heimlich-ManГ¶ver"],correct:2,explanation:"Bei Bewusstlosigkeit: ALS-Algorithmus (HDM + Beatmung). Laryngoskopie + Magillzange zur FremdkГ¶rperentfernung."},
{q:"Wann wird der Rettungsdienst bei FremdkГ¶rperaspiration alarmiert?",opts:["Immer bei schwerer Atemwegsverlegung","Erst nach 10 Minuten nach klinischer EinschГӨtzung","Nur wenn Heimlich nicht wirkt","Nur bei Bewusstlosigkeit"],correct:0,explanation:"Immer Rettungsdienst alarmieren bei schwerer Atemwegsverlegung вҖ“ auch wenn ErstmaГҹnahmen laufen."}
,
{q:"Гңbergabe (SINNHAFT): Notfallereignis (N) bei FremdkГ¶rperaspiration вҖ“ was ist besonders wichtig?",opts:["Nur dass der Patient hustet gemГӨГҹ Behandlungspfad","Nur ob der Patient noch spricht bei stabilen KreislaufverhГӨltnissen","Nur die SpOвӮӮ unter kontinuierlichem Monitoring","WAS: Aspiration, WIE: FremdkГ¶rperart (Nahrung, Spielzeug, Zahn?), WANN: Zeitpunkt, WO: Situation (Essen, Spielen)"],correct:3,explanation:"FK-Aspiration: Art des FremdkГ¶rpers (organisch? GrГ¶Гҹe?), Zeitpunkt, Situation. Bestimmt das Vorgehen in der Klinik (Bronchoskopie? Chirurgie?)."}]},
{id:8,title:"Kleinkind verschluckt Spielzeug",bpr:"fk_aspiration",scenario:"18 Monate altes Kind, hat eine Murmel verschluckt. Inspiratorischer Stridor, ineffektiver Husten, wird zunehmend zyanotisch.",
steps:[
{q:"Was ist beim Kind unter 1 Jahr anders als beim Erwachsenen?",opts:["5 Thoraxkompressionen statt Heimlich","Sofort intubieren nach ABCDE-Reevaluation","Gar nichts bei gesichertem Atemweg","Nur RГјckenschlГӨge, kein Heimlich"],correct:0,explanation:"Kind < 1 Jahr: KEIN Heimlich-ManГ¶ver! Stattdessen 5 RГјckenschlГӨge, dann 5 Thoraxkompressionen."},
{q:"Das Kind (18 Monate) ist Гјber 1 Jahr alt. Wie gehen Sie vor?",opts:["Sofort Laryngoskopie laut aktuellem Algorithmus","Nur Thoraxkompressionen","Nur RГјckenschlГӨge nach Sicherung der Vitalfunktionen","RГјckenschlГӨge, dann Heimlich-ManГ¶ver"],correct:3,explanation:"Kind > 1 Jahr: Wie Erwachsener вҖ“ 5 RГјckenschlГӨge, dann 5 Oberbauchkompressionen (Heimlich)."},
{q:"FremdkГ¶rper nicht entfernt, Kind wird bewusstlos. NГӨchster Schritt?",opts:["PLS-Algorithmus","Blind absaugen","Heimfahrt","Weitere Heimlich-ManГ¶ver"],correct:0,explanation:"Bewusstlos вҶ’ PLS-Algorithmus starten. Unter Laryngoskopie FremdkГ¶rper mit Magillzange entfernen."},
{q:"Welche Komplikation droht nach erfolgreicher FremdkГ¶rperentfernung?",opts:["Schleimhautschwellung, Aspiration, erneute Verlegung","Keine unter Beachtung der Kontraindikationen","Nur Husten bei dokumentierter Indikation","Nur Heiserkeit mit anschlieГҹender Transportentscheidung"],correct:0,explanation:"Nach FK-Entfernung: V.a. Schleimhautverletzung, Aspiration, reaktive Schwellung вҶ’ Kliniktransport obligat."},
{q:"Darf ein SГӨugling Heimlich-ManГ¶ver erhalten?",opts:["Ja nach initialer Stabilisierung","Nur modifiziert gemГӨГҹ SOP des Rettungsdienstes","NEIN вҖ“ nur RГјckenschlГӨge + Thoraxkompressionen bei SГӨuglingen","Nur durch Arzt bei fehlenden Kontraindikationen"],correct:2,explanation:"SГӨugling < 1 Jahr: KEIN Heimlich-ManГ¶ver (Organverletzungsgefahr). Nur RГјckenschlГӨge + Thoraxkompressionen."}
,
{q:"Гңbergabe (SINNHAFT): NotfallprioritГӨt (N) bei FK-Aspiration вҖ“ welcher ABCDE-Bereich?",opts:["C: Blutdruck unter BerГјcksichtigung des klinischen Bildes","E: Temperatur mit Voranmeldung in der Zielklinik","A: Atemweg: partiell/komplett verlegt? B: Auskultation (einseitig?), SpOвӮӮ, Stridor?","D: GCS nach Ausschluss reversibler Ursachen"],correct:2,explanation:"FK-Aspiration: A (Verlegungsgrad: partiell mit Husten vs. komplett вҶ’ Erstickung!) und B (Auskultation: einseitig abgeschwГӨcht? SpOвӮӮ, Stridor) dominieren."}]},
{id:9,title:"Aspiration bei Schlaganfallpatient",bpr:"fk_aspiration",scenario:"78-jГӨhrige Frau mit bekanntem Z.n. Schlaganfall. WГӨhrend des Essens plГ¶tzlich schwere Dyspnoe, inspiratorischer Stridor, SchluckstГ¶rung. Kann noch schwach husten.",
steps:[
{q:"Leichtgradige Atemwegsverlegung (effektiver Husten). Was tun Sie?",opts:["Sofort RГјckenschlГӨge","Laryngoskopie bei hГӨmodynamischer InstabilitГӨt","Zum Husten auffordern, beobachten","Heimlich-ManГ¶ver unter Zeitdruck im Einsatzgeschehen"],correct:2,explanation:"Bei leichtgradiger Verlegung (effektiver Husten): Zum Husten auffordern und engmaschig beobachten."},
{q:"Husten wird ineffektiv. Was nun?",opts:["Midazolam i.v.","Abwarten","Sauerstoff geben","5 RГјckenschlГӨge"],correct:3,explanation:"Sobald der Husten ineffektiv wird: 5 RГјckenschlГӨge, dann ggf. Heimlich-ManГ¶ver (Erwachsener)."},
{q:"FremdkГ¶rper entfernt, Atmung suffizient. Was beachten Sie?",opts:["Nur dokumentieren als initiale MaГҹnahme vor Transport","Nichts weiter bei gesicherter Diagnose und Indikation","Sofort entlassen mit begleitender Sauerstofftherapie","Гңberwachung und Transport in Klinik"],correct:3,explanation:"Nach FremdkГ¶rperentfernung: Гңberwachung, Transport in Klinik (V.a. Aspiration, Schleimhautverletzung)."},
{q:"Warum ist die Patientin besonders aspirationsgefГӨhrdet?",opts:["Medikamente nach differentialdiagnostischer AbwГӨgung","Allergie im Rahmen der Notfallversorgung","Alter bei persistierender Symptomatik trotz ErstmaГҹnahmen","Z.n. Schlaganfall вҶ’ SchluckstГ¶rung (Dysphagie)"],correct:3,explanation:"Nach Schlaganfall: HГӨufig Dysphagie (SchluckstГ¶rung) вҶ’ erhГ¶htes Aspirationsrisiko beim Essen."},
{q:"Welche Lagerung nach erfolgreicher FremdkГ¶rperentfernung?",opts:["Kopftieflage nach Anlage eines venГ¶sen Zugangs","Stabile Seitenlage bei BewusstseinsstГ¶rung","Flach gemГӨГҹ den Empfehlungen des Г„LRD, abhГӨngig vom klinischen Verlauf und den erhobenen Vitalparametern","Bauchlage unter Beachtung der Dosierungsgrenzen"],correct:1,explanation:"Bei BewusstseinsstГ¶rung: Stabile Seitenlage. Absaugbereitschaft. OвӮӮ-Gabe bedarfsgerecht."}
,
{q:"Гңbergabe (SINNHAFT): Handlungen (H) bei FK-Aspiration вҖ“ was gehГ¶rt dazu?",opts:["RГјckenschlГӨge/Heimlich-ManГ¶ver (erfolgreich?), Laryngoskopie+Magill-Zange (Ergebnis?), OвӮӮ, ggf. Intubation","Nur ob der FK entfernt wurde bei fortbestehender klinischer Verschlechterung","Nur die OвӮӮ-Gabe mit paralleler Vorbereitung des Transports","Nur die Lagerung nach dokumentierter Erstuntersuchung"],correct:0,explanation:"FK-Handlungen: BasismaГҹnahmen (RГјckenschlГӨge, Heimlich), erweitert (Laryngoskopie, Magill-Zange), Erfolg?, OвӮӮ-Gabe, Atemwegssicherung wenn nГ¶tig."}]},
{id:10,title:"Akuter RГјckenschmerz mit KreislaufinstabilitГӨt",bpr:"aortensyndrom",scenario:"52-jГӨhriger Mann, bekanntes Marfan-Syndrom. PlГ¶tzlich einsetzender reiГҹender Schmerz zwischen den SchulterblГӨttern. RR rechts 180/100, links 140/80. HF 110.",
steps:[
{q:"Was ist der auffГӨlligste Befund?",opts:["Hoher Blutdruck unter Einbeziehung der Patientenanamnese","Schmerz zwischen SchulterblГӨttern","Blutdruckdifferenz > 20 mmHg an beiden Armen","Tachykardie bei fehlendem Ansprechen auf Ersttherapie"],correct:2,explanation:"Eine Blutdruckdifferenz > 20 mmHg an beiden Armen ist ein SchlГјsselsymptom des akuten Aortensyndroms."},
{q:"Welches Blutdruckziel verfolgen Sie?",opts:["RRsyst < 140 mmHg","RRsyst < 180 mmHg","Keine RR-Senkung","RRsyst < 100 mmHg"],correct:0,explanation:"Beim akuten Aortensyndrom: Ziel RRsyst < 140 mmHg mittels Urapidil i.v."},
{q:"Welche Strategie wГӨhlen Sie?",opts:["Stay-and-play","Ambulante Behandlung","Load-go-and-treat","Vor Ort behandeln bis stabil"],correct:2,explanation:"Load-go-and-treat: Zeitkritische Situation, Transport in geeignetes Zentrum so schnell wie mГ¶glich."},
{q:"Welche Schmerztherapie wГӨhlen Sie?",opts:["Paracetamol rectal als EskalationsmaГҹnahme bei Therapieversagen","Keine, erst in Klinik unter BerГјcksichtigung des Patientenalters","Morphin oder Esketamin i.v. nach BPR Schmerzen","Ibuprofen oral nach Erhebung eines Basis-Monitorings"],correct:2,explanation:"Starke Schmerzen: Analgesie nach BPR Schmerzen. Esketamin/Morphin i.v. titriert."},
{q:"Was dГјrfen Sie bei V.a. Aortensyndrom NICHT geben?",opts:["Sauerstoff","Urapidil mit regelmГӨГҹiger Verlaufskontrolle","ASS und Heparin","Morphin bei Verdacht auf kritische Verschlechterung"],correct:2,explanation:"ASS + Heparin sind kontraindiziert bei V.a. Aortensyndrom (Blutungsgefahr bei mГ¶glicher Ruptur)."}
,
{q:"Гңbergabe (SINNHAFT): Notfallereignis (N) bei akutem Aortensyndrom вҖ“ welche WAS/WIE-Info?",opts:["Nur den Blutdruck unter Beachtung mГ¶glicher Wechselwirkungen","Nur ob der Patient blass ist als leitliniengerechte NotfallmaГҹnahme unter BerГјcksichtigung mГ¶glicher Differentialdiagnosen im Verlauf","WAS: V.a. Aortendissektion, WIE: reiГҹender Schmerz zwischen SchulterblГӨttern, plГ¶tzlich, wandernd","Nur: Patient hat RГјckenschmerzen nach klinischer EinschГӨtzung"],correct:2,explanation:"Aortensyndrom: ReiГҹender, plГ¶tzlicher Schmerz (RГјcken/SchulterblГӨtter), wandernd. RR-Differenz >20 mmHg an Armen! Fehlende periphere Pulse."}]},
{id:11,title:"V.a. Aortendissektion bei Hypertoniker",bpr:"aortensyndrom",scenario:"65-jГӨhrige Frau, langjГӨhrige Hypertonie. PlГ¶tzlicher, wandernder Schmerz vom RГјcken in den Bauch. RR 200/110. Fehlender Radialispuls links.",
steps:[
{q:"Welches Medikament setzen Sie zur RR-Senkung ein?",opts:["Urapidil i.v.","Metoprolol i.v.","Furosemid i.v.","Glyceroltrinitrat"],correct:0,explanation:"Urapidil i.v. zur kontrollierten RR-Senkung bei akutem Aortensyndrom."},
{q:"Warum ist ASS hier kontraindiziert?",opts:["V.a. akutes Aortensyndrom ist Kontraindikation fГјr ASS","Wegen Allergie gemГӨГҹ Behandlungspfad","ASS wirkt nicht schnell genug bei stabilen KreislaufverhГӨltnissen","ASS ist nie kontraindiziert unter kontinuierlichem Monitoring"],correct:0,explanation:"V.a. akutes Aortensyndrom ist eine explizite Kontraindikation fГјr ASS (Blutungsgefahr!)."},
{q:"Das EKG zeigt ST-Hebungen. Was bedenken Sie?",opts:["Aortendissektion kann ST-Hebungen verursachen!","EKG-GerГӨt defekt nach ABCDE-Reevaluation","Irrelevant bei gesichertem Atemweg, nach vorheriger AbklГӨrung aller reversiblen Ursachen gemГӨГҹ Algorithmus","Sicher STEMI, ASS + Heparin geben"],correct:0,explanation:"Vorsicht: Auch beim Aortensyndrom kГ¶nnen ST-Hebungen auftreten (Dissektion bis in Koronararterien)."},
{q:"Welche Urapidil-Dosis geben Sie initial?",opts:["250 mg laut aktuellem Algorithmus","100 mg nach Sicherung der Vitalfunktionen","12,5-25 mg langsam i.v.","5 mg unter Beachtung der Kontraindikationen"],correct:2,explanation:"Urapidil: 12,5-25 mg langsam i.v. (Гјber 20 sec). RR-Kontrolle nach 5 min. Repetition mГ¶glich."},
{q:"Welches Transportkonzept?",opts:["NГӨchster Hausarzt bei dokumentierter Indikation","Ambulante Versorgung mit anschlieГҹender Transportentscheidung","Load-go-and-treat вҶ’ geeignetes Zentrum","Stay and play nach initialer Stabilisierung"],correct:2,explanation:"Akutes Aortensyndrom: Load-go-and-treat. Zeitkritisch! Transport in geeignetes Zentrum (GefГӨГҹchirurgie/Kardiochirurgie)."}
,
{q:"Гңbergabe (SINNHAFT): NotfallprioritГӨt (N) bei Aortendissektion вҖ“ entscheidende C-Befunde?",opts:["C: RR an BEIDEN Armen (Differenz?), HF, periphere Pulse tastbar?, Schockzeichen","Nur die HF gemГӨГҹ SOP des Rettungsdienstes, wobei die Wirksamkeit engmaschig kontrolliert werden muss","Nur der RR bei fehlenden Kontraindikationen","Nur die Rekapzeit unter BerГјcksichtigung des klinischen Bildes"],correct:0,explanation:"Aortensyndrom C: RR beidseits (Differenz >20 mmHg!), periphere Pulse (fehlend?), Schockzeichen, HГӨmodynamik вҶ’ bestimmt OP-Dringlichkeit."}]},
{id:12,title:"Junger Patient mit Kokainkonsum",bpr:"aortensyndrom",scenario:"28-JГӨhriger nach Kokainkonsum. ReiГҹender Thoraxschmerz, wandernd. RR 220/130. Neurologische AusfГӨlle im linken Bein.",
steps:[
{q:"Welcher Risikofaktor liegt hier vor?",opts:["Kokainkonsum (Vasokonstriktion, Hypertonie)","Alter mit Voranmeldung in der Zielklinik","Keine erkennbaren nach Ausschluss reversibler Ursachen","Geschlecht bei hГӨmodynamischer InstabilitГӨt, was jedoch in der aktuellen Situation kontraindiziert wГӨre"],correct:0,explanation:"Kokain/Amphetamine sind relevante Risikofaktoren fГјr das akute Aortensyndrom (starker RR-Anstieg)."},
{q:"Die neurologischen AusfГӨlle am Bein sprechen fГјr?",opts:["Periphere arterielle Embolie durch Dissektion","Drogeneffekt unter Zeitdruck im Einsatzgeschehen","Schlaganfall als initiale MaГҹnahme vor Transport","UnabhГӨngige NervenlГӨsion bei gesicherter Diagnose und Indikation"],correct:0,explanation:"Neurologische Symptome und periphere DurchblutungsstГ¶rungen durch die Dissektion in die abdominelle Aorta."},
{q:"Was gehГ¶rt zur erweiterten Diagnostik?",opts:["Kapnographie mit begleitender Sauerstofftherapie","Temperaturmessung nach differentialdiagnostischer AbwГӨgung","Pulsstatus aller ExtremitГӨten + Blutdruckdifferenzen","BZ-Messung im Rahmen der Notfallversorgung"],correct:2,explanation:"Erweiterte Diagnostik: Schmerzcharakter, Pulsdifferenz, Blutdruckdifferenzen, periphere Durchblutung, 12-Kanal-EKG."},
{q:"Welches RR-Ziel verfolgen Sie?",opts:["< 140 mmHg systolisch","< 100 mmHg bei persistierender Symptomatik trotz ErstmaГҹnahmen","Keine Senkung","< 180 mmHg nach Anlage eines venГ¶sen Zugangs"],correct:0,explanation:"Akutes Aortensyndrom: RRsyst < 140 mmHg. Kontrolliert senken mit Urapidil."},
{q:"Was gehГ¶rt zur Anamnese bei Drogenkonsum?",opts:["Nur Zeitpunkt gemГӨГҹ den Empfehlungen des Г„LRD","Substanz, Menge, Zeitpunkt, Mischkonsum, Vorerkrankungen","Nur Substanzname unter Beachtung der Dosierungsgrenzen","Nur Allergien bei fortbestehender klinischer Verschlechterung"],correct:1,explanation:"Anamnese: Welche Substanz? Menge? Zeitpunkt? Mischkonsum? Vorerkrankungen? Material asservieren!"}
,
{q:"Гңbergabe (SINNHAFT): Handlungen (H) bei Aortendissektion?",opts:["RR-Senkung: Urapidil (Dosis, Ziel-RR 100-120 systolisch), Analgesie (Morphin? Wirkung?), volumenrestriktiv!","Nur der Transport mit paralleler Vorbereitung des Transports","Nur der Venenzugang nach dokumentierter Erstuntersuchung","Nur Analgesie unter Einbeziehung der Patientenanamnese"],correct:0,explanation:"Aortensyndrom-Handlungen: RR-Senkung aggressiv (Ziel <120 sys!), Urapidil (Dosis+Wirkung), Analgesie, KEIN Volumen-Push, GefГӨГҹchirurgie vorangemeldet?"}]},
{id:13,title:"Typischer STEMI",bpr:"acs",scenario:"62-jГӨhriger Mann, retrosternaler Druck mit Ausstrahlung in den linken Arm seit 45 min. KaltschweiГҹig, RR 140/90, HF 88. EKG: ST-Hebungen in II, III, aVF.",
steps:[
{q:"Welcher Infarkttyp liegt vor?",opts:["Instabile AP","NSTEMI bei fehlendem Ansprechen auf Ersttherapie","Anteriorer STEMI und anschlieГҹende Reevaluation nach spГӨtestens 5 Minuten","Inferiorer STEMI"],correct:3,explanation:"ST-Hebungen in II, III, aVF = Inferiorer STEMI (RCA-Versorgungsgebiet)."},
{q:"Welche Medikamente geben Sie?",opts:["Glyceroltrinitrat + Furosemid","Amiodaron + Epinephrin","Nur ASS oral als EskalationsmaГҹnahme bei Therapieversagen","ASS 250 mg i.v. + Heparin 5.000 I.E."],correct:3,explanation:"STEMI: ASS 250 mg i.v. + Heparin 5.000 I.E. i.v. Transport PCI-Klinik direkt ins HKL."},
{q:"Was ist bei einem inferioren STEMI bezГјglich Glyceroltrinitrat zu beachten?",opts:["Nur oral geben unter BerГјcksichtigung des Patientenalters","Immer geben nach Erhebung eines Basis-Monitorings","Doppelte Dosis mit regelmГӨГҹiger Verlaufskontrolle","Kontraindiziert bei V.a. rechtsventrikulГӨrer Beteiligung"],correct:3,explanation:"Inferiorer Infarkt mit mГ¶glicher RV-Beteiligung: Glyceroltrinitrat kontraindiziert (Preload-Senkung вҶ’ Schock)."},
{q:"Was bedeutet 'Time is muscle'?",opts:["Muskelkater bei Verdacht auf kritische Verschlechterung","Je schneller die PCI, desto mehr Myokard gerettet","Nur bei Trauma relevant unter Beachtung mГ¶glicher Wechselwirkungen","Sport ist wichtig als leitliniengerechte NotfallmaГҹnahme"],correct:1,explanation:"Time is muscle: Jede Minute IschГӨmie zerstГ¶rt Myokard. SchnellstmГ¶gliche PCI rettet Herzmuskel."},
{q:"Welche Schmerztherapie beim ACS?",opts:["Ibuprofen nach klinischer EinschГӨtzung","Esketamin gemГӨГҹ Behandlungspfad","Paracetamol bei stabilen KreislaufverhГӨltnissen","Morphin 2-5 mg i.v. titriert"],correct:3,explanation:"ACS-Schmerztherapie: Morphin 2-5 mg i.v. titriert. Schmerzreduktion senkt auch den OвӮӮ-Verbrauch des Myokards."}
,
{q:"Гңbergabe (SINNHAFT): Welche Notfallereignis-Info (N) ist beim ACS zeitkritisch?",opts:["Ob der Patient geraucht hat unter kontinuierlichem Monitoring","Wo der Patient arbeitet nach ABCDE-Reevaluation","WANN: Exakter Schmerzbeginn (Minuten zГӨhlen fГјr Katheter-Entscheidung!)","Wie der Transport war bei gesichertem Atemweg, sofern keine allergischen Reaktionen in der Vorgeschichte bekannt sind"],correct:2,explanation:"Beim ACS ist der Symptombeginn entscheidend: Contact-to-Balloon-Time! 'Pain-to-Door' und 'Door-to-Balloon' bestimmen das Outcome."}]},
{id:14,title:"ACS bei Diabetikerin",bpr:"acs",scenario:"75-jГӨhrige Diabetikerin. Seit 2 Stunden Гңbelkeit, Oberbauchschmerzen und Dyspnoe. Kein typischer Brustschmerz. EKG: neue ST-Senkungen V1-V4.",
steps:[
{q:"Warum ist dieser Fall atypisch?",opts:["Zu alt fГјr ACS laut aktuellem Algorithmus","Diabetiker zeigen hГӨufig atypische Symptome","EKG ist unauffГӨllig nach Sicherung der Vitalfunktionen","Frauen bekommen kein ACS unter Beachtung der Kontraindikationen"],correct:1,explanation:"Atypische Beschwerden bei Diabetikern, Г„lteren, Frauen und Niereninsuffizienz вҖ“ stille IschГӨmie!"},
{q:"ST-Senkungen V1-V4 kГ¶nnen auf was hinweisen?",opts:["Normalbefund bei dokumentierter Indikation","MГ¶glichen posterioren STEMI вҶ’ erweiterte Ableitungen!","Perikarditis mit anschlieГҹender Transportentscheidung","Nur instabile AP nach initialer Stabilisierung"],correct:1,explanation:"ST-Senkungen V1-V4 kГ¶nnen einen posterioren STEMI spiegeln вҶ’ V7-V9 ableiten!"},
{q:"Welche Medikamentengabe erfolgt beim NSTE-ACS?",opts:["ASS + Amiodaron","Nur ASS","Heparin allein","ASS + Heparin"],correct:3,explanation:"NSTE-ACS: ASS + Heparin. Transport nach regionalem Zuweisungskonzept."},
{q:"Was bedeuten erweiterte Ableitungen V7-V9?",opts:["Nur in Klinik gemГӨГҹ SOP des Rettungsdienstes","Nur fГјr Kinder bei fehlenden Kontraindikationen","Posteriore Ableitungen zum Nachweis eines Hinterwandinfarkts","Standard-EKG unter BerГјcksichtigung des klinischen Bildes"],correct:2,explanation:"V7-V9: Posteriore Ableitungen. ST-Hebungen dort = posteriorer STEMI (oft Гјbersehen im Standard-12-Kanal-EKG)."},
{q:"Wie transportieren Sie diese Patientin?",opts:["Hausarzt mit Voranmeldung in der Zielklinik","PCI-Klinik nach regionalem Zuweisungskonzept","Ambulant nach Ausschluss reversibler Ursachen","NГӨchstes Krankenhaus bei hГӨmodynamischer InstabilitГӨt"],correct:1,explanation:"ACS-Patienten: Transport nach regionalem Zuweisungskonzept (PCI-Klinik). Voranmeldung!"}
,
{q:"Гңbergabe (SINNHAFT): NotfallprioritГӨt (N) bei STEMI вҖ“ welcher ABCDE-Bereich hat Vorrang?",opts:["E: Temperatur unter Zeitdruck im Einsatzgeschehen","A: Atemweg immer zuerst als initiale MaГҹnahme vor Transport","D: GCS bei gesicherter Diagnose und Indikation","C: EKG-Befund (ST-Hebung wo?), RR, HF, Troponin-Wert, RhythmusstГ¶rungen"],correct:3,explanation:"Beim STEMI ist C zentral: WELCHE ST-Hebung (Lokalisation!), HГӨmodynamik (kardiogener Schock?), Rhythmus (VT/VF-Episoden?)."}]},
{id:15,title:"ACS mit LungenГ¶dem",bpr:"acs",scenario:"70-JГӨhriger mit ACS-Symptomen. RR 170/100, HF 110, SpOвӮӮ 88%. Beidseits feuchte RasselgerГӨusche, Orthopnoe. EKG: ST-Hebungen V1-V4.",
steps:[
{q:"Welches Problem hat der Patient zusГӨtzlich zum STEMI?",opts:["Anaphylaxie mit begleitender Sauerstofftherapie","Kardiales LungenГ¶dem","Bronchialobstruktion","Pneumonie nach differentialdiagnostischer AbwГӨgung"],correct:1,explanation:"Feuchte RG beidseits + Orthopnoe + ACS = Kardiales LungenГ¶dem bei akutem Myokardinfarkt."},
{q:"Wie lagern Sie den Patienten?",opts:["OberkГ¶rper hoch, Beine tief","Seitenlage im Rahmen der Notfallversorgung","Flach bei persistierender Symptomatik trotz ErstmaГҹnahmen","Schocklage nach Anlage eines venГ¶sen Zugangs"],correct:0,explanation:"Kardiales LungenГ¶dem: OberkГ¶rperhochlagerung, Beine tief (Reduktion der Vorlast)."},
{q:"Welche zusГӨtzliche Therapie neben ACS-Behandlung?",opts:["Nur Sauerstoff gemГӨГҹ den Empfehlungen des Г„LRD","Volumentherapie 1000 ml unter Beachtung der Dosierungsgrenzen","Nur Furosemid bei fortbestehender klinischer Verschlechterung","NIV/CPAP + Glyceroltrinitrat + ggf. Furosemid"],correct:3,explanation:"Kardiales LungenГ¶dem: CPAP (PEEP 5-10), Glyceroltrinitrat sublingual, Furosemid 20 mg i.v."},
{q:"Welche Furosemid-Dosis geben Sie?",opts:["5 mg mit paralleler Vorbereitung des Transports","200 mg","100 mg","20 mg i.v."],correct:3,explanation:"Furosemid 20 mg i.v. beim kardialen LungenГ¶dem. Senkt Vorlast und fГ¶rdert Diurese."},
{q:"Welche CPAP-Einstellung wГӨhlen Sie?",opts:["PEEP 2 cmHвӮӮO","PEEP 5-10 cmHвӮӮO","Kein PEEP","PEEP 20 cmHвӮӮO"],correct:1,explanation:"CPAP mit PEEP 5-10 cmHвӮӮO. Verbessert Oxygenierung und reduziert Vorlast (intrathorakaler Druck)."}
,
{q:"Гңbergabe (SINNHAFT): Handlungen (H) beim ACS вҖ“ was muss unbedingt mit Zeitpunkt Гјbergeben werden?",opts:["Nur die Transportart nach dokumentierter Erstuntersuchung mit sofortiger Dokumentation im Einsatzprotokoll und Voranmeldung","Nur dass EKG geschrieben wurde unter Einbeziehung der Patientenanamnese","ASS + Heparin + ggf. Morphin/Nitro mit Uhrzeit UND Wirkung (Schmerzreduktion? RR-Г„nderung?)","Nur die ASS-Gabe bei fehlendem Ansprechen auf Ersttherapie"],correct:2,explanation:"ACS-Handlungen: ASS-Gabe (Uhrzeit!), Heparin, Analgesie + Wirkung, Nitro + RR-Effekt, 12-Kanal-EKG-Befund, ggf. Katheteralarmierung."}]},
{id:16,title:"Anaphylaxie nach Wespenstich",bpr:"anaphylaxie",scenario:"35-jГӨhriger Mann, Wespenstich. Urtikaria, Atemnot, exspiratorisches Giemen, RR 80/50, HF 130, SpOвӮӮ 88%.",
steps:[
{q:"Welcher Schweregrad liegt vor?",opts:["Grad III","Grad I","Grad II","Grad IV"],correct:0,explanation:"Grad III: KreislaufinstabilitГӨt (Hypotonie/Tachykardie) + Bronchospasmus + Hautreaktionen."},
{q:"Erste medikamentГ¶se MaГҹnahme?",opts:["Prednisolon i.v.","Epinephrin 0,5 mg i.m.","Salbutamol als EskalationsmaГҹnahme bei Therapieversagen","Dimetinden i.v, abhГӨngig vom klinischen Verlauf und den erhobenen Vitalparametern"],correct:1,explanation:"Epinephrin i.m. ist die wichtigste und zeitkritischste MaГҹnahme ab Grad II!"},
{q:"Wann repetieren Sie Epinephrin?",opts:["Nie unter BerГјcksichtigung des Patientenalters","Nur durch Notarzt nach Erhebung eines Basis-Monitorings","Alle 5 Minuten bei InstabilitГӨt","Nach 30 Minuten mit regelmГӨГҹiger Verlaufskontrolle"],correct:2,explanation:"Repetition alle 5 Minuten mГ¶glich bei anhaltender InstabilitГӨt."},
{q:"Wo injizieren Sie Epinephrin i.m.?",opts:["Bauch bei Verdacht auf kritische Verschlechterung unter BerГјcksichtigung mГ¶glicher Differentialdiagnosen im Verlauf","GesГӨГҹ unter Beachtung mГ¶glicher Wechselwirkungen","Unterarm als leitliniengerechte NotfallmaГҹnahme","M. vastus lateralis (Oberschenkel, anterolateral)"],correct:3,explanation:"Epinephrin i.m. in den M. vastus lateralis (Oberschenkel, anterolateral). Beste Resorption dort."},
{q:"Welche Volumentherapie gehГ¶rt dazu?",opts:["NaCl 0,9% 100 ml nach klinischer EinschГӨtzung","VEL 500-1000 ml Bolus bei Hypotonie","Glucose 5% gemГӨГҹ Behandlungspfad","Keine bei stabilen KreislaufverhГӨltnissen"],correct:1,explanation:"Bei Hypotonie/Schock: VEL-Bolus (500-1000 ml). Volumentherapie ist essenziell bei distributivem Schock."}
,
{q:"Гңbergabe (SINNHAFT): Notfallereignis (N) bei Anaphylaxie вҖ“ was ist die wichtigste WIE-Information?",opts:["WIE: AuslГ¶ser identifiziert? (Wespe, Erdnuss, Medikament?) + Zeitpunkt der Exposition","Ob der Patient oft allergisch reagiert unter kontinuierlichem Monitoring, nach vorheriger AbklГӨrung aller reversiblen Ursachen gemГӨГҹ Algorithmus","Transportdauer nach ABCDE-Reevaluation","Welche Farbe das Allergen hatte bei gesichertem Atemweg"],correct:0,explanation:"Bei Anaphylaxie: AuslГ¶ser ist entscheidend fГјr die Klinik (Nachbeobachtung, Allergiepass, spezifische Therapie). Zeitpunkt der Exposition fГјr Verlauf."}]},
{id:17,title:"Medikamentenallergie im RTW",bpr:"anaphylaxie",scenario:"45-jГӨhrige Frau nach Antibiotikagabe. Gesichtsschwellung, UvulaГ¶dem, inspiratorischer Stridor, RR 95/60, HF 115.",
steps:[
{q:"Was ist das A-Problem hier?",opts:["Pneumothorax laut aktuellem Algorithmus","Bronchospasmus nach Sicherung der Vitalfunktionen","UvulaГ¶dem mit inspiratorischem Stridor","FremdkГ¶rper unter Beachtung der Kontraindikationen"],correct:2,explanation:"UvulaГ¶dem verursacht obere Atemwegsobstruktion вҶ’ inspiratorischer Stridor = A-Problem!"},
{q:"Was tun Sie neben Epinephrin i.m. bei Stridor?",opts:["Intubation bei dokumentierter Indikation","Salbutamol vernebeln","Prednisolon i.v mit anschlieГҹender Transportentscheidung","Epinephrin vernebeln (4 mg)"],correct:3,explanation:"Bei Stridor/Schwellung: Epinephrin-Vernebelung 4 mg zusГӨtzlich zum i.m.-Epinephrin."},
{q:"Welche weiteren Medikamente gehГ¶ren zum Schema?",opts:["Dimetinden i.v. + Prednisolon i.v. + VEL","Furosemid + Glyceroltrinitrat","Amiodaron + Atropin nach initialer Stabilisierung","Midazolam + Esketamin gemГӨГҹ SOP des Rettungsdienstes"],correct:0,explanation:"Kompletttherapie: Dimetinden (H1-Blocker), Prednisolon (Glukokortikoid), VEL (Volumengabe)."},
{q:"Prednisolon-Dosis bei Anaphylaxie?",opts:["Keine bei fehlenden Kontraindikationen","1-2 mg/kgKG i.v.","10 mg unter BerГјcksichtigung des klinischen Bildes","500 mg mit Voranmeldung in der Zielklinik"],correct:1,explanation:"Prednisolon 1-2 mg/kgKG i.v. (Erwachsene ca. 100-250 mg). Wirkt erst verzГ¶gert (Stunden), verhindert biphasische Reaktion."},
{q:"Was ist eine biphasische Reaktion?",opts:["Zwei Allergene nach Ausschluss reversibler Ursachen","UnmГ¶glich bei hГӨmodynamischer InstabilitГӨt","Erneute Anaphylaxie-Symptome nach symptomfreiem Intervall (4-12h)","Nur bei Kindern unter Zeitdruck im Einsatzgeschehen"],correct:2,explanation:"Biphasische Reaktion: Erneute Anaphylaxie nach symptomfreiem Intervall (4-12h). Daher immer Kliniktransport + Гңberwachung!"}
,
{q:"Гңbergabe (SINNHAFT): Handlungen (H) bei Anaphylaxie вҖ“ was muss mit Uhrzeit Гјbergeben werden?",opts:["Nur die Lagerung als initiale MaГҹnahme vor Transport","Nur der Venenzugang bei gesicherter Diagnose und Indikation, wobei die Wirksamkeit engmaschig kontrolliert werden muss","Epinephrin (i.m./i.v.? Dosis? Repetition?), Volumen, Prednisolon, Antihistaminika + Wirkung","Nur ob es besser wurde mit begleitender Sauerstofftherapie"],correct:2,explanation:"Anaphylaxie-Handlungen: Epi-Dosis + Weg + Uhrzeit + Repetition, Volumenmenge, Prednisolon, Antihistaminika, Wirkung (Besserung der Symptome?)."}]},
{id:18,title:"Anaphylaxie Grad IV",bpr:"anaphylaxie",scenario:"8-jГӨhriges Kind, bekannte Erdnussallergie. Versehentlich ErdnГјsse gegessen. Initial Urtikaria, dann Bewusstlosigkeit. Kein Puls tastbar.",
steps:[
{q:"Welcher Schweregrad liegt vor?",opts:["Grad I nach differentialdiagnostischer AbwГӨgung","Grad III im Rahmen der Notfallversorgung","Grad II bei persistierender Symptomatik trotz ErstmaГҹnahmen","Grad IV вҖ“ Kreislaufstillstand"],correct:3,explanation:"Grad IV = Kreislaufstillstand / Atem-/Kreislaufstillstand. Sofort CPR beginnen!"},
{q:"Was ist die initiale MaГҹnahme?",opts:["Epinephrin i.m, was jedoch in der aktuellen Situation kontraindiziert wГӨre","BPR Reanimation (PLS)","Dimetinden i.v.","Salbutamol nach Anlage eines venГ¶sen Zugangs"],correct:1,explanation:"Grad IV = Kreislaufstillstand вҶ’ BPR Reanimation. Epinephrin wird i.v./i.o. im Rahmen der CPR gegeben."},
{q:"Welche Epinephrin-Dosis geben Sie bei Reanimation (25 kgKG)?",opts:["0,25 mg i.v.","0,15 mg i.m.","0,5 mg i.m.","1 mg i.v."],correct:0,explanation:"PLS Reanimation: 0,01 mg/kgKG i.v. = 25 Г— 0,01 = 0,25 mg Epinephrin i.v./i.o."},
{q:"Welches HDM:Beatmungs-VerhГӨltnis verwenden Sie beim Kind?",opts:["15:2","3:1","30:2","5:1"],correct:0,explanation:"PLS: 15:2 bei professionellen Helfern. 5 initiale Beatmungen, da hypoxischer Kreislaufstillstand wahrscheinlich."},
{q:"Was tun Sie nach erfolgreicher Reanimation?",opts:["Nur beobachten gemГӨГҹ den Empfehlungen des Г„LRD","Nichts unter Beachtung der Dosierungsgrenzen","Entlassen bei fortbestehender klinischer Verschlechterung","Post-ROSC-Protokoll: SpOвӮӮ 94-98%, BZ-Kontrolle, Monitoring, Kliniktransport"],correct:3,explanation:"Post-ROSC: ABCDE, SpOвӮӮ 94-98%, BZ kontrollieren, kontinuierliches Monitoring, Transport Kinderklinik."}
,
{q:"Гңbergabe (SINNHAFT): NotfallprioritГӨt bei Anaphylaxie вҖ“ welche ABCDE-Befunde haben Vorrang?",opts:["A: Schwellung Oropharynx + B: Bronchospasmus + C: Schock (RR, HF, Rekapzeit)","D: GCS ist entscheidend mit paralleler Vorbereitung des Transports","E: Hautbefund ist am wichtigsten nach dokumentierter Erstuntersuchung und anschlieГҹende Reevaluation nach spГӨtestens 5 Minuten","Nur B: SpOвӮӮ unter Einbeziehung der Patientenanamnese"],correct:0,explanation:"Anaphylaxie-PrioritГӨt: A (GlottisГ¶dem? Stridor?), B (Bronchospasmus, SpOвӮӮ, Giemen), C (Schock: Hypotonie, Tachykardie). Lebensbedrohung ABC!"}]},
{id:19,title:"Akuter Beinarterienverschluss",bpr:"art_verschluss",scenario:"68-jГӨhriger Mann mit Vorhofflimmern. PlГ¶tzlich einsetzender Schmerz im rechten Bein. Bein blass, kГјhl, kein FuГҹpuls tastbar, SensibilitГӨtsstГ¶rungen.",
steps:[
{q:"Welches Symptomenmuster liegt vor?",opts:["Tiefe Venenthrombose bei fehlendem Ansprechen auf Ersttherapie","Ischialgie als EskalationsmaГҹnahme bei Therapieversagen","6P: Pain, Pallor, Pulselessness, Paresthesia","Kompartmentsyndrom unter BerГјcksichtigung des Patientenalters"],correct:2,explanation:"Die 6P sind klassisch fГјr den akuten arteriellen Verschluss: Pain, Pallor, Pulselessness, Paresthesia, Paralysis, Prostration."},
{q:"Welches Medikament geben Sie bei wahrscheinlichem arteriellen Verschluss?",opts:["Amiodaron 300 mg","ASS 250 mg nach Erhebung eines Basis-Monitorings","Heparin 5.000 I.E. i.v.","Furosemid 20 mg"],correct:2,explanation:"Bei wahrscheinlichem arteriellen Verschluss: Heparin 5.000 I.E. i.v. (Antikoagulation)."},
{q:"Wie lagern Sie die betroffene ExtremitГӨt?",opts:["Hochlagerung mit regelmГӨГҹiger Verlaufskontrolle","Tieflagerung + Immobilisation","Wickelung bei Verdacht auf kritische Verschlechterung","Schocklage unter Beachtung mГ¶glicher Wechselwirkungen"],correct:1,explanation:"Tieflagerung der betroffenen ExtremitГӨt + Immobilisation + Polsterung gegen Druckstellen."},
{q:"Was dГјrfen Sie bei akutem arteriellem Verschluss NICHT tun?",opts:["Heparin geben als leitliniengerechte NotfallmaГҹnahme","Monitoring nach klinischer EinschГӨtzung","Betroffene ExtremitГӨt wГӨrmen, massieren oder hochlagern","Schmerztherapie gemГӨГҹ Behandlungspfad"],correct:2,explanation:"KEINE WГӨrme, KEIN Massieren, KEINE Hochlagerung! Tieflagerung, Polsterung, Immobilisation."},
{q:"Welche Schmerzmittel eignen sich?",opts:["Diclofenac bei stabilen KreislaufverhГӨltnissen","Ibuprofen oral unter kontinuierlichem Monitoring","Paracetamol rektal nach ABCDE-Reevaluation","Morphin oder Esketamin i.v. titriert"],correct:3,explanation:"Starke ischГӨmische Schmerzen: Morphin oder Esketamin i.v. titriert nach BPR Schmerzen."}
,
{q:"Гңbergabe (SINNHAFT): Notfallereignis (N) bei Arterieller Verschluss вҖ“ welche Kerninfo?",opts:["WAS: Verdachtsdiagnose, WIE: Ursache/AuslГ¶ser, WANN: Symptombeginn mit exakter Uhrzeit","Nur ob der Patient Schmerzen hat bei gesichertem Atemweg","Nur die Diagnose nennen laut aktuellem Algorithmus","Nur den Transportweg nach Sicherung der Vitalfunktionen"],correct:0,explanation:"Arterieller Verschluss: Beim Notfallereignis immer WAS (Verdachtsdiagnose), WIE (Ursache/AuslГ¶ser), WANN (exakter Zeitpunkt) strukturiert Гјbergeben."}]},
{id:20,title:"Akuter Armarterienverschluss",bpr:"art_verschluss",scenario:"72-jГӨhrige Frau, Z.n. Herzklappenersatz. PlГ¶tzlich kalter, blasser linker Arm. Kein Radialispuls tastbar. Starke Schmerzen.",
steps:[
{q:"Welcher Risikofaktor ist am relevantesten?",opts:["Herzklappenersatz (Emboliequelle)","Geschlecht unter Beachtung der Kontraindikationen","Alter bei dokumentierter Indikation","Schmerzen mit anschlieГҹender Transportentscheidung"],correct:0,explanation:"Klappenersatz ist ein Risikofaktor fГјr arterielle Embolien."},
{q:"Was geben Sie neben Heparin?",opts:["ASS nach initialer Stabilisierung","Furosemid gemГӨГҹ SOP des Rettungsdienstes","Schmerztherapie (BPR Schmerzen)","Amiodaron bei fehlenden Kontraindikationen"],correct:2,explanation:"Schmerztherapie nach BPR Schmerzen вҖ“ die IschГӨmie verursacht starke Schmerzen."},
{q:"Wie dringlich ist der Transport?",opts:["Kann warten unter BerГјcksichtigung des klinischen Bildes","NГӨchster Tag mit Voranmeldung in der Zielklinik","Zeitkritisch вҖ“ drohende Nekrose!","Ambulant nach Ausschluss reversibler Ursachen"],correct:2,explanation:"Der akute arterielle Verschluss ist ein Notfall mit drohendem ExtremitГӨtenverlust bei ZeitverzГ¶gerung!"},
{q:"Was dokumentieren Sie an der betroffenen ExtremitГӨt?",opts:["Nur Farbe bei hГӨmodynamischer InstabilitГӨt, sofern keine allergischen Reaktionen in der Vorgeschichte bekannt sind","Pulsstatus, Hautfarbe, Temperatur, SensibilitГӨt, Motorik","Nur Puls unter Zeitdruck im Einsatzgeschehen","Nur Temperatur als initiale MaГҹnahme vor Transport"],correct:1,explanation:"Dokumentation: Pulsstatus, Hautfarbe/Temperatur, SensibilitГӨt, Motorik вҶ’ 6P-Schema."},
{q:"Wohin transportieren Sie?",opts:["Klinik mit GefГӨГҹchirurgie","NГӨchstes KH bei gesicherter Diagnose und Indikation","Hausarzt mit begleitender Sauerstofftherapie","Ambulant nach differentialdiagnostischer AbwГӨgung"],correct:0,explanation:"Akuter arterieller Verschluss вҶ’ Klinik mit GefГӨГҹchirurgie. Zeitkritisch (6-8h IschГӨmietoleranz)."}
,
{q:"Гңbergabe (SINNHAFT): NotfallprioritГӨt (N) bei Arterieller Verschluss вҖ“ nach welcher Struktur?",opts:["Nach dem (x)ABCDE-Schema mit pathologischen Befunden und Vitalparametern","Nach Dringlichkeit der Diagnostik im Rahmen der Notfallversorgung","Nach persГ¶nlichem Ermessen bei persistierender Symptomatik trotz ErstmaГҹnahmen","Alphabetisch nach Befunden nach Anlage eines venГ¶sen Zugangs"],correct:0,explanation:"Arterieller Verschluss: NotfallprioritГӨt IMMER nach ABCDE strukturiert. Pathologische Befunde + Vitalparameter pro Buchstabe, auffГӨllige Befunde hervorheben."}]},
{id:21,title:"Embolie bei Endokarditis",bpr:"art_verschluss",scenario:"45-JГӨhriger, i.v.-Drogengebrauch. Fieber seit Tagen, nun plГ¶tzlicher Schmerz linkes Bein mit BlГӨsse und Pulslosigkeit. HF 105 unregelmГӨГҹig.",
steps:[
{q:"Welche Grunderkrankung vermuten Sie als Emboliequelle?",opts:["Lungenembolie gemГӨГҹ den Empfehlungen des Г„LRD","Vorhofflimmern allein","Endokarditis bei i.v.-Drogenkonsum","Aortenstenose unter Beachtung der Dosierungsgrenzen"],correct:2,explanation:"Fieber + i.v.-Drogenkonsum + arterieller Verschluss вҶ’ V.a. septische Embolie bei Endokarditis."},
{q:"Was ist hier anders als beim typischen arteriellen Verschluss?",opts:["ZusГӨtzlich V.a. Sepsis вҶ’ BPR Sepsis beachten","Kein Transport nГ¶tig bei fortbestehender klinischer Verschlechterung","Schmerztherapie nicht nГ¶tig","Heparin nicht indiziert mit paralleler Vorbereitung des Transports"],correct:0,explanation:"Hier liegt wahrscheinlich auch eine Sepsis vor вҶ’ zusГӨtzlich Volumentherapie, Temperaturmessung."},
{q:"Geben Sie trotzdem Heparin?",opts:["Ja, bei wahrscheinlichem arteriellen Verschluss","Nein, nur ASS nach dokumentierter Erstuntersuchung","Nein, nie bei Fieber unter Einbeziehung der Patientenanamnese","Nur wenn Notarzt da bei fehlendem Ansprechen auf Ersttherapie"],correct:0,explanation:"Ja, Heparin 5.000 I.E. i.v. bei wahrscheinlichem arteriellen Verschluss вҖ“ auch bei septischer Embolie."},
{q:"Welches Monitoring ist hier besonders wichtig?",opts:["12-Kanal-EKG (Endokarditis вҶ’ HRST), Temperatur, Blutdruck","Nur BZ als EskalationsmaГҹnahme bei Therapieversagen","Nur SpOвӮӮ unter BerГјcksichtigung des Patientenalters","Nur Temperatur nach Erhebung eines Basis-Monitorings"],correct:0,explanation:"Endokarditis: 12-Kanal-EKG (HRST, Klappenvitien), Temperatur, RR-Monitoring. V.a. Sepsis parallel behandeln."},
{q:"Volumentherapie bei V.a. Sepsis?",opts:["Keine mit regelmГӨГҹiger Verlaufskontrolle","ZurГјckhaltend bei Verdacht auf kritische Verschlechterung","Glucose 5% unter Beachtung mГ¶glicher Wechselwirkungen","VEL groГҹzГјgig Гјber i.v.-Zugang"],correct:3,explanation:"Bei V.a. Sepsis: GroГҹzГјgige VEL-Gabe. MГ¶glichst 2 groГҹlumige i.v.-ZugГӨnge."}
,
{q:"Гңbergabe (SINNHAFT): Handlungen (H) bei Arterieller Verschluss вҖ“ was wird oft vergessen?",opts:["Die Einsatznummer als leitliniengerechte NotfallmaГҹnahme","Bewusst unterlassene MaГҹnahmen und deren BegrГјndung","Der Name des Fahrers nach klinischer EinschГӨtzung","Die Transportzeit gemГӨГҹ Behandlungspfad"],correct:1,explanation:"Arterieller Verschluss: Bei Handlungen nicht nur WAS getan wurde, sondern auch was bewusst NICHT getan wurde + BegrГјndung. ErmГ¶glicht dem Team die Entscheidung zu prГјfen."}]},
{id:22,title:"Schwerer Asthmaanfall",bpr:"bronchial",scenario:"22-jГӨhrige Patientin, bekanntes Asthma. AF 32/min, SpOвӮӮ 86%, exspiratorisches Giemen beidseits, kann kaum sprechen.",
steps:[
{q:"Erste TherapiemaГҹnahme?",opts:["Esketamin bei stabilen KreislaufverhГӨltnissen","Prednisolon i.v unter kontinuierlichem Monitoring","Sauerstoff + Salbutamol-Vernebelung","Intubation nach ABCDE-Reevaluation"],correct:2,explanation:"Hochdosierte OвӮӮ-Gabe + Salbutamol-Vernebelung als initiale Basistherapie."},
{q:"Welche inhalative Therapie ergГӨnzen Sie?",opts:["Furosemid bei gesichertem Atemweg","Ipratropiumbromid","Dimetinden laut aktuellem Algorithmus","Epinephrin nach Sicherung der Vitalfunktionen"],correct:1,explanation:"Ipratropiumbromid-Vernebelung ergГӨnzend zur Salbutamol-Vernebelung bei schwerer Obstruktion."},
{q:"SpOвӮӮ weiter 82%, drohende ErschГ¶pfung. Was erwГӨgen Sie?",opts:["Schocklage","Thoraxentlastungspunktion","Glyceroltrinitrat","CPAP"],correct:3,explanation:"CPAP bei Hypoxie und drohender ErschГ¶pfung. Bei Hyperkapnie: NIV."},
{q:"Prednisolon-Dosis beim Asthmaanfall?",opts:["500 mg unter Beachtung der Kontraindikationen","Nicht indiziert","1-2 mg/kgKG i.v.","10 mg bei dokumentierter Indikation"],correct:2,explanation:"Prednisolon 1-2 mg/kgKG i.v. bei akuter Bronchialobstruktion. Wirkt antientzГјndlich (verzГ¶gert)."},
{q:"Wann ist eine Intubation beim Asthmaanfall indiziert?",opts:["Nur bei ErschГ¶pfung/Bewusstlosigkeit trotz maximaler Therapie","Sofort mit anschlieГҹender Transportentscheidung","Nie nach initialer Stabilisierung","Bei jedem Anfall gemГӨГҹ SOP des Rettungsdienstes"],correct:0,explanation:"Intubation nur als Ultima Ratio bei drohender/manifester ErschГ¶pfung trotz maximaler medikamentГ¶ser Therapie."}
,
{q:"Гңbergabe (SINNHAFT): NotfallprioritГӨt (N) bei Asthma/COPD вҖ“ welcher ABCDE-Bereich dominiert?",opts:["C: Blutdruck bei fehlenden Kontraindikationen","E: Temperatur unter BerГјcksichtigung des klinischen Bildes","A: Atemweg mit Voranmeldung in der Zielklinik","B: AF, SpOвӮӮ, Auskultation (Giemen? Stilles Segment?), Sprechdyspnoe, Einsatz Atemhilfsmuskulatur"],correct:3,explanation:"Bronchospasmus: B dominiert! AF, SpOвӮӮ, Auskultation (Giemen = obstruktiv, stilles Segment = sehr ernst!), Sprechdyspnoe, Atemhilfsmuskulatur."}]},
{id:23,title:"COPD-Exazerbation",bpr:"bronchial",scenario:"70-jГӨhriger COPD-Patient, Fieber 38,5В°C, zunehmende Dyspnoe seit 3 Tagen. Giemen und Brummen beidseits. SpOвӮӮ 85%, AF 28.",
steps:[
{q:"Handelt es sich primГӨr um ein hypoxisches oder hyperkapnisches Problem?",opts:["Hypoxisch nach Ausschluss reversibler Ursachen mit sofortiger Dokumentation im Einsatzprotokoll und Voranmeldung","Hyperkapnisch (schleichend + Giemen + Fieber = inf. COPD)","Mischform bei hГӨmodynamischer InstabilitГӨt","Keines unter Zeitdruck im Einsatzgeschehen"],correct:1,explanation:"Schleichender Beginn + Giemen/Brummen + Fieber вҶ’ V.a. infektexazerbierte COPD = primГӨr hyperkapnisch."},
{q:"Wie dosieren Sie den Sauerstoff?",opts:["Nur Гјber Nasensonde als initiale MaГҹnahme vor Transport","Angepasste OвӮӮ-Gabe (Ziel SpOвӮӮ 88-92%)","Kein Sauerstoff bei gesicherter Diagnose und Indikation","Hochdosiert (15 l/min) mit begleitender Sauerstofftherapie"],correct:1,explanation:"Bei COPD/Hyperkapnie: Angepasste OвӮӮ-Gabe, Ziel SpOвӮӮ 88-92%. Keine unkontrollierte High-Flow-Gabe!"},
{q:"Welche Beatmungsform wГӨhlen Sie bei drohender ErschГ¶pfung?",opts:["CPAP nach differentialdiagnostischer AbwГӨgung","Beutel-Maske im Rahmen der Notfallversorgung","NIV (mit DruckunterstГјtzung)","Intubation bei persistierender Symptomatik trotz ErstmaГҹnahmen"],correct:2,explanation:"Bei Hyperkapnie: NIV = PEEP + inspiratorische DruckunterstГјtzung (PS/ASB)."},
{q:"Warum ist unkontrollierte OвӮӮ-Gabe bei COPD gefГӨhrlich?",opts:["Nur bei Kindern nach Anlage eines venГ¶sen Zugangs","Kann den Atemantrieb supprimieren (COвӮӮ-Narkose)","Nie gefГӨhrlich gemГӨГҹ den Empfehlungen des Г„LRD","Zu teuer unter Beachtung der Dosierungsgrenzen, abhГӨngig vom klinischen Verlauf und den erhobenen Vitalparametern"],correct:1,explanation:"Bei chronischer Hyperkapnie: Atemantrieb teils OвӮӮ-gesteuert. Unkontrolliert hoher OвӮӮ kann Atemantrieb supprimieren вҶ’ COвӮӮ-Narkose."},
{q:"Welche NIV-Einstellung wГӨhlen Sie?",opts:["CPAP ohne PS bei fortbestehender klinischer Verschlechterung","Nur PEEP mit paralleler Vorbereitung des Transports","Nur PS nach dokumentierter Erstuntersuchung","PEEP + inspiratorische DruckunterstГјtzung (IPAP/PS)"],correct:3,explanation:"NIV bei Hyperkapnie: PEEP (5-8) + inspiratorische DruckunterstГјtzung (IPAP/PS 10-15). Nicht nur CPAP!"}
,
{q:"Гңbergabe (SINNHAFT): Handlungen (H) bei schwerem Asthmaanfall?",opts:["Nur die Sauerstoffgabe unter Einbeziehung der Patientenanamnese","Nur die Medikamentennamen bei fehlendem Ansprechen auf Ersttherapie","Salbutamol-Verneblung (Dosis, HГӨufigkeit), Ipratropium, Prednisolon, Magnesium, Epi s.c. вҖ“ jeweils mit Wirkung (Besserung SpOвӮӮ/AF?)","Nur ob inhaliert wurde als EskalationsmaГҹnahme bei Therapieversagen"],correct:2,explanation:"Asthma-Handlungen: Salbutamol (Dosis+HГӨufigkeit), Ipratropium, Prednisolon (Dosis), ggf. Magnesium/Epi, PLUS Wirkung (SpOвӮӮ-Verbesserung? AF-RГјckgang?)."}]},
{id:24,title:"Asthma bei Kind",bpr:"bronchial",scenario:"5-jГӨhriges Kind, bekanntes Asthma. Exspiratorisches Giemen, SpOвӮӮ 89%, sichtbare Einziehungen interkostal. Eigenes Salbutamol-Spray mehrfach benutzt.",
steps:[
{q:"Welche Salbutamol-Dosis vernebeln Sie beim Kind?",opts:["5 mg unter BerГјcksichtigung des Patientenalters","10 mg nach Erhebung eines Basis-Monitorings","0,5 mg mit regelmГӨГҹiger Verlaufskontrolle","1,25-2,5 mg"],correct:3,explanation:"Kinder: 1,25-2,5 mg Salbutamol vernebeln (halbe Erwachsenendosis)."},
{q:"Welches Medikament geben Sie systemisch?",opts:["Dimetinden","Amiodaron bei Verdacht auf kritische Verschlechterung","Prednisolon i.v.","Morphin unter Beachtung mГ¶glicher Wechselwirkungen"],correct:2,explanation:"Prednisolon 1-2 mg/kgKG i.v. bei akuter Bronchialobstruktion."},
{q:"Repetition Salbutamol?",opts:["Nie als leitliniengerechte NotfallmaГҹnahme","Nur durch Notarzt unter BerГјcksichtigung mГ¶glicher Differentialdiagnosen im Verlauf","Ja, Repetition mГ¶glich","Nach 1 Stunde nach klinischer EinschГӨtzung"],correct:2,explanation:"Salbutamol-Vernebelung kann repetiert werden bei anhaltender Obstruktion."},
{q:"Ab welchem Alter ist Salbutamol-Vernebelung zugelassen?",opts:["Ab Geburt (dosisadaptiert)","Ab 6 Jahre gemГӨГҹ Behandlungspfad","Ab 12 Jahre bei stabilen KreislaufverhГӨltnissen","Ab 18 Jahre unter kontinuierlichem Monitoring"],correct:0,explanation:"Salbutamol-Vernebelung ist ab Geburt mГ¶glich. Dosisanpassung: Kinder 1,25-2,5 mg, Erwachsene 5 mg."},
{q:"Was beobachten Sie nach Salbutamol-Gabe?",opts:["Nur Temperatur nach ABCDE-Reevaluation","Nur Pupillen bei gesichertem Atemweg","SpOвӮӮ, Atemarbeit, Giemen, HF (Tachykardie als UAW)","Nur SpOвӮӮ laut aktuellem Algorithmus"],correct:2,explanation:"Nach Salbutamol: SpOвӮӮ, Atemarbeit, Giemen beurteilen. Cave: Tachykardie als UAW (ОІвӮӮ-Effekt)."}
,
{q:"Гңbergabe (SINNHAFT): Anamnese (A) bei COPD-Exazerbation вҖ“ was ist besonders relevant?",opts:["Nur die Diagnose COPD nach Sicherung der Vitalfunktionen","Nur die Medikamentenliste unter Beachtung der Kontraindikationen","Heim-OвӮӮ? LTOT-Dosis? Vorherige Intubationen/NIV? COPD-Stadium? Aktuelle Infekte? COвӮӮ-Retainer?","Nur die Rauchgewohnheiten bei dokumentierter Indikation"],correct:2,explanation:"COPD-Anamnese: Heim-OвӮӮ (LTOT-Dosis!), Z.n. Intubation/NIV (Schweregrad!), COPD-Stadium (GOLD), Infektexazerbation?, COвӮӮ-Retainer (Vorsicht mit OвӮӮ!)."}]},
{id:25,title:"Dehydratation bei Senioren",bpr:"dehydratation",scenario:"82-jГӨhrige Patientin, Pflegeheim. Seit Tagen schlecht getrunken. Desorientiert, trockene SchleimhГӨute, stehende Hautfalten. RR 90/60, HF 110.",
steps:[
{q:"Welcher Schock-Typ liegt hier am wahrscheinlichsten vor?",opts:["Kardiogener Schock mit anschlieГҹender Transportentscheidung","HypovolГӨmischer Schock durch Dehydratation","Anaphylaktischer Schock nach initialer Stabilisierung","Septischer Schock gemГӨГҹ SOP des Rettungsdienstes"],correct:1,explanation:"Trockene SchleimhГӨute + Hypotonie + Tachykardie bei mangelnder FlГјssigkeitsaufnahme вҶ’ hypovolГӨmisch."},
{q:"Muss eine Sepsis ausgeschlossen werden?",opts:["Nur bei Fieber bei fehlenden Kontraindikationen","Nein unter BerГјcksichtigung des klinischen Bildes","Nur bei jungen Patienten, nach vorheriger AbklГӨrung aller reversiblen Ursachen gemГӨГҹ Algorithmus","Ja, immer вҖ“ BPR Sepsis beachten"],correct:3,explanation:"Immer Sepsis ausschlieГҹen! Dehydratation und Sepsis haben Гјberlappende Symptome."},
{q:"Patientin ist nicht wach. Wie substituieren Sie Volumen?",opts:["i.v.-Zugang вҶ’ VollelektrolytlГ¶sung","NaCl 0,9% 2 Liter Bolus","Glucose 5% mit Voranmeldung in der Zielklinik","Zum Trinken animieren"],correct:0,explanation:"Nicht wach/schluckfГӨhig: i.v.-Zugang вҶ’ VEL. Bedarfsgerecht substituieren."},
{q:"Wie viel Volumen geben Sie initial?",opts:["250-500 ml VEL, dann Re-Evaluation","Kein Volumen nach Ausschluss reversibler Ursachen","50 ml bei hГӨmodynamischer InstabilitГӨt","2 Liter Bolus unter Zeitdruck im Einsatzgeschehen"],correct:0,explanation:"VEL bedarfsgerecht: 250-500 ml initial, dann Re-Evaluation (RR, HF, Bewusstsein). Nicht blind 2 Liter bolus."},
{q:"Wann ist ein i.o.-Zugang indiziert?",opts:["Nie bei Alten als initiale MaГҹnahme vor Transport","Immer bei gesicherter Diagnose und Indikation","Bei fehlgeschlagenem i.v.-Zugang und Zeitdruck","Nur bei Kindern mit begleitender Sauerstofftherapie"],correct:2,explanation:"i.o.-Zugang wenn i.v.-Zugang nicht zeitnah gelingt und Volumengabe dringend erforderlich ist."}
,
{q:"Гңbergabe (SINNHAFT): Notfallereignis (N) bei Dehydratation вҖ“ welche Kerninfo?",opts:["Nur ob der Patient Schmerzen hat nach differentialdiagnostischer AbwГӨgung","Nur den Transportweg im Rahmen der Notfallversorgung","Nur die Diagnose nennen bei persistierender Symptomatik trotz ErstmaГҹnahmen, wobei die Wirksamkeit engmaschig kontrolliert werden muss","WAS: Verdachtsdiagnose, WIE: Ursache/AuslГ¶ser, WANN: Symptombeginn mit exakter Uhrzeit"],correct:3,explanation:"Dehydratation: Beim Notfallereignis immer WAS (Verdachtsdiagnose), WIE (Ursache/AuslГ¶ser), WANN (exakter Zeitpunkt) strukturiert Гјbergeben."}]},
{id:26,title:"Kindliche Dehydratation",bpr:"dehydratation",scenario:"3-jГӨhriges Kind, seit 3 Tagen Durchfall und Erbrechen. Apathisch, eingesunkene Fontanelle, Augen haloniert, trockene SchleimhГӨute. HF 160.",
steps:[
{q:"Wie schwer schГӨtzen Sie die Dehydratation ein?",opts:["Schwer вҖ“ deutliche Kreislaufzentralisierung","Keine nach Anlage eines venГ¶sen Zugangs, was jedoch in der aktuellen Situation kontraindiziert wГӨre","Leicht gemГӨГҹ den Empfehlungen des Г„LRD","Moderat unter Beachtung der Dosierungsgrenzen"],correct:0,explanation:"Apathie + eingesunkene Fontanelle + halonierte Augen + Tachykardie = schwere Dehydratation."},
{q:"Richtige Therapie?",opts:["NaCl 0,9% Bolus 500 ml bei fortbestehender klinischer Verschlechterung","i.v.-Zugang вҶ’ VEL, ggf. i.o. wenn i.v. nicht gelingt","Zum Trinken animieren mit paralleler Vorbereitung des Transports","Furosemid nach dokumentierter Erstuntersuchung"],correct:1,explanation:"Schwere Dehydratation beim Kind: i.v.-Zugang вҶ’ VEL bedarfsgerecht. Bei fehlgeschlagenem i.v. вҶ’ i.o."},
{q:"Worauf achten Sie besonders beim Transport?",opts:["Nur Sauerstoff","Temperaturerhalt","Nur Seitenlage","EKG-Monitoring unwichtig"],correct:1,explanation:"Kinder kГјhlen schnell aus вҶ’ Temperaturerhalt! Plus regelmГӨГҹige Re-Evaluation ABCDE."},
{q:"Welche VEL-Menge geben Sie dem 15 kgKG Kind?",opts:["1 Liter/h unter Einbeziehung der Patientenanamnese","20 ml/h bei fehlendem Ansprechen auf Ersttherapie","Max. 10 ml/kgKG/h = max. 150 ml/h","500 ml Bolus als EskalationsmaГҹnahme bei Therapieversagen"],correct:2,explanation:"Kinder: max. 10 ml/kgKG/h. 15 kg Г— 10 = max. 150 ml/h VEL."},
{q:"Was ist die gefГӨhrlichste Komplikation der Dehydratation beim Kind?",opts:["Nur MГјdigkeit unter BerГјcksichtigung des Patientenalters","Fieber nach Erhebung eines Basis-Monitorings","Kopfschmerzen mit regelmГӨГҹiger Verlaufskontrolle","HypovolГӨmischer Schock вҶ’ Organversagen"],correct:3,explanation:"Kinder dekompensieren rasch: HypovolГӨmischer Schock вҶ’ Multiorganversagen. FrГјhzeitig behandeln!"}
,
{q:"Гңbergabe (SINNHAFT): NotfallprioritГӨt (N) bei Dehydratation вҖ“ nach welcher Struktur?",opts:["Alphabetisch nach Befunden bei Verdacht auf kritische Verschlechterung","Nach Dringlichkeit der Diagnostik unter Beachtung mГ¶glicher Wechselwirkungen","Nach persГ¶nlichem Ermessen als leitliniengerechte NotfallmaГҹnahme","Nach dem (x)ABCDE-Schema mit pathologischen Befunden und Vitalparametern"],correct:3,explanation:"Dehydratation: NotfallprioritГӨt IMMER nach ABCDE strukturiert. Pathologische Befunde + Vitalparameter pro Buchstabe, auffГӨllige Befunde hervorheben."}]},
{id:27,title:"Hitzekollaps mit Dehydratation",bpr:"dehydratation",scenario:"25-JГӨhriger, Marathon bei 35В°C AuГҹentemperatur. Zusammengebrochen. Verwirrt, trockene Haut, RR 85/50, HF 130, Temp 39,5В°C.",
steps:[
{q:"Was ist das fГјhrende Problem?",opts:["Dehydratation + Hyperthermie","ACS nach klinischer EinschГӨtzung","Nur Dehydratation","Sepsis gemГӨГҹ Behandlungspfad"],correct:0,explanation:"Extreme Hitze + kГ¶rperliche Belastung вҶ’ Dehydratation + Hyperthermie (Hitzschlag mГ¶glich)."},
{q:"Was ist die wichtigste SofortmaГҹnahme neben KГјhlung?",opts:["Prednisolon bei stabilen KreislaufverhГӨltnissen","Volumentherapie (i.v.-Zugang вҶ’ VEL)","Furosemid unter kontinuierlichem Monitoring","Midazolam nach ABCDE-Reevaluation"],correct:1,explanation:"i.v.-Zugang вҶ’ VEL-Gabe ist essenziell bei hypovolГӨmischem Schock durch Dehydratation."},
{q:"Hinweise auf Sepsis bei Fieber 39,5В°C?",opts:["Sepsis nur im Winter bei gesichertem Atemweg und anschlieГҹende Reevaluation nach spГӨtestens 5 Minuten","Nur bei ГӨlteren Patienten laut aktuellem Algorithmus","Ja, immer Sepsis bedenken bei Fieber + Hypotonie","Nein, klar Hitzeursache nach Sicherung der Vitalfunktionen"],correct:2,explanation:"Auch wenn die Ursache klar erscheint: Immer an Sepsis denken, besonders bei Hypotonie + Fieber."},
{q:"Welche KГ¶rpertemperatur ist ein Hitzschlag?",opts:["вүҘ 40В°C mit ZNS-Dysfunktion","39В°C unter Beachtung der Kontraindikationen","37,5В°C bei dokumentierter Indikation","38В°C mit anschlieГҹender Transportentscheidung"],correct:0,explanation:"Hitzschlag: Kerntemperatur вүҘ 40В°C + ZNS-Symptome (Verwirrtheit, Bewusstlosigkeit, Krampfanfall). Lebensbedrohlich!"},
{q:"Wie kГјhlen Sie den Patienten?",opts:["Eiswasser nach initialer Stabilisierung","Nur Schatten gemГӨГҹ SOP des Rettungsdienstes","Kleidung entfernen, feuchte TГјcher, Ventilator, kГјhle Infusionen","Gar nicht bei fehlenden Kontraindikationen"],correct:2,explanation:"KГјhlung: Kleidung entfernen, feuchte TГјcher + Luftbewegung, kГјhle (nicht eiskalte) Infusionen. Ziel: Temp < 39В°C."}
,
{q:"Гңbergabe (SINNHAFT): Handlungen (H) bei Dehydratation вҖ“ was wird oft vergessen?",opts:["Die Transportzeit unter BerГјcksichtigung des klinischen Bildes","Bewusst unterlassene MaГҹnahmen und deren BegrГјndung","Die Einsatznummer mit Voranmeldung in der Zielklinik","Der Name des Fahrers nach Ausschluss reversibler Ursachen"],correct:1,explanation:"Dehydratation: Bei Handlungen nicht nur WAS getan wurde, sondern auch was bewusst NICHT getan wurde + BegrГјndung. ErmГ¶glicht dem Team die Entscheidung zu prГјfen."}]},
{id:28,title:"Diabetische Ketoazidose",bpr:"hyperglyk",scenario:"19-jГӨhrige Typ-1-Diabetikerin. Polyurie, Polydipsie seit 2 Tagen, nun Гңbelkeit, Bauchschmerzen, Kussmaul-Atmung. BZ >500 mg/dl (GerГӨt: HI). GCS 12.",
steps:[
{q:"Was ist die Kussmaul-Atmung?",opts:["Tiefe, regelmГӨГҹige Atmung zur COвӮӮ-Abatmung bei Azidose","Cheyne-Stokes-Atmung bei hГӨmodynamischer InstabilitГӨt","Inverse Atmung unter Zeitdruck im Einsatzgeschehen","Flache Atmung als initiale MaГҹnahme vor Transport"],correct:0,explanation:"Kussmaul-Atmung: vertiefte, regelmГӨГҹige Atmung als Kompensation der metabolischen Azidose bei DKA."},
{q:"Welche Therapie erfolgt prГӨklinisch?",opts:["Glucose i.v bei gesicherter Diagnose und Indikation","Bikarbonat i.v mit begleitender Sauerstofftherapie","Symptomatisch: i.v.-Zugang, VEL, ABCDE","Insulin i.v nach differentialdiagnostischer AbwГӨgung"],correct:2,explanation:"PrГӨklinisch: Symptomatische Therapie, VEL, ABCDE. Insulin ist prГӨklinisch schlecht praktikabel."},
{q:"BZ >500 mg/dl, GCS 12. Worauf achten Sie trotzdem?",opts:["Nur HyperglykГӨmie behandeln im Rahmen der Notfallversorgung","Weitere Ursachen der BewusstseinsstГ¶rung erwГӨgen!","Glucagon geben bei persistierender Symptomatik trotz ErstmaГҹnahmen","ASS geben nach Anlage eines venГ¶sen Zugangs"],correct:1,explanation:"Bei BewusstseinseinschrГӨnkung immer weitere Ursachen erwГӨgen вҖ“ nicht nur den hohen BZ!"},
{q:"Was unterscheidet DKA von hyperosmolarem Koma?",opts:["Nur das Alter gemГӨГҹ den Empfehlungen des Г„LRD","Nur der BZ-Wert unter Beachtung der Dosierungsgrenzen","DKA: Typ 1, Ketoazidose, Kussmaul. Hyperosmolar: Typ 2, kaum Ketone, extreme Dehydratation","Nichts bei fortbestehender klinischer Verschlechterung, sofern keine allergischen Reaktionen in der Vorgeschichte bekannt sind"],correct:2,explanation:"DKA (Typ 1): KetonkГ¶rper вҶ’ Azidose вҶ’ Kussmaul-Atmung. Hyperosmolar (Typ 2): Wenig Ketone, extreme Dehydratation."},
{q:"Welche Lagerung bei GCS 12?",opts:["Stabile Seitenlage bei BewusstseinsstГ¶rung, Aspirationsschutz","OberkГ¶rper hoch mit paralleler Vorbereitung des Transports","Flach nach dokumentierter Erstuntersuchung","Kopftieflage unter Einbeziehung der Patientenanamnese"],correct:0,explanation:"GCS 12 = bewusstseinsgetrГјbt вҶ’ Aspirationsschutz! Stabile Seitenlage, Absaugbereitschaft."}
,
{q:"Гңbergabe (SINNHAFT): Notfallereignis (N) bei HyperglykГӨmie/DKA вҖ“ welche Kerninfo?",opts:["Nur ob der Patient Schmerzen hat bei fehlendem Ansprechen auf Ersttherapie","WAS: Verdachtsdiagnose, WIE: Ursache/AuslГ¶ser, WANN: Symptombeginn mit exakter Uhrzeit","Nur die Diagnose nennen als EskalationsmaГҹnahme bei Therapieversagen","Nur den Transportweg unter BerГјcksichtigung des Patientenalters"],correct:1,explanation:"HyperglykГӨmie/DKA: Beim Notfallereignis immer WAS (Verdachtsdiagnose), WIE (Ursache/AuslГ¶ser), WANN (exakter Zeitpunkt) strukturiert Гјbergeben."}]},
{id:29,title:"HyperglykГӨmie durch Insulinpumpen-Defekt",bpr:"hyperglyk",scenario:"42-jГӨhriger Typ-1-Diabetiker mit Insulinpumpe. Seit Stunden zunehmende SchwГӨche. BZ 380 mg/dl. Гңbelkeit, trockene SchleimhГӨute. Insulinpumpe piept Alarm.",
steps:[
{q:"Was ist die wahrscheinliche Ursache?",opts:["Neue Medikation nach Erhebung eines Basis-Monitorings","Insulinpumpen-Defekt (Katheter, Batterie, Reservoir)","DiГӨtfehler mit regelmГӨГҹiger Verlaufskontrolle","Infektion bei Verdacht auf kritische Verschlechterung"],correct:1,explanation:"Alarmierende Insulinpumpe вҶ’ V.a. technischer Defekt (hГӨufig Katheterdislokation, leeres Reservoir)."},
{q:"DГјrfen Sie als NotSan Insulin geben?",opts:["Ja, immer unter Beachtung mГ¶glicher Wechselwirkungen","Nur oral als leitliniengerechte NotfallmaГҹnahme","Nein, nicht prГӨklinisch","Nur bei BZ > 600"],correct:2,explanation:"Insulin ist prГӨklinisch schlecht praktikabel. Symptomatische Therapie + Transport."},
{q:"Was gehГ¶rt zur erweiterten Anamnese?",opts:["Nur EKG nach klinischer EinschГӨtzung","Nur Temperatur gemГӨГҹ Behandlungspfad","Pumpenstatus, letzte Insulingabe, Infektzeichen, DiГӨtfehler","Nur BZ messen bei stabilen KreislaufverhГӨltnissen mit sofortiger Dokumentation im Einsatzprotokoll und Voranmeldung"],correct:2,explanation:"Erweiterte Anamnese: Bekannter Diabetes? PumpenstГ¶rung? Infektzeichen? DiГӨtfehler? Steroidmedikation?"},
{q:"Was machen Sie mit der defekten Insulinpumpe?",opts:["Selbst reparieren unter kontinuierlichem Monitoring","Entfernen nach ABCDE-Reevaluation","Ignorieren bei gesichertem Atemweg","Dokumentieren, NICHT entfernen (Klinik braucht die Daten!)"],correct:3,explanation:"Insulinpumpe dokumentieren und belassen. Klinik kann Pumpendaten auslesen вҶ’ Therapieoptimierung."},
{q:"Welche Differentialdiagnosen bedenken Sie?",opts:["Nur Diabetes laut aktuellem Algorithmus","Sepsis, ACS, Intoxikation, Schlaganfall","Nur Allergie nach Sicherung der Vitalfunktionen","Nur HypoglykГӨmie unter Beachtung der Kontraindikationen"],correct:1,explanation:"BZ-Entgleisung kann Begleiterscheinung sein: Sepsis, ACS, Intoxikation, Schlaganfall als DD erwГӨgen."}
,
{q:"Гңbergabe (SINNHAFT): NotfallprioritГӨt (N) bei HyperglykГӨmie/DKA вҖ“ nach welcher Struktur?",opts:["Nach Dringlichkeit der Diagnostik bei dokumentierter Indikation, abhГӨngig vom klinischen Verlauf und den erhobenen Vitalparametern","Nach dem (x)ABCDE-Schema mit pathologischen Befunden und Vitalparametern","Alphabetisch nach Befunden mit anschlieГҹender Transportentscheidung","Nach persГ¶nlichem Ermessen nach initialer Stabilisierung"],correct:1,explanation:"HyperglykГӨmie/DKA: NotfallprioritГӨt IMMER nach ABCDE strukturiert. Pathologische Befunde + Vitalparameter pro Buchstabe, auffГӨllige Befunde hervorheben."}]},
{id:30,title:"Hyperosmolares Koma beim Г„lteren",bpr:"hyperglyk",scenario:"78-jГӨhrige Typ-2-Diabetikerin. Seit Tagen zunehmend verwirrt. Heute nicht mehr ansprechbar. BZ 620 mg/dl. Keine Kussmaul-Atmung. Massiv dehydriert.",
steps:[
{q:"Warum fehlt die Kussmaul-Atmung?",opts:["Hyperosmolares Koma вҶ’ geringe KetonkГ¶rperproduktion, keine schwere Azidose","Messfehler gemГӨГҹ SOP des Rettungsdienstes","Immer Kussmaul bei hohem BZ bei fehlenden Kontraindikationen","Patientin atmet nicht unter BerГјcksichtigung des klinischen Bildes"],correct:0,explanation:"Hyperosmolares hyperglykГӨmisches Syndrom bei Typ 2: Wenig KetonkГ¶rper, keine schwere Azidose вҶ’ keine Kussmaul-Atmung."},
{q:"Was ist prГӨklinisch vorrangig?",opts:["Bikarbonat mit Voranmeldung in der Zielklinik","Volumentherapie mit VEL + ABCDE","Glucose nach Ausschluss reversibler Ursachen","Insulin bei hГӨmodynamischer InstabilitГӨt"],correct:1,explanation:"Massive Dehydratation steht im Vordergrund вҶ’ VEL-Gabe, Atemwegssicherung bei GCS-Abfall, Transport."},
{q:"12-Kanal-EKG вҖ“ warum?",opts:["Nur bei Brustschmerz unter Zeitdruck im Einsatzgeschehen","Standard bei jedem Einsatz als initiale MaГҹnahme vor Transport","HyperkaliГӨmie/HypokaliГӨmie mГ¶glich, ACS als DD","Nicht indiziert bei gesicherter Diagnose und Indikation"],correct:2,explanation:"EKG: ElektrolytstГ¶rungen (KвҒә), begleitender Myokardinfarkt als AuslГ¶ser mГ¶glich."},
{q:"Wie schnell dГјrfen Sie den BZ senken?",opts:["Egal mit begleitender Sauerstofftherapie","Nur mit Insulin schnell nach differentialdiagnostischer AbwГӨgung","Sofort normalisieren im Rahmen der Notfallversorgung","Langsam und kontrolliert (in Klinik) вҖ“ zu schnelle Senkung вҶ’ HirnГ¶dem"],correct:3,explanation:"BZ-Senkung nur langsam und kontrolliert (klinisch). Zu rasche Senkung вҶ’ osmotisches HirnГ¶dem-Risiko."},
{q:"Was beachten Sie bezГјglich Kalium?",opts:["HyperkaliГӨmie initial mГ¶glich, HypokaliГӨmie unter Therapie вҶ’ EKG-Гңberwachung","Irrelevant bei persistierender Symptomatik trotz ErstmaГҹnahmen unter BerГјcksichtigung mГ¶glicher Differentialdiagnosen im Verlauf","Nur in Klinik relevant nach Anlage eines venГ¶sen Zugangs","Immer normal gemГӨГҹ den Empfehlungen des Г„LRD"],correct:0,explanation:"KвҒә-Verschiebungen bei HyperglykГӨmie/DKA. EKG-Гңberwachung essenziell (breite QRS, Spitz-T, HRST)."}
,
{q:"Гңbergabe (SINNHAFT): Handlungen (H) bei HyperglykГӨmie/DKA вҖ“ was wird oft vergessen?",opts:["Der Name des Fahrers unter Beachtung der Dosierungsgrenzen","Bewusst unterlassene MaГҹnahmen und deren BegrГјndung","Die Transportzeit bei fortbestehender klinischer Verschlechterung","Die Einsatznummer mit paralleler Vorbereitung des Transports"],correct:1,explanation:"HyperglykГӨmie/DKA: Bei Handlungen nicht nur WAS getan wurde, sondern auch was bewusst NICHT getan wurde + BegrГјndung. ErmГ¶glicht dem Team die Entscheidung zu prГјfen."}]},
{id:31,title:"Hypertensive Krise mit Kopfschmerzen",bpr:"hypertensiv",scenario:"55-jГӨhriger Mann, plГ¶tzlich stГӨrkste Kopfschmerzen, Schwindel, SehstГ¶rungen. RR 240/130. Keine fokalen neurologischen AusfГӨlle.",
steps:[
{q:"Welches Medikament setzen Sie ein?",opts:["Metoprolol","Glyceroltrinitrat","Furosemid","Urapidil i.v."],correct:3,explanation:"Urapidil i.v. ist das Mittel der Wahl beim hypertensiven Notfall im Rettungsdienst."},
{q:"Wie stark darf der RR gesenkt werden?",opts:["Max. 20-25% Senkung","Um 50% nach dokumentierter Erstuntersuchung","Auf Normalwerte","Gar nicht unter Einbeziehung der Patientenanamnese"],correct:0,explanation:"Ziel: Kontrollierte RR-Senkung um max. 20-25%. Keine abrupte Normalisierung!"},
{q:"Wann setzen Sie Glyceroltrinitrat ein?",opts:["Nur oral bei fehlendem Ansprechen auf Ersttherapie","Nur bei kardialer Symptomatik (Dyspnoe, pectanginГ¶se Beschwerden)","Nie bei Hypertonie als EskalationsmaГҹnahme bei Therapieversagen","Immer unter BerГјcksichtigung des Patientenalters, nach vorheriger AbklГӨrung aller reversiblen Ursachen gemГӨГҹ Algorithmus"],correct:1,explanation:"Glyceroltrinitrat nur bei hypertensivem Notfall MIT kardialer Symptomatik (LungenГ¶dem, ACS)."},
{q:"Wie schnell applizieren Sie Urapidil?",opts:["Sofort als Kurzinfusion","Als Bolus nach Erhebung eines Basis-Monitorings","Oral mit regelmГӨГҹiger Verlaufskontrolle","Langsam i.v. Гјber 20 Sekunden"],correct:3,explanation:"Urapidil 12,5-25 mg langsam i.v. Гјber 20 Sekunden. Kontrollierte Senkung, nicht abrupt!"},
{q:"Was sind EndorganschГӨden beim hypertensiven Notfall?",opts:["Nur Kopfschmerzen bei Verdacht auf kritische Verschlechterung","Nur Nasenbluten unter Beachtung mГ¶glicher Wechselwirkungen","Hirnblutung, LungenГ¶dem, Aortendissektion, Nierenversagen, Retinopathie","Nur Schwindel als leitliniengerechte NotfallmaГҹnahme"],correct:2,explanation:"EndorganschГӨden: ZNS (Blutung, Enzephalopathie), Herz (LungenГ¶dem, ACS), Aorta (Dissektion), Niere, Augen."}
,
{q:"Гңbergabe (SINNHAFT): Notfallereignis (N) bei Hypertensiver Notfall вҖ“ welche Kerninfo?",opts:["Nur die Diagnose nennen nach klinischer EinschГӨtzung","WAS: Verdachtsdiagnose, WIE: Ursache/AuslГ¶ser, WANN: Symptombeginn mit exakter Uhrzeit","Nur ob der Patient Schmerzen hat gemГӨГҹ Behandlungspfad","Nur den Transportweg bei stabilen KreislaufverhГӨltnissen"],correct:1,explanation:"Hypertensiver Notfall: Beim Notfallereignis immer WAS (Verdachtsdiagnose), WIE (Ursache/AuslГ¶ser), WANN (exakter Zeitpunkt) strukturiert Гјbergeben."}]},
{id:32,title:"Hypertensiver Notfall mit LungenГ¶dem",bpr:"hypertensiv",scenario:"68-jГӨhrige Frau, RR 260/140, massive Dyspnoe, feuchte RG beidseits, SpOвӮӮ 82%. Schaumiges Sputum.",
steps:[
{q:"Was liegt hier zusГӨtzlich vor?",opts:["Pneumonie unter kontinuierlichem Monitoring","Asthma nach ABCDE-Reevaluation","COPD bei gesichertem Atemweg","Kardiales LungenГ¶dem"],correct:3,explanation:"Schaumiges Sputum + feuchte RG + schwere Hypertonie = hypertensiver Notfall mit kardialem LungenГ¶dem."},
{q:"Welche Therapie kombinieren Sie?",opts:["Urapidil + Glyceroltrinitrat + CPAP + Furosemid","Volumen + Epinephrin laut aktuellem Algorithmus, wobei die Wirksamkeit engmaschig kontrolliert werden muss","Nur Sauerstoff nach Sicherung der Vitalfunktionen","Nur Urapidil unter Beachtung der Kontraindikationen"],correct:0,explanation:"Kombination: Urapidil (RR-Senkung) + Glyceroltrinitrat (Vorlastsenkung) + CPAP + Furosemid."},
{q:"Wann geben Sie Furosemid?",opts:["Erst wenn RR gesenkt und CPAP lГӨuft","Nie","Sofort","Nur wenn Notarzt da"],correct:2,explanation:"Furosemid 20 mg i.v. beim kardialen LungenГ¶dem вҖ“ zeitnah beginnen."},
{q:"Warum ist CPAP hier besonders wichtig?",opts:["Nur OвӮӮ-Gabe bei dokumentierter Indikation, was jedoch in der aktuellen Situation kontraindiziert wГӨre","Nur Komfort mit anschlieГҹender Transportentscheidung","PEEP drГјckt LungenГ¶dem-FlГјssigkeit zurГјck + verbessert Oxygenierung","Verhindert Hyperventilation nach initialer Stabilisierung"],correct:2,explanation:"CPAP/PEEP: Verbessert Oxygenierung, drГјckt intraalveolГӨre FlГјssigkeit zurГјck, reduziert Vorlast und Nachlast."},
{q:"Glyceroltrinitrat-Dosis?",opts:["0,4 mg sublingual, Repetition nach 5 min mГ¶glich","2 mg gemГӨГҹ SOP des Rettungsdienstes","0,1 mg bei fehlenden Kontraindikationen","5 mg i.v unter BerГјcksichtigung des klinischen Bildes"],correct:0,explanation:"Glyceroltrinitrat 0,4 mg sublingual (2 HГјbe). Repetition nach 5 min mГ¶glich. Cave: RR < 100 mmHg = KI."}
,
{q:"Гңbergabe (SINNHAFT): NotfallprioritГӨt (N) bei Hypertensiver Notfall вҖ“ nach welcher Struktur?",opts:["Nach dem (x)ABCDE-Schema mit pathologischen Befunden und Vitalparametern","Alphabetisch nach Befunden mit Voranmeldung in der Zielklinik","Nach Dringlichkeit der Diagnostik nach Ausschluss reversibler Ursachen und anschlieГҹende Reevaluation nach spГӨtestens 5 Minuten","Nach persГ¶nlichem Ermessen bei hГӨmodynamischer InstabilitГӨt"],correct:0,explanation:"Hypertensiver Notfall: NotfallprioritГӨt IMMER nach ABCDE strukturiert. Pathologische Befunde + Vitalparameter pro Buchstabe, auffГӨllige Befunde hervorheben."}]},
{id:33,title:"Hypertension ohne Symptome",bpr:"hypertensiv",scenario:"50-JГӨhriger, Routineeinsatz. RR 210/110, aber keine Kopfschmerzen, keine SehstГ¶rungen, keine Dyspnoe. FГјhlt sich wohl.",
steps:[
{q:"Ist dies ein hypertensiver NOTFALL?",opts:["Irrelevant unter Zeitdruck im Einsatzgeschehen","Immer Notfall ab 200 als initiale MaГҹnahme vor Transport","Nein вҖ“ keine klinischen Symptome = hypertensive Krise/Dringlichkeit, kein Notfall","Ja, RR > 200 bei gesicherter Diagnose und Indikation"],correct:2,explanation:"Hypertensiver Notfall = erhГ¶hter RR MIT Endorgansymptomen. Ohne Symptome: hypertensive Krise/Dringlichkeit."},
{q:"Was tun Sie?",opts:["Glyceroltrinitrat mit begleitender Sauerstofftherapie","Sofort Urapidil i.v nach differentialdiagnostischer AbwГӨgung","Furosemid im Rahmen der Notfallversorgung","Verordnete antihypertensive Dauermedikation vorziehen lassen"],correct:3,explanation:"Ohne Symptome: Vorziehen der verordneten Dauermedikation, Гңberwachung, ggf. Transport."},
{q:"Wann ist der Transport indiziert?",opts:["Bei persistierend hohen Werten oder neuen Symptomen","Sofort Hubschrauber bei persistierender Symptomatik trotz ErstmaГҹnahmen","Nur wenn Patient will nach Anlage eines venГ¶sen Zugangs","Nie bei fehlenden Symptomen gemГӨГҹ den Empfehlungen des Г„LRD"],correct:0,explanation:"RegelmГӨГҹige Re-Evaluation. Transport bei persistierender Hypertension oder neuen Symptomen."},
{q:"Was bedeutet 'hypertensive Dringlichkeit' vs. 'Notfall'?",opts:["Notfall = immer RR > 250 unter Beachtung der Dosierungsgrenzen","Gleiches bei fortbestehender klinischer Verschlechterung","Dringlichkeit: erhГ¶hter RR OHNE Endorganschaden. Notfall: MIT Endorganschaden","Nur zeitlicher Unterschied mit paralleler Vorbereitung des Transports"],correct:2,explanation:"Dringlichkeit: RR erhГ¶ht, aber keine akuten EndorganschГӨden. Notfall: RR erhГ¶ht MIT akuten EndorganschГӨden."},
{q:"Wann alarmiert der Patient den Rettungsdienst erneut?",opts:["Nur bei RR > 300 nach dokumentierter Erstuntersuchung","Nie unter Einbeziehung der Patientenanamnese","Morgen bei fehlendem Ansprechen auf Ersttherapie","Bei neuen Symptomen: Kopfschmerzen, SehstГ¶rungen, Brustschmerz, Atemnot"],correct:3,explanation:"Wiedervorstellungskriterien: Neue Kopfschmerzen, SehstГ¶rungen, Brustschmerz, Atemnot, neurologische AusfГӨlle."}
,
{q:"Гңbergabe (SINNHAFT): Handlungen (H) bei Hypertensiver Notfall вҖ“ was wird oft vergessen?",opts:["Bewusst unterlassene MaГҹnahmen und deren BegrГјndung","Die Einsatznummer als EskalationsmaГҹnahme bei Therapieversagen","Der Name des Fahrers unter BerГјcksichtigung des Patientenalters","Die Transportzeit nach Erhebung eines Basis-Monitorings"],correct:0,explanation:"Hypertensiver Notfall: Bei Handlungen nicht nur WAS getan wurde, sondern auch was bewusst NICHT getan wurde + BegrГјndung. ErmГ¶glicht dem Team die Entscheidung zu prГјfen."}]},
{id:34,title:"HypoglykГӨmischer Krampfanfall",bpr:"hypoglyk",scenario:"45-jГӨhrige Diabetikerin (Typ 1). Verwirrtheit, dann generalisierter Krampfanfall. BZ 28 mg/dl, SpOвӮӮ 91%, GCS 3.",
steps:[
{q:"Was hat PrioritГӨt?",opts:["BZ-Korrektur mit regelmГӨГҹiger Verlaufskontrolle","Krampfdurchbrechung mit Midazolam","Intubation bei Verdacht auf kritische Verschlechterung","EKG unter Beachtung mГ¶glicher Wechselwirkungen"],correct:1,explanation:"Aktiver Krampfanfall zuerst durchbrechen! Dann BZ-Korrektur."},
{q:"Kein i.v.-Zugang mГ¶glich. Wie behandeln Sie die HypoglykГӨmie?",opts:["Glucagon 1 mg i.m.","Glucose 40% rectal","Abwarten als leitliniengerechte NotfallmaГҹnahme","Orale Glucose"],correct:0,explanation:"Ohne i.v.-Zugang und bei bewusstlosem Patienten: Glucagon 1 mg i.m. (>25 kgKG)."},
{q:"i.v.-Zugang gelingt. Welche Glucose-Dosis?",opts:["8-10 g i.v. (max. 20%ig)","100 ml Glucose 5%","2-3 g nach klinischer EinschГӨtzung","50 g gemГӨГҹ Behandlungspfad"],correct:0,explanation:"Erwachsene: 8-10 g Glucose i.v., max. 20%ig, mit VEL zusammen applizieren."},
{q:"Wann kontrollieren Sie den BZ?",opts:["In der Klinik","Nach ca. 5 Minuten","Sofort bei stabilen KreislaufverhГӨltnissen","Nach 30 Minuten"],correct:1,explanation:"BZ-Kontrolle nach ca. 5 min. Ziel: > 90 mg/dl. Bei Nichterreichen: Repetition."},
{q:"Warum ist Glucose i.v. besser als Glucagon bei mГ¶glichem Alkoholmissbrauch?",opts:["Glucagon benГ¶tigt Glykogenreserven вҖ“ die bei Alkoholikern erschГ¶pft sein kГ¶nnen","Schmeckt besser unter kontinuierlichem Monitoring","Kein Unterschied nach ABCDE-Reevaluation","Glucagon ist immer besser bei gesichertem Atemweg"],correct:0,explanation:"Glucagon wirkt Гјber Glykogenolyse. Bei erschГ¶pften Glykogenreserven (Alkohol, Hunger) wirkungslos вҶ’ Glucose i.v. bevorzugt."}
,
{q:"Гңbergabe (SINNHAFT): Notfallereignis (N) bei HypoglykГӨmie вҖ“ welche WANN-Info zГӨhlt?",opts:["Wann die letzte Insulingabe regulГӨr fГӨllig war laut aktuellem Algorithmus","Wann der Patient zuletzt beim Arzt war nach Sicherung der Vitalfunktionen","Wann der Diabetes diagnostiziert wurde unter Beachtung der Kontraindikationen, sofern keine allergischen Reaktionen in der Vorgeschichte bekannt sind","WANN: Zeitpunkt der BZ-Messung + niedrigster gemessener Wert + letzte Nahrungsaufnahme"],correct:3,explanation:"HypoglykГӨmie-Ereignis: Zeitpunkt + niedrigster BZ-Wert + letzte Nahrungsaufnahme. Ursache: Insulin-Гңberdosis? Mahlzeit ausgelassen? Alkohol?"}]},
{id:35,title:"Leichte HypoglykГӨmie beim Diabetiker",bpr:"hypoglyk",scenario:"60-jГӨhriger Diabetiker (Typ 2). Zitterig, schweiГҹig, verwirrt. BZ 45 mg/dl. Ansprechbar, SchluckfГӨhigkeit erhalten.",
steps:[
{q:"Patient ist wach und schluckfГӨhig. Was ist die richtige Therapie?",opts:["Infusion VEL bei dokumentierter Indikation","Orale Glucose (Traubenzucker, Saft)","Glucagon i.m mit anschlieГҹender Transportentscheidung","Glucose i.v nach initialer Stabilisierung"],correct:1,explanation:"Wach + schluckfГӨhig = orale Glucosegabe bevorzugt! Einfach, schnell, effektiv."},
{q:"Wann kontrollieren Sie den BZ nach oraler Gabe?",opts:["Nach ca. 10 Minuten","Gar nicht gemГӨГҹ SOP des Rettungsdienstes","Nach 1 Stunde","Sofort bei fehlenden Kontraindikationen"],correct:0,explanation:"BZ-Kontrolle nach ca. 10 Minuten bei oraler Gabe. Ziel: > 90 mg/dl."},
{q:"BZ nach 10 min: 95 mg/dl. Darf der Patient zu Hause bleiben?",opts:["Nur wenn Notarzt zustimmt unter BerГјcksichtigung des klinischen Bildes","Nie mit Voranmeldung in der Zielklinik","Nur mit AufklГӨrung, regelmГӨГҹigen Kontrollen und gesicherter Betreuung","Ja, immer nach Ausschluss reversibler Ursachen"],correct:2,explanation:"Verbleib zu Hause mГ¶glich bei unauffГӨlliger Rekompensation, gesicherter Betreuung und AufklГӨrung."},
{q:"Was muss bei sulfonylharnstoff-induzierter HypoglykГӨmie beachtet werden?",opts:["Sofort entlassen bei hГӨmodynamischer InstabilitГӨt","Lange Wirkdauer вҶ’ RГјckfallgefahr Гјber Stunden, immer Kliniktransport","Einmalige Glucose reicht unter Zeitdruck im Einsatzgeschehen","Nichts Besonderes als initiale MaГҹnahme vor Transport mit sofortiger Dokumentation im Einsatzprotokoll und Voranmeldung"],correct:1,explanation:"Sulfonylharnstoffe wirken lang вҶ’ RГјckfall-HypoglykГӨmie Гјber Stunden mГ¶glich. IMMER Kliniktransport!"},
{q:"Was raten Sie dem Patienten bei Verbleib vor Ort?",opts:["Insulin spritzen bei gesicherter Diagnose und Indikation","Nichts mit begleitender Sauerstofftherapie","Kohlenhydratreiche Mahlzeit einnehmen, Kontrolle sicherstellen","Sport treiben nach differentialdiagnostischer AbwГӨgung"],correct:2,explanation:"Nach BZ-Normalisierung: Kohlenhydratreiche Mahlzeit, regelmГӨГҹige BZ-Kontrollen, Betreuungsperson informieren."}
,
{q:"Гңbergabe (SINNHAFT): Handlungen (H) bei HypoglykГӨmie вҖ“ welche Info braucht die Klinik?",opts:["Nur dass Glucose gegeben wurde im Rahmen der Notfallversorgung","Nur der aktuelle BZ bei persistierender Symptomatik trotz ErstmaГҹnahmen","Glucose: Menge + Applikationsweg (oral/i.v.) + Zeitpunkt + BZ-Verlauf (Kontroll-BZ nach Gabe!)","Nur ob der Patient wieder wach ist nach Anlage eines venГ¶sen Zugangs"],correct:2,explanation:"HypoglykГӨmie-Handlungen: Glucose (Menge, Weg, Zeitpunkt) + Kontroll-BZ-Werte! + Ansprechen auf Therapie (GCS-Verbesserung?). Bei Sulfonylharnstoff: Rezidivgefahr!"}]},
{id:36,title:"HypoglykГӨmie beim Kind",bpr:"hypoglyk",scenario:"8-jГӨhriges Kind (Typ-1-Diabetes). Bewusstlos, tonuslos. BZ 32 mg/dl. Kein i.v.-Zugang mГ¶glich.",
steps:[
{q:"Wie geben Sie Glucagon bei einem Kind >25 kgKG?",opts:["1 mg i.m.","0,5 mg i.m.","3 mg nasal","2 mg i.m."],correct:0,explanation:"Kinder > 25 kgKG: 1 mg Glucagon i.m. Alternative: 3 mg Glucagon nasal (ab 4 Jahren)."},
{q:"Alternativ nasal вҖ“ welche Dosis?",opts:["1 mg gemГӨГҹ den Empfehlungen des Г„LRD","3 mg Glucagon nasal (BaqsimiВ®)","2 mg unter Beachtung der Dosierungsgrenzen","0,5 mg bei fortbestehender klinischer Verschlechterung"],correct:1,explanation:"BaqsimiВ® 3 mg intranasal ab 4 Jahren mГ¶glich."},
{q:"i.v.-Zugang gelingt. Glucose-Dosis fГјr 25 kgKG?",opts:["5 g (0,2 g/kgKG)","1 g mit paralleler Vorbereitung des Transports","20 g nach dokumentierter Erstuntersuchung","8-10 g unter Einbeziehung der Patientenanamnese"],correct:0,explanation:"Kinder: 0,2 g/kgKG Glucose i.v. вҶ’ 25 Г— 0,2 = 5 g. Max. 20%ig mit VEL applizieren."},
{q:"Welche Glucose-Konzentration verwenden Sie bei Kindern?",opts:["Glucose 50% bei fehlendem Ansprechen auf Ersttherapie","Max. Glucose 20% (mit VEL verdГјnnen)","Glucose 40% als EskalationsmaГҹnahme bei Therapieversagen","Glucose 5% unter BerГјcksichtigung des Patientenalters"],correct:1,explanation:"Kinder: Max. Glucose 20%! HГ¶here Konzentrationen вҶ’ GewebeschГӨden bei Paravasation. Mit VEL verdГјnnen."},
{q:"Was tun Sie, wenn BZ nach 5 min noch < 90 mg/dl?",opts:["Transport ohne weitere Therapie","Insulin geben nach Erhebung eines Basis-Monitorings","Abwarten mit regelmГӨГҹiger Verlaufskontrolle","Repetition der Glucose-Gabe (0,2 g/kgKG)"],correct:3,explanation:"Ziel > 90 mg/dl nicht erreicht вҶ’ Repetition. Kinder: 0,2 g/kgKG Glucose i.v. erneut."}
,
{q:"Гңbergabe (SINNHAFT): Anamnese (A) bei HypoglykГӨmie вҖ“ was ist klinisch entscheidend?",opts:["Nur ob der Patient Insulin spritzt bei Verdacht auf kritische Verschlechterung","Nur die Diagnose Diabetes unter Beachtung mГ¶glicher Wechselwirkungen","Diabetestyp, Insulinart + Dosis, Sulfonylharnstoff (Rezidivgefahr!), Alkoholkonsum, Niereninsuffizienz","Nur der HbA1c als leitliniengerechte NotfallmaГҹnahme"],correct:2,explanation:"HypoglykГӨmie-Anamnese: Diabetestyp, Insulinschema, Sulfonylharnstoff (вҶ’ prolongierte Hypo!), Alkohol, Nierenfunktion (verminderte Insulin-Clearance)."}]},
{id:37,title:"Hypothermie Stadium II",bpr:"hypothermie",scenario:"65-jГӨhriger Obdachloser, im Winter drauГҹen aufgefunden. Bewusstsein beeintrГӨchtigt, kein KГӨltezittern mehr. Kerntemperatur ca. 31В°C.",
steps:[
{q:"Welchem Hypothermie-Stadium entspricht dieser Befund?",opts:["Stadium III nach klinischer EinschГӨtzung","Stadium IV gemГӨГҹ Behandlungspfad","Stadium I bei stabilen KreislaufverhГӨltnissen","Stadium II (beeintrГӨchtigtes Bewusstsein, kein Frieren)"],correct:3,explanation:"Stadium II: BeeintrГӨchtigtes Bewusstsein ohne Frieren/KГӨltezittern."},
{q:"Was ist die wichtigste ErstmaГҹnahme?",opts:["Aktive WiedererwГӨrmung mit heiГҹem Wasser","Sofort ins warme Fahrzeug tragen","Warme Infusion als Bolus unter kontinuierlichem Monitoring","Immobilisation + WГӨrmeerhalt (passive Isolation)"],correct:3,explanation:"Stadium II/III: Immobilisation + passive WГӨrmeisolation. Vorsichtiger Umgang (Bergungstod-Gefahr!)."},
{q:"Warum ist Immobilisation so wichtig?",opts:["Keine Bewegung bei KГӨlte nach ABCDE-Reevaluation","Frakturgefahr bei gesichertem Atemweg","Zur Dokumentation laut aktuellem Algorithmus","Kaltes Blut kann bei Bewegung zum Herzen gelangen вҶ’ HerzrhythmusstГ¶rungen"],correct:3,explanation:"Afterdrop: Kaltes peripheres Blut strГ¶mt bei Bewegung zum Herzen вҶ’ Kammerflimmern mГ¶glich!"},
{q:"Was dГјrfen Sie bei Hypothermie Stadium II NICHT tun?",opts:["Aktiv bewegen, reiben oder heiГҹe GetrГӨnke geben","Monitoring nach Sicherung der Vitalfunktionen, abhГӨngig vom klinischen Verlauf und den erhobenen Vitalparametern","Rettungsdecke unter Beachtung der Kontraindikationen","Transport bei dokumentierter Indikation"],correct:0,explanation:"KEINE aktive Bewegung, KEIN Reiben, KEINE heiГҹen GetrГӨnke bei Stadium II+. Afterdrop-Gefahr!"},
{q:"Welche HRST drohen?",opts:["Keine mit anschlieГҹender Transportentscheidung","Nur Tachykardie nach initialer Stabilisierung","VF, VT, Asystolie bei < 30В°C","Nur Vorhofflimmern"],correct:2,explanation:"Bei Kerntemperatur < 30В°C: Hohes Risiko fГјr VF, VT, Asystolie. Vorsichtiger Umgang essenziell."}
,
{q:"Гңbergabe (SINNHAFT): Notfallereignis (N) bei Hypothermie вҖ“ welche Kerninfo?",opts:["WAS: Verdachtsdiagnose, WIE: Ursache/AuslГ¶ser, WANN: Symptombeginn mit exakter Uhrzeit","Nur ob der Patient Schmerzen hat gemГӨГҹ SOP des Rettungsdienstes","Nur den Transportweg bei fehlenden Kontraindikationen","Nur die Diagnose nennen unter BerГјcksichtigung des klinischen Bildes unter BerГјcksichtigung mГ¶glicher Differentialdiagnosen im Verlauf"],correct:0,explanation:"Hypothermie: Beim Notfallereignis immer WAS (Verdachtsdiagnose), WIE (Ursache/AuslГ¶ser), WANN (exakter Zeitpunkt) strukturiert Гјbergeben."}]},
{id:38,title:"Hypothermie Stadium IV mit Kreislaufstillstand",bpr:"hypothermie",scenario:"Skifahrer nach LawinenverschГјttung, 45 min unter Schnee. Keine Vitalzeichen. Kerntemperatur geschГӨtzt < 28В°C.",
steps:[
{q:"Wird reanimiert?",opts:["Ja вҖ“ niemand ist tot, solange er nicht warm und tot ist","Nur wenn VF im EKG mit Voranmeldung in der Zielklinik","Nur kurz nach Ausschluss reversibler Ursachen","Nein, sicher tot bei hГӨmodynamischer InstabilitГӨt"],correct:0,explanation:"'Nobody is dead until warm and dead.' Bei Hypothermie wird reanimiert und in eine Klinik mit Herz-Lungen-Maschine transportiert."},
{q:"Medikamentengabe bei Hypothermie <30В°C?",opts:["Normal dosieren unter Zeitdruck im Einsatzgeschehen","Keine Medikamente je als initiale MaГҹnahme vor Transport","Doppelte Dosis bei gesicherter Diagnose und Indikation","Medikamentenintervalle verlГӨngern / zurГјckhalten"],correct:3,explanation:"Bei Kerntemperatur < 30В°C: Medikamentengabe zurГјckhalten oder Intervalle deutlich verlГӨngern."},
{q:"Defibrillation bei Hypothermie?",opts:["Max. 3 Versuche, dann erst nach ErwГӨrmung weitere","Nur mit AED mit begleitender Sauerstofftherapie","Nie nach differentialdiagnostischer AbwГӨgung","Unbegrenzt im Rahmen der Notfallversorgung"],correct:0,explanation:"Bei VF und Hypothermie: Max. 3 Defibrillationsversuche. Weitere Schocks erst nach WiedererwГӨrmung."},
{q:"Wo wird der Patient transportiert?",opts:["Klinik mit MГ¶glichkeit der extrakorporalen WiedererwГӨrmung (ECLS/ECMO)","Ambulant bei persistierender Symptomatik trotz ErstmaГҹnahmen, nach vorheriger AbklГӨrung aller reversiblen Ursachen gemГӨГҹ Algorithmus","NГӨchstes Krankenhaus nach Anlage eines venГ¶sen Zugangs","Hausarzt gemГӨГҹ den Empfehlungen des Г„LRD"],correct:0,explanation:"Schwere Hypothermie mit Kreislaufstillstand вҶ’ Klinik mit ECLS/ECMO zur extrakorporalen WiedererwГӨrmung."},
{q:"Ab welcher Temperatur gelten die Defi-EinschrГӨnkungen?",opts:["< 25В°C","< 35В°C","< 30В°C","< 20В°C"],correct:2,explanation:"< 30В°C: Max. 3 Defi-Versuche, Medikamente zurГјckhalten/Intervalle verlГӨngern. Zwischen 30-35В°C: Intervalle verlГӨngern."}
,
{q:"Гңbergabe (SINNHAFT): NotfallprioritГӨt (N) bei Hypothermie вҖ“ nach welcher Struktur?",opts:["Nach Dringlichkeit der Diagnostik unter Beachtung der Dosierungsgrenzen","Nach persГ¶nlichem Ermessen bei fortbestehender klinischer Verschlechterung","Nach dem (x)ABCDE-Schema mit pathologischen Befunden und Vitalparametern","Alphabetisch nach Befunden mit paralleler Vorbereitung des Transports"],correct:2,explanation:"Hypothermie: NotfallprioritГӨt IMMER nach ABCDE strukturiert. Pathologische Befunde + Vitalparameter pro Buchstabe, auffГӨllige Befunde hervorheben."}]},
];
// NotSanTrainer 2025 - Fallsimulationen (Teil 2/4, FГӨlle 39-76)
CASES = CASES.concat([
{id:39,title:"Milde Hypothermie nach Wasserrettung",bpr:"hypothermie",scenario:"30-JГӨhrige, 20 min in kaltem GewГӨsser. Bewusstseinsklar, friert stark, zittert. Kerntemperatur 34В°C.",
steps:[
{q:"Welches Stadium?",opts:["Stadium III nach dokumentierter Erstuntersuchung","Stadium IV unter Einbeziehung der Patientenanamnese","Stadium I (bewusstseinsklar, frierend)","Stadium II bei fehlendem Ansprechen auf Ersttherapie"],correct:2,explanation:"Stadium I: Bewusstseinsklar und frierend. Gute Prognose."},
{q:"Therapie bei Stadium I?",opts:["Reanimation als EskalationsmaГҹnahme bei Therapieversagen","Sofort Klinik unter BerГјcksichtigung des Patientenalters","Adrenalin i.v nach Erhebung eines Basis-Monitorings","Warme Umgebung, trockene Kleidung, warme GetrГӨnke"],correct:3,explanation:"Stadium I: Warme Umgebung schaffen, nasse Kleidung entfernen, warme GetrГӨnke wenn mГ¶glich."},
{q:"Transport nГ¶tig?",opts:["Nein mit regelmГӨГҹiger Verlaufskontrolle","Ja, Гңberwachung und Re-Evaluation sinnvoll","Nur bei Symptomen bei Verdacht auf kritische Verschlechterung","Nur RГјcksprache Hausarzt unter Beachtung mГ¶glicher Wechselwirkungen"],correct:1,explanation:"Transport zur Гңberwachung empfohlen вҖ“ auch milde Hypothermie kann sich verschlechtern."},
{q:"Wann hat der Patient Stadium I verlassen?",opts:["Wenn BewusstseinsstГ¶rung eintritt вҶ’ Stadium II","Wenn er aufhГ¶rt zu zittern als leitliniengerechte NotfallmaГҹnahme","Erst bei Kreislaufstillstand","Wenn er einschlГӨft nach klinischer EinschГӨtzung"],correct:0,explanation:"Stadium I вҶ’ II: BewusstseinsstГ¶rung + AufhГ¶ren des Zitterns. Dann: Immobilisation, passiver WГӨrmeerhalt, vorsichtiger Transport."},
{q:"Welche Temperaturmessung ist am genauesten?",opts:["Stirnthermometer gemГӨГҹ Behandlungspfad","Axillar bei stabilen KreislaufverhГӨltnissen","Oral unter kontinuierlichem Monitoring","Г–sophageal oder tympanal (epitympanal)"],correct:3,explanation:"Г–sophageal oder epitympanal (tympanal) sind am genauesten. Axillar und Stirn sind unzuverlГӨssig bei Hypothermie."}
,
{q:"Гңbergabe (SINNHAFT): Handlungen (H) bei Hypothermie вҖ“ was wird oft vergessen?",opts:["Bewusst unterlassene MaГҹnahmen und deren BegrГјndung","Die Transportzeit nach ABCDE-Reevaluation","Der Name des Fahrers bei gesichertem Atemweg","Die Einsatznummer laut aktuellem Algorithmus"],correct:0,explanation:"Hypothermie: Bei Handlungen nicht nur WAS getan wurde, sondern auch was bewusst NICHT getan wurde + BegrГјndung. ErmГ¶glicht dem Team die Entscheidung zu prГјfen."}]},
{id:40,title:"AV-Block IIIВ° mit Synkope",bpr:"bradykardie",scenario:"75-jГӨhriger Mann, wiederholt synkopiert. HF 35/min, RR 80/55. GCS 13. EKG: totaler AV-Block mit breitem QRS-Ersatzrhythmus.",
steps:[
{q:"Welches Medikament geben Sie zuerst?",opts:["Midazolam nach Sicherung der Vitalfunktionen","Epinephrin unter Beachtung der Kontraindikationen","Amiodaron bei dokumentierter Indikation","Atropin 0,5 mg i.v."],correct:3,explanation:"Instabile Bradykardie: Atropin 0,5 mg i.v. als erste MaГҹnahme."},
{q:"Atropin bleibt wirkungslos (AV-Block IIIВ° spricht oft nicht an). Was nun?",opts:["Amiodaron mit anschlieГҹender Transportentscheidung","Mehr Atropin bis 10 mg","Defibrillation","Epinephrin (5 Вөg Boli)"],correct:3,explanation:"Bei Atropin-Versagen: Wechsel auf Epinephrin als Perfusor / 5 Вөg Boli i.v."},
{q:"Epinephrin reicht nicht. Was ist die nГӨchste Eskalation?",opts:["Defibrillation nach initialer Stabilisierung","Thoraxentlastungspunktion","Externe transkutane Schrittmachertherapie","Amiodaron i.v gemГӨГҹ SOP des Rettungsdienstes"],correct:2,explanation:"Externe Schrittmachertherapie bei therapierefraktГӨrer instabiler Bradykardie. Schmerztherapie beachten!"},
{q:"Atropin-Dosis bei instabiler Bradykardie?",opts:["1 mg einmalig bei fehlenden Kontraindikationen","5 mg unter BerГјcksichtigung des klinischen Bildes","0,1 mg mit Voranmeldung in der Zielklinik","0,5 mg i.v., wiederholbar bis max. 3 mg"],correct:3,explanation:"Atropin 0,5 mg i.v. Wiederholbar alle 4 min bis max. 3 mg Gesamtdosis."},
{q:"Warum spricht AV-Block IIIВ° oft nicht auf Atropin an?",opts:["Allergisch nach Ausschluss reversibler Ursachen","Falsche Applikation bei hГӨmodynamischer InstabilitГӨt","Atropin wirkt am AV-Knoten вҖ“ bei totalem Block entsteht der Ersatzrhythmus darunter","Zu niedrig dosiert unter Zeitdruck im Einsatzgeschehen"],correct:2,explanation:"Atropin beschleunigt nur den Sinusknoten/AV-Knoten. Bei AV-Block IIIВ° leitet der AV-Knoten nicht вҖ“ Ersatzrhythmus weiter unten."}
,
{q:"Гңbergabe (SINNHAFT): Notfallereignis (N) bei Bradykardie вҖ“ welche Kerninfo?",opts:["Nur ob der Patient Schmerzen hat als initiale MaГҹnahme vor Transport, wobei die Wirksamkeit engmaschig kontrolliert werden muss","Nur die Diagnose nennen bei gesicherter Diagnose und Indikation","Nur den Transportweg mit begleitender Sauerstofftherapie","WAS: Verdachtsdiagnose, WIE: Ursache/AuslГ¶ser, WANN: Symptombeginn mit exakter Uhrzeit"],correct:3,explanation:"Bradykardie: Beim Notfallereignis immer WAS (Verdachtsdiagnose), WIE (Ursache/AuslГ¶ser), WANN (exakter Zeitpunkt) strukturiert Гјbergeben."}]},
{id:41,title:"Sinusbradykardie durch Betablocker",bpr:"bradykardie",scenario:"62-jГӨhrige Frau, Гңberdosis Metoprolol (suizidal). HF 38/min, RR 75/40, GCS 10.",
steps:[
{q:"Welche reversible Ursache liegt vor?",opts:["HyperkaliГӨmie nach differentialdiagnostischer AbwГӨgung","Hypothermie im Rahmen der Notfallversorgung","Volumenmangel bei persistierender Symptomatik trotz ErstmaГҹnahmen","Medikamentenintoxikation (Betablocker)"],correct:3,explanation:"Betablocker-Гңberdosis вҶ’ schwere Bradykardie mit Hypotonie. Reversible Ursache!"},
{q:"Atropin-Gabe. Maximaldosis?",opts:["3 mg","5 mg","1 mg","2 mg"],correct:0,explanation:"Max. Gesamtdosis Atropin: 3 mg. Bei Wirkungslosigkeit вҶ’ Eskalation."},
{q:"Was ist bei Betablocker-Intoxikation als spezifischere Therapie zu erwГӨgen?",opts:["Flumazenil nach Anlage eines venГ¶sen Zugangs","Dimetinden gemГӨГҹ den Empfehlungen des Г„LRD","Naloxon unter Beachtung der Dosierungsgrenzen","Glucagon (durch NA)"],correct:3,explanation:"Glucagon wirkt am Herzen Гјber einen betablocker-unabhГӨngigen Mechanismus вҖ“ spezifisch bei BB-Intoxikation (NA-MaГҹnahme)."},
{q:"Wie therapieren Sie die Hypotonie neben Atropin?",opts:["Glyceroltrinitrat bei fortbestehender klinischer Verschlechterung","Furosemid mit paralleler Vorbereitung des Transports","VEL + ggf. Epinephrin als Vasopressor","Urapidil nach dokumentierter Erstuntersuchung"],correct:2,explanation:"Hypotonie bei Bradykardie: VEL-Gabe + ggf. Epinephrin als Vasopressor (5 Вөg Boli oder Perfusor)."},
{q:"Welche Гңberwachung ist essenziell?",opts:["Nur SpOвӮӮ unter Einbeziehung der Patientenanamnese","Nur HF bei fehlendem Ansprechen auf Ersttherapie","Kontinuierliches EKG-Monitoring + RR + SpOвӮӮ + GCS","Nur Temperatur als EskalationsmaГҹnahme bei Therapieversagen"],correct:2,explanation:"Kontinuierliches Monitoring: EKG, RR, SpOвӮӮ, GCS. Bei Betablocker-Intoxikation: rasche Verschlechterung mГ¶glich."}
,
{q:"Гңbergabe (SINNHAFT): NotfallprioritГӨt (N) bei Bradykardie вҖ“ nach welcher Struktur?",opts:["Nach Dringlichkeit der Diagnostik unter BerГјcksichtigung des Patientenalters","Nach dem (x)ABCDE-Schema mit pathologischen Befunden und Vitalparametern","Alphabetisch nach Befunden nach Erhebung eines Basis-Monitorings, was jedoch in der aktuellen Situation kontraindiziert wГӨre","Nach persГ¶nlichem Ermessen mit regelmГӨГҹiger Verlaufskontrolle"],correct:1,explanation:"Bradykardie: NotfallprioritГӨt IMMER nach ABCDE strukturiert. Pathologische Befunde + Vitalparameter pro Buchstabe, auffГӨllige Befunde hervorheben."}]},
{id:42,title:"Symptomatische Bradykardie beim Sportler",bpr:"bradykardie",scenario:"28-jГӨhriger Ausdauersportler. Synkope beim Aufstehen. HF 42/min, RR 100/60. Bewusstseinsklar, keine weiteren Symptome.",
steps:[
{q:"Ist diese Bradykardie behandlungsbedГјrftig?",opts:["Immer behandeln < 50/min bei Verdacht auf kritische Verschlechterung","Ja, sofort Atropin unter Beachtung mГ¶glicher Wechselwirkungen","Nein вҖ“ sportlerbedingte Sinusbradykardie, orthostatische Synkope","Sofort Schrittmacher als leitliniengerechte NotfallmaГҹnahme"],correct:2,explanation:"Klinisch stabile Bradykardie bei Sportlern ist hГӨufig und harmlos. Orthostatische Synkope als Ursache wahrscheinlich."},
{q:"Wann wГӨre Therapie indiziert?",opts:["Immer bei HF < 60 nach klinischer EinschГӨtzung","Bei InstabilitГӨtszeichen: Schock, BewusstseinsstГ¶rung, Synkope, MyokardischГӨmie","Nie bei jungen Patienten gemГӨГҹ Behandlungspfad","Nur bei HF < 20 bei stabilen KreislaufverhГӨltnissen"],correct:1,explanation:"Therapie nur bei InstabilitГӨtszeichen! Einmalige orthostatische Synkope вү  instabile Bradykardie."},
{q:"Was tun Sie bei diesem stabilen Patienten?",opts:["Entlassung ohne weitere MaГҹnahme unter kontinuierlichem Monitoring","Atropin geben nach ABCDE-Reevaluation","12-Kanal-EKG, Гңberwachung, ggf. Transport zur AbklГӨrung","Sofort Schrittmacher bei gesichertem Atemweg und anschlieГҹende Reevaluation nach spГӨtestens 5 Minuten"],correct:2,explanation:"EKG-Dokumentation, Гңberwachung, ggf. Transport вҖ“ auch bei stabiler Bradykardie AbklГӨrung empfohlen."},
{q:"Was dokumentieren Sie fГјr die Klinik?",opts:["12-Kanal-EKG, HF-Verlauf, Symptomatik, Sportart, Synkope-UmstГӨnde","Nur Name laut aktuellem Algorithmus","Nur HF nach Sicherung der Vitalfunktionen","Nur Blutdruck unter Beachtung der Kontraindikationen"],correct:0,explanation:"12-Kanal-EKG (Long QT? WPW? Brugada?), HF-Verlauf, Synkope-UmstГӨnde, Sportart вҶ’ wichtig fГјr kardiologische AbklГӨrung."},
{q:"Welche Vitaltreserve hat ein trainierter Sportler?",opts:["Niedrig bei dokumentierter Indikation","Mittel mit anschlieГҹender Transportentscheidung","Keine nach initialer Stabilisierung","Hohe вҖ“ kompensiert lange, kann aber plГ¶tzlich dekompensieren"],correct:3,explanation:"Sportler kompensieren lange (hohe Vitaltreserve), kГ¶nnen aber plГ¶tzlich dekompensieren. Daher: Nicht unterschГӨtzen!"}
,
{q:"Гңbergabe (SINNHAFT): Handlungen (H) bei Bradykardie вҖ“ was wird oft vergessen?",opts:["Die Einsatznummer gemГӨГҹ SOP des Rettungsdienstes","Der Name des Fahrers bei fehlenden Kontraindikationen","Bewusst unterlassene MaГҹnahmen und deren BegrГјndung","Die Transportzeit unter BerГјcksichtigung des klinischen Bildes"],correct:2,explanation:"Bradykardie: Bei Handlungen nicht nur WAS getan wurde, sondern auch was bewusst NICHT getan wurde + BegrГјndung. ErmГ¶glicht dem Team die Entscheidung zu prГјfen."}]},
{id:43,title:"SVT mit InstabilitГӨt",bpr:"tachykardie",scenario:"32-jГӨhrige Frau, plГ¶tzlich Herzrasen. HF 210/min, RR 80/50, Schwindel, GCS 14. EKG: regelmГӨГҹige Schmalkomplextachykardie.",
steps:[
{q:"Was versuchen Sie zuerst bei stabiler regelmГӨГҹiger SVT?",opts:["Atropin mit Voranmeldung in der Zielklinik, sofern keine allergischen Reaktionen in der Vorgeschichte bekannt sind","Vagusreiz (modifiziertes Valsalva-ManГ¶ver)","Kardioversion nach Ausschluss reversibler Ursachen","Amiodaron bei hГӨmodynamischer InstabilitГӨt"],correct:1,explanation:"Bei stabiler regelmГӨГҹiger Schmalkomplextachykardie: ZunГӨchst Vagusreiz (mod. Valsalva-ManГ¶ver)."},
{q:"Patientin wird bewusstlos. HF 210/min persistiert. NГӨchster Schritt?",opts:["Weiterer Vagusreiz unter Zeitdruck im Einsatzgeschehen","Elektrische Kardioversion (synchronisiert)","Atropin i.v als initiale MaГҹnahme vor Transport","Defibrillation bei gesicherter Diagnose und Indikation"],correct:1,explanation:"Instabil + bewusstlos вҶ’ Sofortige elektrische Kardioversion (R-Zacken-synchron!)."},
{q:"Was muss VOR der Kardioversion bei wachem Patienten erfolgen?",opts:["Intubation mit begleitender Sauerstofftherapie","Nichts nach differentialdiagnostischer AbwГӨgung","Magensonde im Rahmen der Notfallversorgung","Sedierung falls mГ¶glich"],correct:3,explanation:"Bei wachem Patienten: Sedierung vor Kardioversion falls mГ¶glich und Zeit erlaubt."},
{q:"Welche Kardioversions-Energie verwenden Sie initial?",opts:["50 J bei persistierender Symptomatik trotz ErstmaГҹnahmen","200 J nach Anlage eines venГ¶sen Zugangs","360 J gemГӨГҹ den Empfehlungen des Г„LRD","70-120 J synchronisiert"],correct:3,explanation:"Schmalkomplextachykardie: Start mit 70-120 J synchronisiert. Breitkomplextachykardie: 120-150 J."},
{q:"Was ist das modifizierte Valsalva-ManГ¶ver?",opts:["HustenstoГҹ unter Beachtung der Dosierungsgrenzen","Kaltes Wasser trinken bei fortbestehender klinischer Verschlechterung","Karotismassage mit paralleler Vorbereitung des Transports","Pressen (15s) вҶ’ sofort flach hinlegen + Beine hoch fГјr 15s"],correct:3,explanation:"Modifiziertes Valsalva: 15s pressen вҶ’ sofort OberkГ¶rper flach + Beine passiv 45В° hoch fГјr 15s. HГ¶here Konversionsrate als klassisch."}
,
{q:"Гңbergabe (SINNHAFT): Notfallereignis (N) bei Tachykardie вҖ“ welche Kerninfo?",opts:["Nur den Transportweg nach dokumentierter Erstuntersuchung","Nur ob der Patient Schmerzen hat unter Einbeziehung der Patientenanamnese","WAS: Verdachtsdiagnose, WIE: Ursache/AuslГ¶ser, WANN: Symptombeginn mit exakter Uhrzeit","Nur die Diagnose nennen bei fehlendem Ansprechen auf Ersttherapie"],correct:2,explanation:"Tachykardie: Beim Notfallereignis immer WAS (Verdachtsdiagnose), WIE (Ursache/AuslГ¶ser), WANN (exakter Zeitpunkt) strukturiert Гјbergeben."}]},
{id:44,title:"Breitkomplextachykardie",bpr:"tachykardie",scenario:"68-jГӨhriger Mann, plГ¶tzlich Herzrasen, Schmerzen in der Brust. HF 180/min, RR 90/55. EKG: regelmГӨГҹige Breitkomplextachykardie (QRS > 120 ms).",
steps:[
{q:"Was ist bis zum Beweis des Gegenteils anzunehmen?",opts:["VentrikulГӨre Tachykardie","Vorhofflimmern","Sinustachykardie","SupraventrikulГӨre Tachykardie"],correct:0,explanation:"RegelmГӨГҹige Breitkomplextachykardie = bis zum Beweis des Gegenteils вҶ’ Kammertachykardie!"},
{q:"Patient noch bei Bewusstsein aber instabil. Wer therapiert?",opts:["Nur Transport als EskalationsmaГҹnahme bei Therapieversagen","Keine Therapie unter BerГјcksichtigung des Patientenalters","NotSan selbststГӨndig nach Erhebung eines Basis-Monitorings","Weitere spezifische medikamentГ¶se Therapie durch NA"],correct:3,explanation:"Instabil aber wach: Spezifische medikamentГ¶se Therapie der Tachykardie bleibt dem NA vorbehalten."},
{q:"Was muss immer bedacht werden?",opts:["Nur Volumen mit regelmГӨГҹiger Verlaufskontrolle","Kardiale IschГӨmie als Ursache der RhythmusstГ¶rung","Nur die Frequenz bei Verdacht auf kritische Verschlechterung","Nur Elektrolyte unter Beachtung mГ¶glicher Wechselwirkungen"],correct:1,explanation:"Bei InstabilitГӨt durch HRST immer auch kardiale IschГӨmie als Ursache bedenken вҶ’ 12-Kanal-EKG!"},
{q:"Welches Medikament kann der NA bei VT geben?",opts:["Amiodaron 300 mg i.v. Гјber 20-60 min","Atropin als leitliniengerechte NotfallmaГҹnahme","Furosemid nach klinischer EinschГӨtzung","Dimetinden gemГӨГҹ Behandlungspfad mit sofortiger Dokumentation im Einsatzprotokoll und Voranmeldung"],correct:0,explanation:"VT (stabil): Amiodaron 300 mg i.v. Гјber 20-60 min durch NA. Bei InstabilitГӨt: Kardioversion."},
{q:"Was ist Ihre Aufgabe als NotSan bei instabiler Breitkomplex-Tachykardie?",opts:["Kardioversion bei stabilen KreislaufverhГӨltnissen, abhГӨngig vom klinischen Verlauf und den erhobenen Vitalparametern","Amiodaron geben unter kontinuierlichem Monitoring","BasismaГҹnahmen, OвӮӮ, i.v.-Zugang, NA-Nachforderung","Defibrillation nach ABCDE-Reevaluation"],correct:2,explanation:"NotSan: BasismaГҹnahmen, OвӮӮ, i.v.-Zugang, EKG-Monitoring, NA-Nachforderung. Spezifische HRST-Therapie = NA-MaГҹnahme."}
,
{q:"Гңbergabe (SINNHAFT): NotfallprioritГӨt (N) bei Tachykardie вҖ“ nach welcher Struktur?",opts:["Alphabetisch nach Befunden bei gesichertem Atemweg","Nach dem (x)ABCDE-Schema mit pathologischen Befunden und Vitalparametern","Nach Dringlichkeit der Diagnostik laut aktuellem Algorithmus","Nach persГ¶nlichem Ermessen nach Sicherung der Vitalfunktionen"],correct:1,explanation:"Tachykardie: NotfallprioritГӨt IMMER nach ABCDE strukturiert. Pathologische Befunde + Vitalparameter pro Buchstabe, auffГӨllige Befunde hervorheben."}]},
{id:45,title:"Tachyarrhythmia absoluta mit Schock",bpr:"tachykardie",scenario:"78-jГӨhrige Frau mit VHF. HF 170/min unregelmГӨГҹig, RR 75/45, BewusstseinstrГјbung. SpOвӮӮ 90%.",
steps:[
{q:"Was sind die InstabilitГӨtszeichen hier?",opts:["Nur HF > 150 unter Beachtung der Kontraindikationen","Keine InstabilitГӨt bei dokumentierter Indikation","Schock (Hypotonie) + BewusstseinsstГ¶rung","Nur SpOвӮӮ < 95% mit anschlieГҹender Transportentscheidung"],correct:2,explanation:"InstabilitГӨtszeichen: Schock (RR 75/45) + BewusstseinsstГ¶rung вҶ’ instabile Tachykardie."},
{q:"Reversible Ursachen prГјfen. Welche?",opts:["HyperkaliГӨmie, HypovolГӨmie, HypoglykГӨmie","4H und HITS nach initialer Stabilisierung","SAMPLER gemГӨГҹ SOP des Rettungsdienstes","Nur EKG bei fehlenden Kontraindikationen"],correct:0,explanation:"Reversible Ursachen bei Tachykardie: HyperkaliГӨmie, HypovolГӨmie, HypoglykГӨmie вҖ“ behandelbare AuslГ¶ser!"},
{q:"Was tun Sie neben OвӮӮ und i.v.-Zugang?",opts:["Kardioversion bei Bewusstlosigkeit, NA-Nachforderung","Defibrillation unter BerГјcksichtigung des klinischen Bildes","Atropin mit Voranmeldung in der Zielklinik","Furosemid nach Ausschluss reversibler Ursachen"],correct:0,explanation:"Bei instabiler Tachykardie: NA-Nachforderung fГјr medikamentГ¶se Therapie bzw. Kardioversion bei Bewusstlosigkeit."},
{q:"Was ist Tachyarrhythmia absoluta?",opts:["Vorhofflimmern mit schneller Гңberleitung (unregelmГӨГҹig!)","RegelmГӨГҹige Tachykardie bei hГӨmodynamischer InstabilitГӨt","Kammerflimmern unter Zeitdruck im Einsatzgeschehen","Nur schneller Puls als initiale MaГҹnahme vor Transport"],correct:0,explanation:"Tachyarrhythmia absoluta = Vorhofflimmern mit schneller, unregelmГӨГҹiger Гңberleitung. UnregelmГӨГҹig-unregelmГӨГҹig!"},
{q:"Welche OвӮӮ-Gabe?",opts:["Immer 15 l/min bei gesicherter Diagnose und Indikation","Nur Raumluft mit begleitender Sauerstofftherapie unter BerГјcksichtigung mГ¶glicher Differentialdiagnosen im Verlauf","Bedarfsgerechte OвӮӮ-Gabe, Ziel SpOвӮӮ 92-96% (SAA Sauerstoff)","Keine nach differentialdiagnostischer AbwГӨgung"],correct:2,explanation:"Bedarfsgerechte OвӮӮ-Gabe gemГӨГҹ SAA Sauerstoff: Ziel SpOвӮӮ 92-96% (ohne Hyperkapnierisiko). BPR Tachykardie verweist auf SAA Sauerstoff."}
,
{q:"Гңbergabe (SINNHAFT): Handlungen (H) bei Tachykardie вҖ“ was wird oft vergessen?",opts:["Der Name des Fahrers im Rahmen der Notfallversorgung","Bewusst unterlassene MaГҹnahmen und deren BegrГјndung","Die Transportzeit bei persistierender Symptomatik trotz ErstmaГҹnahmen","Die Einsatznummer nach Anlage eines venГ¶sen Zugangs, nach vorheriger AbklГӨrung aller reversiblen Ursachen gemГӨГҹ Algorithmus"],correct:1,explanation:"Tachykardie: Bei Handlungen nicht nur WAS getan wurde, sondern auch was bewusst NICHT getan wurde + BegrГјndung. ErmГ¶glicht dem Team die Entscheidung zu prГјfen."}]},
{id:46,title:"Opioid-Intoxikation",bpr:"intoxikation",scenario:"24-JГӨhriger, auf Г¶ffentlicher Toilette aufgefunden. Somnolent, Miosis (Stecknadelkopfpupillen), AF 6/min, SpOвӮӮ 78%. Einstichstellen an den Armen.",
steps:[
{q:"Welches Toxidrom liegt vor?",opts:["Sympathomimetisch","Cholinerg","Opioid-Toxidrom","Anticholinerg"],correct:2,explanation:"Miosis + Bradypnoe + Einstichstellen = klassisches Opioid-Toxidrom."},
{q:"Was sind die primГӨren MaГҹnahmen BEVOR Naloxon gegeben wird?",opts:["Sofort intubieren gemГӨГҹ den Empfehlungen des Г„LRD","Kommandoatmung, OвӮӮ, ggf. Beutel-Masken-Beatmung","Flumazenil geben unter Beachtung der Dosierungsgrenzen","Sofort Naloxon bei fortbestehender klinischer Verschlechterung"],correct:1,explanation:"PrimГӨre MaГҹnahmen zuerst: Kommandoatmung, Sauerstoff, assistierte Beatmung вҖ“ dann Naloxon."},
{q:"Welche Naloxon-Dosis?",opts:["0,4 mg als Bolus mit paralleler Vorbereitung des Transports","0,1 mg fraktioniert alle 2 min i.v.","1 mg i.m nach dokumentierter Erstuntersuchung","2 mg nasal unter Einbeziehung der Patientenanamnese"],correct:1,explanation:"Naloxon 0,1 mg fraktioniert, langsam i.v. alle 2 min вҖ“ bis suffiziente Spontanatmung."},
{q:"Warum fraktioniert und nicht als Bolus?",opts:["Nur fraktioniert verfГјgbar","Wirkt nicht als Bolus bei fehlendem Ansprechen auf Ersttherapie","Zu teuer als EskalationsmaГҹnahme bei Therapieversagen","Akutes Entzugssyndrom + Schmerzen vermeiden"],correct:3,explanation:"Bolus-Gabe вҶ’ Akutes Entzugssyndrom (Agitation, Erbrechen, Aggression) + Auftreten von Schmerzen."},
{q:"Was tun Sie, wenn die Spontanatmung nach Naloxon wieder einsetzt?",opts:["Flumazenil geben unter BerГјcksichtigung des Patientenalters","Patient kann gehen nach Erhebung eines Basis-Monitorings","Naloxon stoppen, Patient beobachten","Mehr Naloxon geben mit regelmГӨГҹiger Verlaufskontrolle"],correct:2,explanation:"Bei suffizienter Spontanatmung: Naloxon-Gabe stoppen. ABER: Naloxon HWZ kГјrzer als Opioid вҶ’ engmaschige Гңberwachung, RГјckfall mГ¶glich!"}
,
{q:"Гңbergabe (SINNHAFT): Notfallereignis (N) bei Intoxikation вҖ“ welche Kerninfo?",opts:["WAS: Verdachtsdiagnose, WIE: Ursache/AuslГ¶ser, WANN: Symptombeginn mit exakter Uhrzeit","Nur ob der Patient Schmerzen hat bei Verdacht auf kritische Verschlechterung","Nur die Diagnose nennen unter Beachtung mГ¶glicher Wechselwirkungen","Nur den Transportweg als leitliniengerechte NotfallmaГҹnahme"],correct:0,explanation:"Intoxikation: Beim Notfallereignis immer WAS (Verdachtsdiagnose), WIE (Ursache/AuslГ¶ser), WANN (exakter Zeitpunkt) strukturiert Гјbergeben."}]},
{id:47,title:"Rauchgasvergiftung",bpr:"intoxikation",scenario:"35-jГӨhrige Frau, aus brennendem GebГӨude gerettet. RuГҹspuren im Gesicht, Husten, Kopfschmerzen, Schwindel. SpOвӮӮ 98% (Cave!).",
steps:[
{q:"Warum ist die SpOвӮӮ von 98% trГјgerisch?",opts:["Immer zuverlГӨssig nach klinischer EinschГӨtzung","Pulsoxymeter kann CO-Hb nicht von OвӮӮ-Hb unterscheiden!","SpOвӮӮ immer normal bei Rauchgas gemГӨГҹ Behandlungspfad","GerГӨt defekt bei stabilen KreislaufverhГӨltnissen"],correct:1,explanation:"Bei CO-Intoxikation: Pulsoxymeter misst falsch hoch! CO-Hb wird als OвӮӮ-Hb gemessen."},
{q:"Welche Therapie steht im Vordergrund?",opts:["Prednisolon unter kontinuierlichem Monitoring","Glyceroltrinitrat nach ABCDE-Reevaluation","Salbutamol bei gesichertem Atemweg, wobei die Wirksamkeit engmaschig kontrolliert werden muss","Hochdosierte Sauerstoffgabe (Ziel FiOвӮӮ 1,0)"],correct:3,explanation:"CO-Intoxikation: Hochdosierte OвӮӮ-Gabe mit hГ¶chstmГ¶glichem FiOвӮӮ (15 l/min Reservoirmaske)."},
{q:"Woran mГјssen Sie bei Rauchgasinhalation noch denken?",opts:["Nur Hautverletzungen laut aktuellem Algorithmus, was jedoch in der aktuellen Situation kontraindiziert wГӨre","Nur Kopfschmerzen nach Sicherung der Vitalfunktionen","Nur CO unter Beachtung der Kontraindikationen","Inhalationstrauma (SchleimhautschГӨdigung, Bronchospasmus)"],correct:3,explanation:"Inhalationstrauma: SchleimhautschГӨdigung, drohende Atemwegsschwellung, Bronchospasmus."},
{q:"Welche Komplikation droht Stunden nach Rauchgasinhalation?",opts:["Toxisches LungenГ¶dem (verzГ¶gert, 24-48h)","Sofort Blutung bei dokumentierter Indikation","Nur Kopfschmerzen mit anschlieГҹender Transportentscheidung","Nichts nach initialer Stabilisierung und anschlieГҹende Reevaluation nach spГӨtestens 5 Minuten"],correct:0,explanation:"Toxisches LungenГ¶dem kann verzГ¶gert (24-48h) auftreten. Daher: IMMER Kliniktransport und Гңberwachung!"},
{q:"Wie lange geben Sie den hochdosierten Sauerstoff?",opts:["5 Minuten gemГӨГҹ SOP des Rettungsdienstes","Mindestens bis Klinik / HWZ des CO-Hb verkГјrzen","Nur kurz bei fehlenden Kontraindikationen","Gar nicht nГ¶tig unter BerГјcksichtigung des klinischen Bildes"],correct:1,explanation:"OвӮӮ verkГјrzt die HWZ von CO-Hb von 4-5h auf ca. 1h. Daher: Hochdosiert bis Klinikankunft (ggf. HBO-Therapie)."}
,
{q:"Гңbergabe (SINNHAFT): NotfallprioritГӨt (N) bei Intoxikation вҖ“ nach welcher Struktur?",opts:["Nach Dringlichkeit der Diagnostik mit Voranmeldung in der Zielklinik","Alphabetisch nach Befunden nach Ausschluss reversibler Ursachen","Nach persГ¶nlichem Ermessen bei hГӨmodynamischer InstabilitГӨt","Nach dem (x)ABCDE-Schema mit pathologischen Befunden und Vitalparametern"],correct:3,explanation:"Intoxikation: NotfallprioritГӨt IMMER nach ABCDE strukturiert. Pathologische Befunde + Vitalparameter pro Buchstabe, auffГӨllige Befunde hervorheben."}]},
{id:48,title:"Mischintoxikation bei Jugendlichem",bpr:"intoxikation",scenario:"17-JГӨhriger, auf Party zusammengebrochen. GCS 8, erweiterte Pupillen, HF 130, RR 160/95, Temp 39В°C. Freunde berichten von 'Pillen und Alkohol'.",
steps:[
{q:"Welches Toxidrom vermuten Sie?",opts:["Sympathomimetisch / serotoninerg (Mydriasis, Tachykardie, Hyperthermie)","Cholinerg unter Zeitdruck im Einsatzgeschehen","Opioid (Miosis) als initiale MaГҹnahme vor Transport","Anticholinerg bei gesicherter Diagnose und Indikation"],correct:0,explanation:"Mydriasis + Tachykardie + Hypertonie + Hyperthermie вҶ’ sympathomimetisches/serotonerges Syndrom."},
{q:"Was ist die wichtigste ErstmaГҹnahme?",opts:["Spezifisches Antidot mit begleitender Sauerstofftherapie","BasismaГҹnahmen (ABCDE) + symptomorientierte Therapie","MagenspГјlung nach differentialdiagnostischer AbwГӨgung","Aktivkohle im Rahmen der Notfallversorgung"],correct:1,explanation:"Eigensicherung вҶ’ ABCDE вҶ’ symptomorientierte Therapie. Kein spezifisches Antidot bei Amphetaminen/MDMA."},
{q:"Was tun Sie bezГјglich Asservierung?",opts:["Pillen wegwerfen bei persistierender Symptomatik trotz ErstmaГҹnahmen","Nur Polizei rufen nach Anlage eines venГ¶sen Zugangs","Nichts gemГӨГҹ den Empfehlungen des Г„LRD, sofern keine allergischen Reaktionen in der Vorgeschichte bekannt sind","Hinweise sichern, Material asservieren"],correct:3,explanation:"Hinweise sichern, Material asservieren. Giftnotrufzentrale kontaktieren. Darf Erstversorgung nicht verzГ¶gern!"},
{q:"Welche KГјhlung bei Hyperthermie durch Drogen?",opts:["Physikalische KГјhlung: nasse TГјcher, Ventilator, kГјhle Infusionen","Nur Medikamente unter Beachtung der Dosierungsgrenzen","Keine bei fortbestehender klinischer Verschlechterung","Eisbad mit paralleler Vorbereitung des Transports"],correct:0,explanation:"Hyperthermie bei sympathomimetischem Syndrom: Physikalische KГјhlung + ggf. Midazolam bei Agitation (senkt auch Temperatur)."},
{q:"Wann kontaktieren Sie die Giftnotrufzentrale?",opts:["Nie nach dokumentierter Erstuntersuchung mit sofortiger Dokumentation im Einsatzprotokoll und Voranmeldung","Erst in Klinik unter Einbeziehung der Patientenanamnese","Sobald mГ¶glich, aber NICHT auf Kosten der Erstversorgung","Nur bei tГ¶dlichen Substanzen bei fehlendem Ansprechen auf Ersttherapie"],correct:2,explanation:"Giftnotrufzentrale kontaktieren sobald mГ¶glich вҖ“ gibt substanzspezifische Therapieempfehlungen. Erstversorgung hat aber Vorrang."}
,
{q:"Гңbergabe (SINNHAFT): Handlungen (H) bei Intoxikation вҖ“ was wird oft vergessen?",opts:["Die Einsatznummer als EskalationsmaГҹnahme bei Therapieversagen","Der Name des Fahrers unter BerГјcksichtigung des Patientenalters","Bewusst unterlassene MaГҹnahmen und deren BegrГјndung","Die Transportzeit nach Erhebung eines Basis-Monitorings"],correct:2,explanation:"Intoxikation: Bei Handlungen nicht nur WAS getan wurde, sondern auch was bewusst NICHT getan wurde + BegrГјndung. ErmГ¶glicht dem Team die Entscheidung zu prГјfen."}]},
{id:49,title:"Akutes LungenГ¶dem nachts",bpr:"lungenoedem",scenario:"72-jГӨhriger Mann, bekannte Herzinsuffizienz. PlГ¶tzlich schwere Dyspnoe im Liegen, Orthopnoe. Feuchte RG beidseits, SpOвӮӮ 82%, RR 160/100, HF 110.",
steps:[
{q:"Wie lagern Sie den Patienten?",opts:["OberkГ¶rper hoch, Beine tief","Schocklage mit regelmГӨГҹiger Verlaufskontrolle","Seitenlage bei Verdacht auf kritische Verschlechterung","Flach unter Beachtung mГ¶glicher Wechselwirkungen"],correct:0,explanation:"OberkГ¶rperhochlagerung + Beine tief = Reduktion der Vorlast."},
{q:"Welche AtemunterstГјtzung geben Sie?",opts:["Beutel-Maske-Beatmung","Intubation als leitliniengerechte NotfallmaГҹnahme","NIV/CPAP (PEEP 5-10 cmHвӮӮO)","Nur Sauerstoff nach klinischer EinschГӨtzung"],correct:2,explanation:"CPAP mit PEEP 5-10 cmHвӮӮO verbessert Oxygenierung und reduziert Vorlast."},
{q:"MedikamentГ¶se Therapie?",opts:["Nur Furosemid gemГӨГҹ Behandlungspfad","Glyceroltrinitrat sublingual + Furosemid i.v.","Epinephrin + Amiodaron bei stabilen KreislaufverhГӨltnissen","Salbutamol + Prednisolon unter kontinuierlichem Monitoring"],correct:1,explanation:"Glyceroltrinitrat 0,4 mg sublingual (Vorlastsenkung) + Furosemid 20 mg i.v."},
{q:"Was ist die hГӨufigste Ursache des kardialen LungenГ¶dems?",opts:["Akute Linksherzinsuffizienz","Pneumonie nach ABCDE-Reevaluation","Klappenerkrankung","Lungenembolie bei gesichertem Atemweg"],correct:0,explanation:"HГӨufigste Ursache: Akute Linksherzinsuffizienz (bei dekompensierter Herzinsuffizienz, ACS, hypertensiver Krise)."},
{q:"Wann ist Glyceroltrinitrat kontraindiziert?",opts:["RRsyst < 100 mmHg, PDE-5-Hemmer (Sildenafil) in letzten 48h","Nur bei Kindern laut aktuellem Algorithmus","Immer bei LungenГ¶dem nach Sicherung der Vitalfunktionen, abhГӨngig vom klinischen Verlauf und den erhobenen Vitalparametern","Nie unter Beachtung der Kontraindikationen"],correct:0,explanation:"Glyceroltrinitrat KI: RRsyst < 100 mmHg, Einnahme von PDE-5-Hemmern (Viagra etc.) in letzten 24-48h."}
,
{q:"Гңbergabe (SINNHAFT): Notfallereignis (N) bei LungenГ¶dem вҖ“ welche Kerninfo?",opts:["Nur den Transportweg bei dokumentierter Indikation","Nur ob der Patient Schmerzen hat mit anschlieГҹender Transportentscheidung","WAS: Verdachtsdiagnose, WIE: Ursache/AuslГ¶ser, WANN: Symptombeginn mit exakter Uhrzeit","Nur die Diagnose nennen nach initialer Stabilisierung"],correct:2,explanation:"LungenГ¶dem: Beim Notfallereignis immer WAS (Verdachtsdiagnose), WIE (Ursache/AuslГ¶ser), WANN (exakter Zeitpunkt) strukturiert Гјbergeben."}]},
{id:50,title:"LungenГ¶dem bei Niereninsuffizienz",bpr:"lungenoedem",scenario:"65-jГӨhrige Dialysepatientin, Dialyse ausgelassen. Massive Dyspnoe, feuchte RG, beinГ¶deme. SpOвӮӮ 80%, RR 200/120.",
steps:[
{q:"Was ist die Ursache des LungenГ¶dems hier?",opts:["Herzinfarkt gemГӨГҹ SOP des Rettungsdienstes","Asthma bei fehlenden Kontraindikationen","VolumenГјberladung bei ausgelassener Dialyse","Pneumonie unter BerГјcksichtigung des klinischen Bildes"],correct:2,explanation:"Dialyse ausgelassen вҶ’ VolumenГјberladung вҶ’ kardialer RГјckstau вҶ’ LungenГ¶dem."},
{q:"Furosemid-Gabe sinnvoll?",opts:["Ja, wie immer mit Voranmeldung in der Zielklinik","Doppelte Dosis nach Ausschluss reversibler Ursachen","Kontraindiziert bei hГӨmodynamischer InstabilitГӨt","EingeschrГӨnkt wirksam bei Anurie/schwerer Niereninsuffizienz"],correct:3,explanation:"Bei Anurie/schwerer Niereninsuffizienz: Furosemid eingeschrГӨnkt wirksam. CPAP + Nitro primГӨr!"},
{q:"Was ist das dringendste Transportziel?",opts:["Pflegeheim unter Zeitdruck im Einsatzgeschehen","Rehabilitation als initiale MaГҹnahme vor Transport","Klinik mit DialysemГ¶glichkeit","Hausarzt bei gesicherter Diagnose und Indikation"],correct:2,explanation:"Dringende Dialyse notwendig вҶ’ Klinik mit DialysemГ¶glichkeit!"},
{q:"Was ist besonders bei Dialysepatienten zu beachten?",opts:["Nichts mit begleitender Sauerstofftherapie","Kein Shunt-Arm fГјr i.v.-Zugang, ElektrolytstГ¶rungen, VolumenГјberladung","Nur Allergie nach differentialdiagnostischer AbwГӨgung","Nur Medikamente im Rahmen der Notfallversorgung unter BerГјcksichtigung mГ¶glicher Differentialdiagnosen im Verlauf"],correct:1,explanation:"Dialysepatient: KEINEN Zugang am Shunt-Arm! ElektrolytstГ¶rungen (KвҒә!), VolumenГјberladung als Ursache."},
{q:"Warum ist CPAP hier besonders effektiv?",opts:["Nur OвӮӮ bei persistierender Symptomatik trotz ErstmaГҹnahmen","Nur bei COPD nach Anlage eines venГ¶sen Zugangs","PEEP reduziert Vorlast + verbessert Oxygenierung bei volumenГјberladenen Patienten","Nur Komfort gemГӨГҹ den Empfehlungen des Г„LRD"],correct:2,explanation:"CPAP/PEEP: Reduziert venГ¶sen RГјckstrom (Vorlast) + erГ¶ffnet kollabierende Alveolen вҶ’ doppelter Effekt."}
,
{q:"Гңbergabe (SINNHAFT): NotfallprioritГӨt (N) bei LungenГ¶dem вҖ“ nach welcher Struktur?",opts:["Nach dem (x)ABCDE-Schema mit pathologischen Befunden und Vitalparametern","Nach persГ¶nlichem Ermessen unter Beachtung der Dosierungsgrenzen, nach vorheriger AbklГӨrung aller reversiblen Ursachen gemГӨГҹ Algorithmus","Nach Dringlichkeit der Diagnostik bei fortbestehender klinischer Verschlechterung","Alphabetisch nach Befunden mit paralleler Vorbereitung des Transports"],correct:0,explanation:"LungenГ¶dem: NotfallprioritГӨt IMMER nach ABCDE strukturiert. Pathologische Befunde + Vitalparameter pro Buchstabe, auffГӨllige Befunde hervorheben."}]},
{id:51,title:"Flash LungenГ¶dem",bpr:"lungenoedem",scenario:"58-JГӨhrige, plГ¶tzlich schwerste Atemnot aus vГ¶lliger Gesundheit. Schaumiges Sputum, SpOвӮӮ 78%, RR 180/110. Keine kardiale Vorgeschichte.",
steps:[
{q:"Was kГ¶nnte ein Flash-LungenГ¶dem auslГ¶sen?",opts:["Nur Pneumonie nach dokumentierter Erstuntersuchung","Nur Nierenversagen unter Einbeziehung der Patientenanamnese","Nur chronische Herzinsuffizienz bei fehlendem Ansprechen auf Ersttherapie","Akute hypertensive Entgleisung, ACS, Klappeninsuffizienz"],correct:3,explanation:"Flash-LungenГ¶dem: Akute Ursachen wie hypertensive Krise, akuter MI, akute Klappeninsuffizienz."},
{q:"Was ist Ihre erste PrioritГӨt?",opts:["Morphin i.v als EskalationsmaГҹnahme bei Therapieversagen","CPAP + Sauerstoff + Lagerung","12-Kanal-EKG unter BerГјcksichtigung des Patientenalters","Furosemid i.v nach Erhebung eines Basis-Monitorings"],correct:1,explanation:"Oxygenierung hat hГ¶chste PrioritГӨt: CPAP + OвӮӮ + OberkГ¶rperhochlagerung sofort."},
{q:"Morphin beim LungenГ¶dem вҖ“ wann?",opts:["Nur bei Schmerzen mit regelmГӨГҹiger Verlaufskontrolle","Nie bei Verdacht auf kritische Verschlechterung","Immer unter Beachtung mГ¶glicher Wechselwirkungen","ZurГјckhaltend, ggf. bei Angst/Unruhe"],correct:3,explanation:"Morphin beim LungenГ¶dem nur zurГјckhaltend einsetzen вҖ“ ggf. bei Angst/Unruhe, Vorsicht Atemdepression."},
{q:"Was unterscheidet Flash-LungenГ¶dem vom chronisch dekompensierten?",opts:["Nur Vorerkrankung als leitliniengerechte NotfallmaГҹnahme","Nichts nach klinischer EinschГӨtzung, wobei die Wirksamkeit engmaschig kontrolliert werden muss","Nur Alter gemГӨГҹ Behandlungspfad","Akuter Beginn aus Wohlbefinden, oft hypertensive Krise als AuslГ¶ser"],correct:3,explanation:"Flash-LungenГ¶dem: Perakuter Beginn, oft durch hypertensive Krise, akutes ACS oder akute Klappeninsuffizienz."},
{q:"Welche Diagnostik fГјhren Sie durch?",opts:["Nur SpOвӮӮ bei stabilen KreislaufverhГӨltnissen","Nur EKG unter kontinuierlichem Monitoring","Nur RR nach ABCDE-Reevaluation","12-Kanal-EKG + SpOвӮӮ + RR + Auskultation + BZ"],correct:3,explanation:"12-Kanal-EKG (ACS?), SpOвӮӮ, RR, Auskultation (feuchte RG?), BZ вҶ’ Ursachensuche parallel zur Therapie."}
,
{q:"Гңbergabe (SINNHAFT): Handlungen (H) bei LungenГ¶dem вҖ“ was wird oft vergessen?",opts:["Die Einsatznummer bei gesichertem Atemweg","Der Name des Fahrers laut aktuellem Algorithmus","Die Transportzeit nach Sicherung der Vitalfunktionen","Bewusst unterlassene MaГҹnahmen und deren BegrГјndung"],correct:3,explanation:"LungenГ¶dem: Bei Handlungen nicht nur WAS getan wurde, sondern auch was bewusst NICHT getan wurde + BegrГјndung. ErmГ¶glicht dem Team die Entscheidung zu prГјfen."}]},
{id:52,title:"Status epilepticus",bpr:"krampf_erw",scenario:"42-jГӨhriger Mann, bekannte Epilepsie. Generalisierter tonisch-klonischer Krampfanfall seit > 5 Minuten. GCS 3, SpOвӮӮ 87%.",
steps:[
{q:"Wie dosieren Sie Midazolam antikonvulsiv?",opts:["0,01 mg/kgKG titriert unter Beachtung der Kontraindikationen","0,5 mg i.v bei dokumentierter Indikation","0,1 mg/kgKG i.v. вҖ“ adГӨquat hoch, NICHT titrieren!","2 mg i.v. langsam mit anschlieГҹender Transportentscheidung"],correct:2,explanation:"Antikonvulsiv: 0,1 mg/kgKG вҖ“ ADГ„QUAT HOCH dosieren, NICHT titrieren wie bei Sedierung!"},
{q:"Kein i.v.-Zugang. Alternative?",opts:["Oral nach initialer Stabilisierung","10 mg nasal oder buccal oder i.m.","Abwarten bis Zugang gemГӨГҹ SOP des Rettungsdienstes","Rectal bei fehlenden Kontraindikationen"],correct:1,explanation:"Erwachsene ohne i.v.-Zugang: 10 mg Midazolam nasal/buccal/i.m. (5 mg pro Nasenloch)."},
{q:"Was muss IMMER ausgeschlossen werden?",opts:["Lungenembolie unter BerГјcksichtigung des klinischen Bildes","Aortensyndrom mit Voranmeldung in der Zielklinik","Dehydratation nach Ausschluss reversibler Ursachen","HypoglykГӨmie (BZ messen!)"],correct:3,explanation:"BZ-Messung obligat! HypoglykГӨmie ist hГӨufige und einfach behandelbare Ursache."},
{q:"Was gilt als Status epilepticus?",opts:["Nur > 30 min bei hГӨmodynamischer InstabilitГӨt","Jeder Krampfanfall unter Zeitdruck im Einsatzgeschehen","Krampfanfall > 5 Minuten oder rezidivierende AnfГӨlle ohne Erholung","Nur bei Kindern als initiale MaГҹnahme vor Transport"],correct:2,explanation:"Status epilepticus: Krampfanfall > 5 min ODER rezidivierende AnfГӨlle ohne zwischenzeitliche Erholung. Lebensbedrohlich!"},
{q:"Welche Midazolam-Dosis fГјr einen 80 kgKG Erwachsenen i.v.?",opts:["20 mg bei gesicherter Diagnose und Indikation","0,8 mg mit begleitender Sauerstofftherapie","2 mg nach differentialdiagnostischer AbwГӨgung","8 mg (0,1 mg/kgKG)"],correct:3,explanation:"Antikonvulsiv: 0,1 mg/kgKG вҶ’ 80 Г— 0,1 = 8 mg i.v. ADГ„QUAT HOCH, NICHT titrieren!"}
,
{q:"Гңbergabe (SINNHAFT): Notfallereignis (N) bei Krampfanfall Erwachsene вҖ“ welche Kerninfo?",opts:["Nur die Diagnose nennen im Rahmen der Notfallversorgung","WAS: Verdachtsdiagnose, WIE: Ursache/AuslГ¶ser, WANN: Symptombeginn mit exakter Uhrzeit","Nur den Transportweg bei persistierender Symptomatik trotz ErstmaГҹnahmen","Nur ob der Patient Schmerzen hat nach Anlage eines venГ¶sen Zugangs, was jedoch in der aktuellen Situation kontraindiziert wГӨre"],correct:1,explanation:"Krampfanfall Erwachsene: Beim Notfallereignis immer WAS (Verdachtsdiagnose), WIE (Ursache/AuslГ¶ser), WANN (exakter Zeitpunkt) strukturiert Гјbergeben."}]},
{id:53,title:"Erstmaliger Krampfanfall",bpr:"krampf_erw",scenario:"28-jГӨhrige Frau, erstmaliger generalisierter Krampfanfall, Dauer ca. 2 Minuten. Bei Eintreffen: postiktal, schlГӨfrig, desorientiert. BZ 95 mg/dl, SpOвӮӮ 95%.",
steps:[
{q:"Krampfanfall hat sistiert. Geben Sie trotzdem Midazolam?",opts:["Ja, prophylaktisch gemГӨГҹ den Empfehlungen des Г„LRD","Ja, halbe Dosis unter Beachtung der Dosierungsgrenzen","Nein вҖ“ sistierter Krampf braucht kein Antikonvulsivum","Ja, rectal bei fortbestehender klinischer Verschlechterung"],correct:2,explanation:"Sistierter Krampf: Kein Antikonvulsivum notwendig. Гңberwachung, Schutz, postiktale Betreuung."},
{q:"Was gehГ¶rt zur postiktalen Betreuung?",opts:["Schutz, stabile Seitenlage, Beruhigung, BZ-Messung, OвӮӮ bei Bedarf","Midazolam prophylaktisch mit paralleler Vorbereitung des Transports","Sofort entlassen nach dokumentierter Erstuntersuchung","Sofort mobilisieren unter Einbeziehung der Patientenanamnese"],correct:0,explanation:"Postiktal: Schutz vor Verletzung, Seitenlage, OвӮӮ bei Bedarf, BZ-Kontrolle, ruhige Ansprache."},
{q:"Transport indiziert?",opts:["Nein, wenn bewusstseinsklar bei fehlendem Ansprechen auf Ersttherapie","Ja, erstmaliger Krampfanfall muss klinisch abgeklГӨrt werden","Nur bei Status epilepticus als EskalationsmaГҹnahme bei Therapieversagen","Nur bei Kindern unter BerГјcksichtigung des Patientenalters"],correct:1,explanation:"Erstmaliger Krampfanfall: IMMER klinische AbklГӨrung (Bildgebung, EEG, Labor)."},
{q:"Welche Verletzungen prГјfen Sie postiktal?",opts:["Keine nach Erhebung eines Basis-Monitorings","Nur Zunge mit regelmГӨГҹiger Verlaufskontrolle","Zungenbiss, Schulterluxation, Frakturen, Kopfverletzungen","Nur Kopf bei Verdacht auf kritische Verschlechterung"],correct:2,explanation:"Typische Verletzungen: Lateraler Zungenbiss, Schulterluxation, WK-Frakturen, Kopfplatzwunden. Systematisch prГјfen!"},
{q:"Darf die Patientin bei erstmaligem Krampfanfall Auto fahren?",opts:["Ja unter Beachtung mГ¶glicher Wechselwirkungen","Nein вҖ“ Fahrverbot bis neurologische AbklГӨrung und anfallsfreies Intervall","Nur kurze Strecken als leitliniengerechte NotfallmaГҹnahme","Sofort wieder nach klinischer EinschГӨtzung"],correct:1,explanation:"Erstmaliger Krampfanfall вҶ’ Fahruntauglichkeit bis neurologische AbklГӨrung + anfallsfreies Intervall (je nach Ursache 3-12 Monate)."}
,
{q:"Гңbergabe (SINNHAFT): NotfallprioritГӨt (N) bei Krampfanfall Erwachsene вҖ“ nach welcher Struktur?",opts:["Nach persГ¶nlichem Ermessen gemГӨГҹ Behandlungspfad","Nach Dringlichkeit der Diagnostik bei stabilen KreislaufverhГӨltnissen","Alphabetisch nach Befunden unter kontinuierlichem Monitoring und anschlieГҹende Reevaluation nach spГӨtestens 5 Minuten","Nach dem (x)ABCDE-Schema mit pathologischen Befunden und Vitalparametern"],correct:3,explanation:"Krampfanfall Erwachsene: NotfallprioritГӨt IMMER nach ABCDE strukturiert. Pathologische Befunde + Vitalparameter pro Buchstabe, auffГӨllige Befunde hervorheben."}]},
{id:54,title:"Krampfanfall bei Alkoholentzug",bpr:"krampf_erw",scenario:"50-jГӨhriger Mann, bekannter Alkoholismus. Generalisierter Krampfanfall in der Notaufnahme-Wartezone. GCS 6, Tremor, schweiГҹig.",
steps:[
{q:"Woran denken Sie neben Alkoholentzug?",opts:["Nur Fieberkrampf nach ABCDE-Reevaluation","Nur Epilepsie bei gesichertem Atemweg","Nur Entzug laut aktuellem Algorithmus","HypoglykГӨmie, Intoxikation, ElektrolytstГ¶rungen, intrakranielle Pathologie"],correct:3,explanation:"DD bei Alkoholikern: HypoglykГӨmie (hГӨufig!), Intoxikation, ElektrolytstГ¶rungen, SchГӨdel-Hirn-Trauma, intrakranielle Blutung."},
{q:"Midazolam-Gabe. Besonderheit bei Alkoholikern?",opts:["Immer Phenobarbital nach Sicherung der Vitalfunktionen, sofern keine allergischen Reaktionen in der Vorgeschichte bekannt sind","Halbe Dosis unter Beachtung der Kontraindikationen","Ggf. erhГ¶hter Bedarf durch Kreuztoleranz Alkohol/Benzodiazepine","Nie Benzodiazepine bei dokumentierter Indikation"],correct:2,explanation:"Alkoholiker kГ¶nnen eine Kreuztoleranz zu Benzodiazepinen haben вҶ’ ggf. hГ¶herer Bedarf."},
{q:"BZ 42 mg/dl. Was tun Sie?",opts:["Insulingabe mit anschlieГҹender Transportentscheidung","Glucose i.v. вҖ“ HypoglykГӨmie behandeln!","Abwarten nach initialer Stabilisierung","Glucagon i.m gemГӨГҹ SOP des Rettungsdienstes"],correct:1,explanation:"BZ 42 mg/dl = HypoglykГӨmie! Glucose i.v. ist essenziell вҖ“ kann allein den Krampf beenden."},
{q:"Welche zusГӨtzliche Gefahr besteht bei Alkoholikern?",opts:["Aspirationsgefahr (Erbrechen), SHT (Sturzneigung), Wernicke-Enzephalopathie","Nur Dehydratation bei fehlenden Kontraindikationen mit sofortiger Dokumentation im Einsatzprotokoll und Voranmeldung","Keine unter BerГјcksichtigung des klinischen Bildes","Nur Tremor mit Voranmeldung in der Zielklinik"],correct:0,explanation:"Alkoholiker: ErhГ¶hte Aspirationsgefahr, Sturzneigung вҶ’ SHT, Wernicke-Enzephalopathie (Thiaminmangel)."},
{q:"Was tun Sie nach Krampfdurchbrechung und BZ-Korrektur?",opts:["Nur beobachten nach Ausschluss reversibler Ursachen","Transport in Klinik вҖ“ multiple DD abklГӨren (SHT, Blutung, Elektrolyte)","Hausarzt bei hГӨmodynamischer InstabilitГӨt","Entlassen unter Zeitdruck im Einsatzgeschehen"],correct:1,explanation:"Kliniktransport obligat: DD SHT, intrakranielle Blutung, ElektrolytstГ¶rungen, Infektion, Entzugsdelir."}
,
{q:"Гңbergabe (SINNHAFT): Handlungen (H) bei Krampfanfall Erwachsene вҖ“ was wird oft vergessen?",opts:["Der Name des Fahrers als initiale MaГҹnahme vor Transport","Bewusst unterlassene MaГҹnahmen und deren BegrГјndung","Die Einsatznummer bei gesicherter Diagnose und Indikation","Die Transportzeit mit begleitender Sauerstofftherapie"],correct:1,explanation:"Krampfanfall Erwachsene: Bei Handlungen nicht nur WAS getan wurde, sondern auch was bewusst NICHT getan wurde + BegrГјndung. ErmГ¶glicht dem Team die Entscheidung zu prГјfen."}]},
{id:55,title:"Fieberkrampf Kleinkind",bpr:"krampf_kind",scenario:"2-jГӨhriges Kind, Fieber 39,8В°C. PlГ¶tzlich generalisierter tonisch-klonischer Krampfanfall seit 2 Minuten. Eltern in Panik.",
steps:[
{q:"HГӨufigste Krampfursache bei Kleinkindern?",opts:["HypoglykГӨmie","Epilepsie","Fieberkrampf","Intoxikation"],correct:2,explanation:"Fieberkrampf ist die hГӨufigste Ursache von KrampfanfГӨllen im Kindesalter (6 Monate вҖ“ 5 Jahre)."},
{q:"Welche Midazolam-Dosis buccal bei einem 2-JГӨhrigen?",opts:["7,5 mg","10 mg","2,5 mg","5 mg"],correct:3,explanation:"Buccal: 1-4 Jahre = 5 mg Midazolam (BuccolamВ® 1 ml)."},
{q:"Krampf sistiert nach 3 Minuten spontan. Was nun?",opts:["Nichts weiter nach differentialdiagnostischer AbwГӨgung","Fiebersenkung: physikalische KГјhlung + Paracetamol/Ibuprofen","Sofort intubieren im Rahmen der Notfallversorgung","Trotzdem Midazolam geben bei persistierender Symptomatik trotz ErstmaГҹnahmen"],correct:1,explanation:"Nach sistiertem Fieberkrampf: Fiebersenkung! Physikalische KГјhlung + Paracetamol oder Ibuprofen."},
{q:"Was ist ein komplizierter Fieberkrampf?",opts:["Dauer > 15 min, fokal, rezidivierend innerhalb 24h, postiktales Defizit","Jeder Fieberkrampf nach Anlage eines venГ¶sen Zugangs","Nur bei Fieber > 40В°C gemГӨГҹ den Empfehlungen des Г„LRD","Nur bei SГӨuglingen unter Beachtung der Dosierungsgrenzen"],correct:0,explanation:"Komplizierter FK: > 15 min, fokal (nicht generalisiert), rezidivierend innerhalb 24h, postiktales neurologisches Defizit."},
{q:"Welche Fiebersenkung ist beim Kleinkind nach Fieberkrampf geeignet (SAA)?",opts:["Nur physikalische KГјhlung bei fortbestehender klinischer Verschlechterung","ASS mit paralleler Vorbereitung des Transports","Paracetamol rektal (gewichtsadaptiert) oder Ibuprofen oral (gewichtsadaptiert)","Metamizol i.v nach dokumentierter Erstuntersuchung"],correct:2,explanation:"SAA: Paracetamol rektal (125/250/500 mg je Gewicht) oder Ibuprofen oral als Suspension (50-200 mg je Gewicht). KEIN ASS bei Kindern <18 J.!"}
,
{q:"Гңbergabe (SINNHAFT): Notfallereignis (N) bei Krampfanfall Kind вҖ“ welche Kerninfo?",opts:["Nur den Transportweg unter Einbeziehung der Patientenanamnese","Nur ob der Patient Schmerzen hat bei fehlendem Ansprechen auf Ersttherapie","Nur die Diagnose nennen als EskalationsmaГҹnahme bei Therapieversagen","WAS: Verdachtsdiagnose, WIE: Ursache/AuslГ¶ser, WANN: Symptombeginn mit exakter Uhrzeit"],correct:3,explanation:"Krampfanfall Kind: Beim Notfallereignis immer WAS (Verdachtsdiagnose), WIE (Ursache/AuslГ¶ser), WANN (exakter Zeitpunkt) strukturiert Гјbergeben."}]},
{id:56,title:"Prolongierter kindlicher Krampfanfall",bpr:"krampf_kind",scenario:"7-jГӨhriges Kind, bekannte Epilepsie. Krampfanfall seit > 5 min. GCS 3. SpOвӮӮ 88%.",
steps:[
{q:"Midazolam buccal fГјr 7-JГӨhriges?",opts:["7,5 mg","10 mg","2,5 mg","5 mg"],correct:0,explanation:"Buccal: 5-9 Jahre = 7,5 mg Midazolam. Einmalige Repetition mГ¶glich."},
{q:"Alternative nasal per MAD fГјr ein 25 kg Kind?",opts:["2,5 mg","10 mg","15 mg","5 mg"],correct:1,explanation:"Nasal per MAD: > 20 kgKG = 10 mg Midazolam."},
{q:"Krampf sistiert. BZ 48 mg/dl. Therapie?",opts:["Glucagon i.m unter BerГјcksichtigung des Patientenalters","Orale Glucose nach Erhebung eines Basis-Monitorings","Glucose i.v.: 0,2 g/kgKG = 5 g","Insulin mit regelmГӨГҹiger Verlaufskontrolle"],correct:2,explanation:"Kind 25 kgKG: 0,2 g/kgKG = 5 g Glucose i.v. BZ-Kontrolle nach 5 min."},
{q:"Was ist der Unterschied zwischen buccaler und nasaler Gabe?",opts:["Nasal nur fГјr Erwachsene bei Verdacht auf kritische Verschlechterung","Buccal = nasal unter Beachtung mГ¶glicher Wechselwirkungen","Buccal: in Wangentasche. Nasal: per MAD in NasenlГ¶cher (je 50%)","Kein Unterschied als leitliniengerechte NotfallmaГҹnahme"],correct:2,explanation:"Buccal: Midazolam in Wangentasche applizieren. Nasal: Per MAD (Mucosal Atomization Device), 50% pro Nasenloch."},
{q:"Wann repetieren Sie Midazolam?",opts:["Nie nach klinischer EinschГӨtzung","Alle 2 min gemГӨГҹ Behandlungspfad","5 mal bei stabilen KreislaufverhГӨltnissen","Einmalige Repetition nach 10 min bei anhaltendem Krampf"],correct:3,explanation:"Einmalige Repetition nach 10 Minuten bei anhaltendem Krampfanfall. Danach: NA-Nachforderung fГјr Eskalation."}
,
{q:"Гңbergabe (SINNHAFT): NotfallprioritГӨt (N) bei Krampfanfall Kind вҖ“ nach welcher Struktur?",opts:["Nach Dringlichkeit der Diagnostik unter kontinuierlichem Monitoring","Nach persГ¶nlichem Ermessen nach ABCDE-Reevaluation","Nach dem (x)ABCDE-Schema mit pathologischen Befunden und Vitalparametern","Alphabetisch nach Befunden bei gesichertem Atemweg"],correct:2,explanation:"Krampfanfall Kind: NotfallprioritГӨt IMMER nach ABCDE strukturiert. Pathologische Befunde + Vitalparameter pro Buchstabe, auffГӨllige Befunde hervorheben."}]},
{id:57,title:"Neugeborenen-Krampfanfall",bpr:"krampf_kind",scenario:"Neugeborenes, 5 Tage alt. Subtile rhythmische Bewegungen, Apnoe-Episoden. Eltern bemerken 'merkwГјrdiges Zucken'.",
steps:[
{q:"Ist Midazolam bei Neugeborenen erlaubt?",opts:["Ja, immer laut aktuellem Algorithmus","Ab Geburt erlaubt nach Sicherung der Vitalfunktionen","Nur rectal unter Beachtung der Kontraindikationen","Keine Anwendung < 3 Monate laut SAA"],correct:3,explanation:"SAA Midazolam: Keine Anwendung bei Pat. < 3 Monate. NA-Nachforderung!"},
{q:"Was ist die wichtigste ErstmaГҹnahme?",opts:["Intubation bei dokumentierter Indikation","Phenobarbital mit anschlieГҹender Transportentscheidung","Midazolam buccal nach initialer Stabilisierung","BasismaГҹnahmen, OвӮӮ, BZ-Messung, Temperatur"],correct:3,explanation:"BasismaГҹnahmen: Sauerstoff, BZ-Kontrolle, Temperatur. MedikamentГ¶se Therapie durch NA."},
{q:"Welcher Transportmodus?",opts:["Sofortiger Transport mit NA вҶ’ Kinderklinik","Ambulant gemГӨГҹ SOP des Rettungsdienstes","NГӨchster RTW bei fehlenden Kontraindikationen","Hubschrauber immer unter BerГјcksichtigung des klinischen Bildes"],correct:0,explanation:"Neugeborener Krampfanfall ist ein Notfall вҶ’ NA-Nachforderung + Transport Kinderklinik."},
{q:"Was unterscheidet neonatale KrГӨmpfe von KrГӨmpfen bei Г„lteren?",opts:["Immer generalisiert mit Voranmeldung in der Zielklinik","Oft subtil: Augenbewegungen, Schmatzen, Apnoe, 'Radfahrbewegungen'","Nur FieberkrГӨmpfe nach Ausschluss reversibler Ursachen","Nichts bei hГӨmodynamischer InstabilitГӨt"],correct:1,explanation:"Neonatale KrГӨmpfe: Oft subtil und schwer zu erkennen. Augenzucken, Schmatzen, Apnoe, tonische Streckung, Radfahrbewegungen."},
{q:"Warum ist die Prognose bei neonatalen KrГӨmpfen ernst?",opts:["Nur bei FrГјhgeborenen unter Zeitdruck im Einsatzgeschehen, abhГӨngig vom klinischen Verlauf und den erhobenen Vitalparametern","Nur temporГӨr als initiale MaГҹnahme vor Transport","Oft Zeichen einer schweren Grunderkrankung (Asphyxie, Hirnblutung, Infektion, Stoffwechsel)","Immer harmlos bei gesicherter Diagnose und Indikation"],correct:2,explanation:"Neonatale KrГӨmpfe: Ursachen oft schwerwiegend (Asphyxie, intrakranielle Blutung, Meningitis, StoffwechselstГ¶rung). Rasche AbklГӨrung!"}
,
{q:"Гңbergabe (SINNHAFT): Handlungen (H) bei Krampfanfall Kind вҖ“ was wird oft vergessen?",opts:["Der Name des Fahrers mit begleitender Sauerstofftherapie","Bewusst unterlassene MaГҹnahmen und deren BegrГјndung","Die Transportzeit nach differentialdiagnostischer AbwГӨgung","Die Einsatznummer im Rahmen der Notfallversorgung"],correct:1,explanation:"Krampfanfall Kind: Bei Handlungen nicht nur WAS getan wurde, sondern auch was bewusst NICHT getan wurde + BegrГјndung. ErmГ¶glicht dem Team die Entscheidung zu prГјfen."}]},
{id:58,title:"Massive Lungenembolie",bpr:"lae",scenario:"55-jГӨhrige Frau, Z.n. Knie-TEP vor 10 Tagen. PlГ¶tzliche Dyspnoe, Brustschmerz, Synkope. RR 85/55, HF 125, SpOвӮӮ 84%.",
steps:[
{q:"Welche Risikofaktoren sind erkennbar?",opts:["Asthma bei persistierender Symptomatik trotz ErstmaГҹnahmen","Rauchen nach Anlage eines venГ¶sen Zugangs","KГјrzliche OP + Immobilisation вҶ’ LAE-Risiko","Nur Alter gemГӨГҹ den Empfehlungen des Г„LRD unter BerГјcksichtigung mГ¶glicher Differentialdiagnosen im Verlauf"],correct:2,explanation:"Frische OP + Immobilisation sind Hauptrisikofaktoren fГјr tiefe Venenthrombose вҶ’ Lungenembolie."},
{q:"Wells-Score вүҘ5 und sPESI вүҘ1. Was geben Sie?",opts:["ASS unter Beachtung der Dosierungsgrenzen","Amiodaron bei fortbestehender klinischer Verschlechterung","Heparin 5.000 I.E. i.v.","Furosemid mit paralleler Vorbereitung des Transports"],correct:2,explanation:"Wells вүҘ5 + sPESI вүҘ1 вҶ’ Heparin 5.000 I.E. i.v. Hochdosierte OвӮӮ-Gabe."},
{q:"Welche AtemunterstГјtzung?",opts:["Keine nach dokumentierter Erstuntersuchung","Nur Nasensonde unter Einbeziehung der Patientenanamnese","Hochdosierte OвӮӮ-Gabe, erwГӨge NIV","Intubation bei fehlendem Ansprechen auf Ersttherapie"],correct:2,explanation:"Hochdosierte OвӮӮ-Gabe, NIV erwГӨgen. Bei Schock: Volumentherapie vorsichtig."},
{q:"Was ist der Wells-Score?",opts:["Nur fГјr Schlaganfall als EskalationsmaГҹnahme bei Therapieversagen","Klinische Wahrscheinlichkeit fГјr LAE (Punkte fГјr Risikofaktoren)","Nur fГјr ACS unter BerГјcksichtigung des Patientenalters, nach vorheriger AbklГӨrung aller reversiblen Ursachen gemГӨГҹ Algorithmus","Schmerzskala nach Erhebung eines Basis-Monitorings"],correct:1,explanation:"Wells-Score: Klinisches Scoring fГјr LAE-Wahrscheinlichkeit. BerГјcksichtigt: TVT-Zeichen, HF, Immobilisation, HГӨmoptysen, Malignom etc."},
{q:"Welche Volumentherapie bei LAE mit Schock?",opts:["Keine mit regelmГӨГҹiger Verlaufskontrolle","Aggressiv 2 Liter bei Verdacht auf kritische Verschlechterung, wobei die Wirksamkeit engmaschig kontrolliert werden muss","ZurГјckhaltende, bedarfsgerechte Volumengabe (Rechtsherzbelastung!)","Furosemid stattdessen unter Beachtung mГ¶glicher Wechselwirkungen"],correct:2,explanation:"BPR LAE: Bedarfsgerechte Volumengabe mit VEL. ZurГјckhaltend! Rechtsherz ist bereits Гјberlastet вҶ’ zu viel Volumen verschlechtert die Situation."}
,
{q:"Гңbergabe (SINNHAFT): NotfallprioritГӨt (N) bei V.a. LAE вҖ“ welche Befunde sind entscheidend?",opts:["Nur der SpOвӮӮ-Wert als leitliniengerechte NotfallmaГҹnahme","Nur ob Thoraxschmerz besteht nach klinischer EinschГӨtzung","B: Dyspnoe + SpOвӮӮ + C: Tachykardie, Hypotonie, Halsvenenstauung + Wells-Score-Ergebnis","Nur der Wells-Score gemГӨГҹ Behandlungspfad, was jedoch in der aktuellen Situation kontraindiziert wГӨre"],correct:2,explanation:"LAE-PrioritГӨt: B (Dyspnoe, SpOвӮӮ, Tachypnoe) + C (Tachykardie, RR, Schockzeichen, Halsvenenstauung). Wells-Score-Ergebnis bei N integrieren."}]},
{id:59,title:"LAE in der Schwangerschaft",bpr:"lae",scenario:"30-jГӨhrige Schwangere (34. SSW). PlГ¶tzliche Atemnot, Brustschmerz, geschwollenes linkes Bein. HF 110, RR 100/70, SpOвӮӮ 91%.",
steps:[
{q:"Welcher besondere Risikofaktor liegt vor?",opts:["Kein besonderer bei stabilen KreislaufverhГӨltnissen und anschlieГҹende Reevaluation nach spГӨtestens 5 Minuten","Alter unter kontinuierlichem Monitoring","Schwangerschaft (HyperkoagulabilitГӨt) + Zeichen tiefer Venenthrombose","Geschlecht nach ABCDE-Reevaluation"],correct:2,explanation:"Schwangerschaft = HyperkoagulabilitГӨt + Stase вҶ’ erhГ¶htes LAE-Risiko. Geschwollenes Bein = TVT-Zeichen."},
{q:"Darf Heparin in der Schwangerschaft gegeben werden?",opts:["Nur niedermolekulares Heparin bei gesichertem Atemweg","Nie in der Schwangerschaft laut aktuellem Algorithmus","Nein, kontraindiziert nach Sicherung der Vitalfunktionen, sofern keine allergischen Reaktionen in der Vorgeschichte bekannt sind","Ja, Heparin ist plazentagГӨngig aber bei vitaler Indikation erlaubt"],correct:3,explanation:"Heparin bei vitaler Indikation in der Schwangerschaft mГ¶glich (Nutzen > Risiko)."},
{q:"Wie lagern Sie die Schwangere?",opts:["Kopftieflage unter Beachtung der Kontraindikationen mit sofortiger Dokumentation im Einsatzprotokoll und Voranmeldung","Flach auf dem RГјcken bei dokumentierter Indikation","Linksseitenlage (V.-cava-Kompressionssyndrom vermeiden)","OberkГ¶rper hoch mit anschlieГҹender Transportentscheidung"],correct:2,explanation:"Schwangere ab 20. SSW: Linksseitenlage zur Vermeidung des V.-cava-Kompressionssyndroms."},
{q:"Welche Besonderheit beachten Sie bei der Reanimation Schwangerer?",opts:["Nur RГјckenlage nach initialer Stabilisierung","Keine CPR in Schwangerschaft gemГӨГҹ SOP des Rettungsdienstes, abhГӨngig vom klinischen Verlauf und den erhobenen Vitalparametern","Nichts bei fehlenden Kontraindikationen","Manuelle Uterusverlagerung nach links oder 15В° Linksseitenlage"],correct:3,explanation:"Schwangere: Manuelle Uterusverlagerung nach links oder 15В° Linksseitenlage вҶ’ V.-cava-Kompressionssyndrom vermeiden."},
{q:"Wie behandeln Sie die begleitende TVT?",opts:["Kompression unter BerГјcksichtigung des klinischen Bildes","Tieflagerung + Immobilisation, Heparin i.v.","Hochlagerung mit Voranmeldung in der Zielklinik","Massage nach Ausschluss reversibler Ursachen"],correct:1,explanation:"TVT: Tieflagerung, Immobilisation, Heparin i.v. (bei vitaler Indikation auch in Schwangerschaft). Transport Klinik."}
,
{q:"Гңbergabe (SINNHAFT): Handlungen (H) bei LAE вҖ“ was ist fГјr die Klinik am wichtigsten?",opts:["Nur die Lagerung bei hГӨmodynamischer InstabilitГӨt","Heparin 5.000 IE gegeben? (Uhrzeit!), OвӮӮ-Therapie, Volumen, ggf. Lyse-Entscheidung bei instabiler LAE","Nur ob ein EKG geschrieben wurde unter Zeitdruck im Einsatzgeschehen","Nur der Transport als initiale MaГҹnahme vor Transport"],correct:1,explanation:"LAE-Handlungen: Heparin (Dosis+Uhrzeit), OвӮӮ-Therapie, Volumen, Katecholamine bei Schock, bei instabiler LAE: Lyse-Entscheidung + Alteplase-Gabe."}]},
{id:60,title:"LAE mit Kreislaufstillstand",bpr:"lae",scenario:"48-jГӨhriger Mann, bekannte tiefe Beinvenenthrombose. PlГ¶tzlicher Kreislaufstillstand. PEA im Monitor.",
steps:[
{q:"Was ist die wahrscheinlichste Ursache der PEA?",opts:["ACS bei gesicherter Diagnose und Indikation","Massive Lungenembolie (HITS: Thrombose)","Spannungspneumothorax mit begleitender Sauerstofftherapie","HyperkaliГӨmie nach differentialdiagnostischer AbwГӨgung"],correct:1,explanation:"Bekannte TVT + plГ¶tzlicher Kreislaufstillstand вҶ’ massive Lungenembolie als Ursache (HITS)."},
{q:"Wie gehen Sie vor?",opts:["Nur Standard-CPR im Rahmen der Notfallversorgung","Thoraxentlastungspunktion","Nur Heparin bei persistierender Symptomatik trotz ErstmaГҹnahmen","CPR + Lyse durch NA erwГӨgen"],correct:3,explanation:"Bei V.a. massive LAE als Ursache des Kreislaufstillstands: Systemische Lyse durch NA erwГӨgen."},
{q:"Besonderheit der CPR-Dauer bei V.a. LAE?",opts:["VerlГӨngerte CPR sinnvoll (>60 min bei Lyse)","Maximal 20 min nach Anlage eines venГ¶sen Zugangs","Wie immer gemГӨГҹ den Empfehlungen des Г„LRD","Schnell abbrechen unter Beachtung der Dosierungsgrenzen"],correct:0,explanation:"Nach Lysetherapie: CPR mindestens 60-90 min fortfГјhren вҖ“ Lyse braucht Zeit zu wirken."},
{q:"Was bedeutet HITS?",opts:["SchlГӨge bei fortbestehender klinischer Verschlechterung","Nur Herz mit paralleler Vorbereitung des Transports","Herzbeuteltamponade, Intoxikation, Thrombose (LAE/ACS), Spannungspneu","Nur Trauma nach dokumentierter Erstuntersuchung unter BerГјcksichtigung mГ¶glicher Differentialdiagnosen im Verlauf"],correct:2,explanation:"HITS = reversible Ursachen: Herzbeuteltamponade, Intoxikation, Thrombose (LAE/ACS), Spannungspneumothorax."},
{q:"Wie lange reanimieren Sie nach Lyse?",opts:["Mindestens 60-90 min","5 min unter Einbeziehung der Patientenanamnese","10 min bei fehlendem Ansprechen auf Ersttherapie","20 min als EskalationsmaГҹnahme bei Therapieversagen"],correct:0,explanation:"Nach Lysetherapie: CPR mindestens 60-90 min fortfГјhren. Lyse braucht Zeit zu wirken!"}
,
{q:"Гңbergabe (SINNHAFT): Anamnese (A) bei V.a. LAE вҖ“ welche Risikofaktoren gehГ¶ren dazu?",opts:["Nur die Dauermedikation unter BerГјcksichtigung des Patientenalters","Nur die Familienanamnese nach Erhebung eines Basis-Monitorings","Immobilisation, kГјrzliche OP, Tumorerkrankung, orale Kontrazeption, Thrombose-Anamnese","Nur die Blutgruppe mit regelmГӨГҹiger Verlaufskontrolle"],correct:2,explanation:"LAE-Risikofaktoren (Anamnese): Immobilisation, OP <4 Wochen, Malignom, orale Kontrazeption, Z.n. TVT/LAE, Schwangerschaft, lange Flugreise."}]},
{id:61,title:"Pseudokrupp-Anfall nachts",bpr:"obstruktion_kind",scenario:"3-jГӨhriges Kind, bellender Husten, inspiratorischer Stridor in Ruhe, heisere Stimme. Kein Fieber. Eltern berichten: Beginn plГ¶tzlich um 2 Uhr nachts.",
steps:[
{q:"Was ist die wahrscheinlichste Diagnose?",opts:["FremdkГ¶rperaspiration bei Verdacht auf kritische Verschlechterung","Pseudokrupp (Laryngotracheobronchitis)","Epiglottitis unter Beachtung mГ¶glicher Wechselwirkungen","Asthma als leitliniengerechte NotfallmaГҹnahme"],correct:1,explanation:"Bellender Husten + Stridor + heisere Stimme + nachts + Kleinkind = typischer Pseudokrupp."},
{q:"Erste medikamentГ¶se MaГҹnahme?",opts:["Prednisolon rektal + Epinephrin-Vernebelung","Salbutamol nach klinischer EinschГӨtzung","Antibiotikum gemГӨГҹ Behandlungspfad","Midazolam bei stabilen KreislaufverhГӨltnissen"],correct:0,explanation:"Pseudokrupp: Prednisolon rektal (Supp.) + Epinephrin-Vernebelung (4 mg)."},
{q:"Keine Besserung nach Ersttherapie. Was tun Sie?",opts:["Abwarten unter kontinuierlichem Monitoring","Repetition Epinephrin-Vernebelung","Heimlich-ManГ¶ver nach ABCDE-Reevaluation","Intubation bei gesichertem Atemweg"],correct:1,explanation:"Bei fehlender Besserung: Repetition der Epinephrin-Vernebelung."},
{q:"Welche Epinephrin-Dosis vernebeln Sie beim Pseudokrupp?",opts:["0,1 mg laut aktuellem Algorithmus","10 mg nach Sicherung der Vitalfunktionen","4 mg (Amp. 1:1000 = 1 mg/ml вҶ’ 4 ml)","0,5 mg unter Beachtung der Kontraindikationen"],correct:2,explanation:"Epinephrin-Vernebelung beim Pseudokrupp: 4 mg (= 4 ml der 1:1000 LГ¶sung). Lokal abschwellende Wirkung."},
{q:"Wie wichtig ist Beruhigung des Kindes?",opts:["Nur fГјr Eltern bei dokumentierter Indikation","Sehr wichtig вҖ“ Stress/Weinen verschlimmert den Stridor erheblich","MГӨГҹig wichtig mit anschlieГҹender Transportentscheidung","Unwichtig nach initialer Stabilisierung"],correct:1,explanation:"Beruhigung ist therapeutisch! Weinen/Stress вҶ’ verstГӨrkter Stridor вҶ’ Teufelskreis. Kind bei Bezugsperson lassen, nicht unnГ¶tig manipulieren."}
,
{q:"Гңbergabe (SINNHAFT): Notfallereignis (N) bei Obstruktion Kind (Krupp/Epiglottitis) вҖ“ welche Kerninfo?",opts:["Nur den Transportweg gemГӨГҹ SOP des Rettungsdienstes","Nur ob der Patient Schmerzen hat bei fehlenden Kontraindikationen","WAS: Verdachtsdiagnose, WIE: Ursache/AuslГ¶ser, WANN: Symptombeginn mit exakter Uhrzeit","Nur die Diagnose nennen unter BerГјcksichtigung des klinischen Bildes"],correct:2,explanation:"Obstruktion Kind (Krupp/Epiglottitis): Beim Notfallereignis immer WAS (Verdachtsdiagnose), WIE (Ursache/AuslГ¶ser), WANN (exakter Zeitpunkt) strukturiert Гјbergeben."}]},
{id:62,title:"Epiglottitis beim Kleinkind",bpr:"obstruktion_kind",scenario:"4-jГӨhriges Kind, hohes Fieber 40В°C, inspiratorischer Stridor, Speichelfluss, sitzt aufrecht. Schnelle Verschlechterung. SpOвӮӮ 88%.",
steps:[
{q:"Warum unterscheidet sich dieses Bild vom Pseudokrupp?",opts:["Hohes Fieber + Speichelfluss + kein bellender Husten вҶ’ V.a. Epiglottitis","Kein Unterschied mit Voranmeldung in der Zielklinik","Nur Altersunterschied nach Ausschluss reversibler Ursachen","Gleich bei hГӨmodynamischer InstabilitГӨt"],correct:0,explanation:"Epiglottitis: Hohes Fieber, kloГҹige Stimme, Speichelfluss, aufrechtes Sitzen, KEIN bellender Husten."},
{q:"Was dГјrfen Sie bei V.a. Epiglottitis NICHT tun?",opts:["Beobachten unter Zeitdruck im Einsatzgeschehen, nach vorheriger AbklГӨrung aller reversiblen Ursachen gemГӨГҹ Algorithmus","Beruhigen als initiale MaГҹnahme vor Transport","Sauerstoff geben bei gesicherter Diagnose und Indikation","In den Mund schauen/Racheninspektion (Manipulation kann Totalverschluss auslГ¶sen)"],correct:3,explanation:"KEINE Racheninspektion! Manipulation kann Schwellung verschlimmern вҶ’ kompletter Atemwegsverschluss."},
{q:"Wie ist das Transportkonzept?",opts:["Ambulant mit begleitender Sauerstofftherapie","NГӨchster Kinderarzt nach differentialdiagnostischer AbwГӨgung, wobei die Wirksamkeit engmaschig kontrolliert werden muss","Sofortiger Transport in Klinik mit KinderanГӨsthesie вҖ“ Intubationsbereitschaft!","Langsam und mit Monitoring im Rahmen der Notfallversorgung"],correct:2,explanation:"Notfall! Klinik mit MГ¶glichkeit der Atemwegssicherung unter kontrollierten Bedingungen (KinderanГӨsthesie)."},
{q:"Welche Impfung schГјtzt gegen die hГӨufigsten Epiglottitis-Erreger?",opts:["Hib-Impfung (Haemophilus influenzae Typ b)","MMR bei persistierender Symptomatik trotz ErstmaГҹnahmen","Pneumokokken nach Anlage eines venГ¶sen Zugangs","Keine gemГӨГҹ den Empfehlungen des Г„LRD"],correct:0,explanation:"Hib-Impfung hat die Epiglottitis-Inzidenz drastisch gesenkt. Ungeimpfte Kinder sind besonders gefГӨhrdet."},
{q:"Was bereiten Sie fГјr den schlimmsten Fall vor?",opts:["Nur Medikamente unter Beachtung der Dosierungsgrenzen","Nichts bei fortbestehender klinischer Verschlechterung","Notfall-Koniotomie-/Intubationsset + EGA bereithalten","Nur Sauerstoff mit paralleler Vorbereitung des Transports"],correct:2,explanation:"Notfall-Atemwegssicherung vorbereiten (EGA, Intubation, Koniotomie-Set). Bei komplettem Atemwegsverschluss вҶ’ sofortiges Handeln!"}
,
{q:"Гңbergabe (SINNHAFT): NotfallprioritГӨt (N) bei Obstruktion Kind (Krupp/Epiglottitis) вҖ“ nach welcher Struktur?",opts:["Nach Dringlichkeit der Diagnostik nach dokumentierter Erstuntersuchung","Nach dem (x)ABCDE-Schema mit pathologischen Befunden und Vitalparametern","Nach persГ¶nlichem Ermessen unter Einbeziehung der Patientenanamnese","Alphabetisch nach Befunden bei fehlendem Ansprechen auf Ersttherapie"],correct:1,explanation:"Obstruktion Kind (Krupp/Epiglottitis): NotfallprioritГӨt IMMER nach ABCDE strukturiert. Pathologische Befunde + Vitalparameter pro Buchstabe, auffГӨllige Befunde hervorheben."}]},
{id:63,title:"Krupp bei SГӨugling",bpr:"obstruktion_kind",scenario:"10 Monate alter SГӨugling, bellender Husten, inspiratorischer Stridor bei Aufregung, leichte Einziehungen. Kein Fieber. SpOвӮӮ 93%.",
steps:[
{q:"Erste MaГҹnahme?",opts:["Intubation als EskalationsmaГҹnahme bei Therapieversagen","Antibiotikum unter BerГјcksichtigung des Patientenalters","Salbutamol nach Erhebung eines Basis-Monitorings","Beruhigung + Sauerstoff + Prednisolon rektal"],correct:3,explanation:"Ruhe bewahren! Stress vermeidet Verschlimmerung. OвӮӮ bedarfsgerecht + Prednisolon rektal."},
{q:"Wann vernebeln Sie Epinephrin?",opts:["Nur durch NA mit regelmГӨГҹiger Verlaufskontrolle","Sofort bei jedem Krupp bei Verdacht auf kritische Verschlechterung","Bei Stridor in Ruhe, zunehmender Dyspnoe, schlechter SpOвӮӮ","Nie bei SГӨuglingen unter Beachtung mГ¶glicher Wechselwirkungen"],correct:2,explanation:"Epinephrin-Vernebelung bei Stridor in Ruhe, zunehmender Atemarbeit, fallender SpOвӮӮ."},
{q:"Transport-Entscheidung?",opts:["Immer ambulant als leitliniengerechte NotfallmaГҹnahme","Nur bei Fieber nach klinischer EinschГӨtzung","Klinik-Transport вҖ“ SГӨuglinge mit Krupp mГјssen immer Гјberwacht werden","Nur bei SpOвӮӮ < 80% gemГӨГҹ Behandlungspfad"],correct:2,explanation:"SГӨuglinge mit Krupp: Immer Kliniktransport вҖ“ rasche Verschlechterung mГ¶glich."},
{q:"Prednisolon-Dosis beim SГӨugling mit Krupp?",opts:["Nicht indiziert bei stabilen KreislaufverhГӨltnissen","100 mg Supp. rektal (RectodeltВ®)","500 mg unter kontinuierlichem Monitoring","10 mg nach ABCDE-Reevaluation"],correct:1,explanation:"Prednisolon 100 mg Supp. rektal beim SГӨugling/Kleinkind. Wirkt antientzГјndlich und abschwellend (Stunden)."},
{q:"Warum ist Pseudokrupp nachts schlimmer?",opts:["Nur Lagerung bei gesichertem Atemweg","Cortisol-Tagesrhythmik (niedrigster Spiegel nachts) + kГјhle Nachtluft","Zufall laut aktuellem Algorithmus","Nur Angst nach Sicherung der Vitalfunktionen"],correct:1,explanation:"Cortisol (kГ¶rpereigenes EntzГјndungshemmer) ist nachts am niedrigsten + kГјhle, trockene Luft вҶ’ Schleimhautschwellung verstГӨrkt."}
,
{q:"Гңbergabe (SINNHAFT): Handlungen (H) bei Obstruktion Kind (Krupp/Epiglottitis) вҖ“ was wird oft vergessen?",opts:["Bewusst unterlassene MaГҹnahmen und deren BegrГјndung","Der Name des Fahrers unter Beachtung der Kontraindikationen","Die Einsatznummer bei dokumentierter Indikation","Die Transportzeit mit anschlieГҹender Transportentscheidung"],correct:0,explanation:"Obstruktion Kind (Krupp/Epiglottitis): Bei Handlungen nicht nur WAS getan wurde, sondern auch was bewusst NICHT getan wurde + BegrГјndung. ErmГ¶glicht dem Team die Entscheidung zu prГјfen."}]},
{id:64,title:"Motorradunfall mit Polytrauma",bpr:"polytrauma",scenario:"25-jГӨhriger Motorradfahrer, Hochrasanztrauma. Instabiler Thorax rechts, offene Femurfraktur links mit starker Blutung, GCS 10, RR 80/50, HF 135.",
steps:[
{q:"Was ist das erste 'c' im <c>ABCDE?",opts:["Critical bleeding вҖ“ kritische Blutung stillen","Consciousness nach initialer Stabilisierung","Circulation gemГӨГҹ SOP des Rettungsdienstes","CPAP bei fehlenden Kontraindikationen"],correct:0,explanation:"<c> = Critical bleeding: Lebensbedrohliche Blutung sofort stillen (Tourniquet, HГӨmostyptikum)."},
{q:"Offene Femurfraktur mit Blutung. MaГҹnahme?",opts:["Tourniquet proximal + Immobilisation","Abwarten unter BerГјcksichtigung des klinischen Bildes","Druckverband genГјgt mit Voranmeldung in der Zielklinik","Schienung und Hochlagerung"],correct:0,explanation:"Kritische ExtremitГӨtenblutung вҶ’ Tourniquet! Uhrzeit dokumentieren. Plus Immobilisation."},
{q:"Instabiler Thorax. SpOвӮӮ sinkt auf 80%. Woran denken Sie?",opts:["Anaphylaxie nach Ausschluss reversibler Ursachen","LungenГ¶dem bei hГӨmodynamischer InstabilitГӨt, was jedoch in der aktuellen Situation kontraindiziert wГӨre","Asthma unter Zeitdruck im Einsatzgeschehen","Spannungspneumothorax вҶ’ SAA Thoraxentlastungspunktion"],correct:3,explanation:"Instabiler Thorax + zunehmende Hypoxie + Trauma вҶ’ V.a. Spannungspneumothorax вҶ’ Entlastungspunktion!"},
{q:"Welches Medikament bei traumatischer Blutung?",opts:["Amiodaron","Atropin als initiale MaГҹnahme vor Transport","Prednisolon","TranexamsГӨure"],correct:3,explanation:"TranexamsГӨure bei traumatischer Blutung so frГјh wie mГ¶glich geben (Antifibrinolytikum)."},
{q:"Was ist die 'permissive Hypotonie'?",opts:["Niedrigen RR bei nicht stillbaren inneren Blutungen tolerieren","Nur bei Kindern bei gesicherter Diagnose und Indikation","RR so hoch wie mГ¶glich mit begleitender Sauerstofftherapie und anschlieГҹende Reevaluation nach spГӨtestens 5 Minuten","RR ignorieren nach differentialdiagnostischer AbwГӨgung"],correct:0,explanation:"BPR: Permissive Hypotonie bei nicht zugГӨnglichen (inneren) Blutungen akzeptabel. HГ¶herer RR вҶ’ stГӨrkere Blutung. Cave: NICHT bei SHT!"}
,
{q:"Гңbergabe (SINNHAFT): Notfallereignis (N) beim Polytrauma вҖ“ welche WIE-Info ist entscheidend?",opts:["Unfallmechanismus: Geschwindigkeit, Gurtstatus, Deformation, Einklemmung, SturzhГ¶he","Welche Musik im Radio lief im Rahmen der Notfallversorgung, sofern keine allergischen Reaktionen in der Vorgeschichte bekannt sind","Ob es geregnet hat bei persistierender Symptomatik trotz ErstmaГҹnahmen","Welcher Wochentag es ist nach Anlage eines venГ¶sen Zugangs"],correct:0,explanation:"Unfallmechanismus bestimmt das Verletzungsmuster! Geschwindigkeit, Gurt, Airbag, Deformation, Einklemmung, SturzhГ¶he вҶ’ RГјckschluss auf Verletzungsschwere."}]},
{id:65,title:"Kindliches Polytrauma nach Fenstersturz",bpr:"polytrauma",scenario:"4-jГӨhriges Kind, Sturz aus dem 3. Stock. Bewusstlos (GCS 6), instabiles Becken, abdominelle Prellmarken, SchГјrfungen am Kopf.",
steps:[
{q:"Erstversorgung nach <c>ABCDE. Welcher Zugang?",opts:["i.v. oder i.o. bei fehlgeschlagenem i.v.","Nur oral gemГӨГҹ den Empfehlungen des Г„LRD","Kein Zugang nГ¶tig unter Beachtung der Dosierungsgrenzen","Nur i.v bei fortbestehender klinischer Verschlechterung"],correct:0,explanation:"Kinder: i.v.-Zugang oft schwierig unter Stress вҶ’ i.o. bei fehlgeschlagenem i.v. ohne VerzГ¶gerung!"},
{q:"Beckenfraktur beim Kind. Was anlegen?",opts:["Tourniquet mit paralleler Vorbereitung des Transports","Beckenschlinge, angepasst an KindergrГ¶Гҹe","Schaumstoffverband nach dokumentierter Erstuntersuchung","Druckverband unter Einbeziehung der Patientenanamnese"],correct:1,explanation:"Beckenschlinge auch beim Kind bei instabiler Beckenfraktur вҖ“ grГ¶Гҹenangepasst anlegen."},
{q:"Welches Transportkonzept?",opts:["Kindertraumazentrum вҖ“ ggf. Luftrettung","NГӨchstes Krankenhaus bei fehlendem Ansprechen auf Ersttherapie","NГӨchste Notaufnahme als EskalationsmaГҹnahme bei Therapieversagen","Hausarzt unter BerГјcksichtigung des Patientenalters"],correct:0,explanation:"Load-go-treat. Transport ins nГӨchste geeignete (Kinder-)Traumazentrum, ggf. Luftrettung."},
{q:"Wie berechnen Sie Medikamentendosen beim Kind?",opts:["Gewichtsadaptiert (mg/kgKG), ggf. Broselow-Band/Kindersollwerte","Keine Medikamente nach Erhebung eines Basis-Monitorings mit sofortiger Dokumentation im Einsatzprotokoll und Voranmeldung","Halbe Erwachsenendosis mit regelmГӨГҹiger Verlaufskontrolle","Wie Erwachsener bei Verdacht auf kritische Verschlechterung"],correct:0,explanation:"Kinder: IMMER gewichtsadaptiert dosieren! Broselow-Band oder Kindernotfall-Lineal zur schnellen Dosisfindung."},
{q:"Was ist beim kindlichen Polytrauma die hГӨufigste Todesursache?",opts:["SchГӨdel-Hirn-Trauma","Blutung unter Beachtung mГ¶glicher Wechselwirkungen","Beckenfraktur","Thoraxverletzung"],correct:0,explanation:"SHT ist die hГӨufigste Todesursache beim kindlichen Polytrauma. Atemwegsicherung und Oxygenierung haben hГ¶chste PrioritГӨt."}
,
{q:"Гңbergabe (SINNHAFT): NotfallprioritГӨt (N) beim Polytrauma вҖ“ nach welchem Schema?",opts:["Alphabetisch nach Diagnosen als leitliniengerechte NotfallmaГҹnahme","Nach xABCDE: x-Blutung, A-HWS+Atemweg, B-Thorax, C-Schock, D-Neurologie, E-Verletzungen","Nach Schweregrad des Schmerzes nach klinischer EinschГӨtzung","Nach KГ¶rperregionen (Kopf, Thorax, Abdomen) gemГӨГҹ Behandlungspfad"],correct:1,explanation:"Polytrauma: xABCDE! x: massive Blutung (Tourniquet?), A: HWS+Atemweg, B: Pneumothorax?, C: HГӨmodynamik, D: GCS+Pupillen, E: alle Verletzungen."}]},
{id:66,title:"Polytrauma FuГҹgГӨnger vs. PKW",bpr:"polytrauma",scenario:"40-jГӨhrige FuГҹgГӨngerin, von PKW mit 50 km/h erfasst. Bewusstlos (GCS 7), offene Unterschenkelfraktur, V.a. SHT, HF 130, RR 90/60.",
steps:[
{q:"WГӨrmeerhalt вҖ“ warum so wichtig beim Polytrauma?",opts:["Nur bei Kindern bei stabilen KreislaufverhГӨltnissen","Hypothermie вҶ’ GerinnungsstГ¶rung вҶ’ verstГӨrkte Blutung ('letale Trias')","Nur kosmetisch unter kontinuierlichem Monitoring, abhГӨngig vom klinischen Verlauf und den erhobenen Vitalparametern","Komfort nach ABCDE-Reevaluation"],correct:1,explanation:"'Letale Trias': Hypothermie + Azidose + Koagulopathie вҶ’ WГӨrmeerhalt ist lebensrettend!"},
{q:"Schmerztherapie beim Polytrauma mit GCS 7?",opts:["Ibuprofen oral bei gesichertem Atemweg unter BerГјcksichtigung mГ¶glicher Differentialdiagnosen im Verlauf","Esketamin i.v. (auch bei Bewusstlosigkeit Schmerzwahrnehmung mГ¶glich)","Paracetamol rectal laut aktuellem Algorithmus","Keine bei Bewusstlosigkeit nach Sicherung der Vitalfunktionen"],correct:1,explanation:"Auch bewusstlose Patienten nehmen Schmerz wahr! Esketamin eignet sich gut beim Trauma."},
{q:"Was dokumentieren Sie am Tourniquet?",opts:["Patienten-Name","Gar nichts unter Beachtung der Kontraindikationen","Uhrzeit der Anlage!","Diagnose bei dokumentierter Indikation"],correct:2,explanation:"IMMER Uhrzeit der Tourniquet-Anlage dokumentieren! Essenziell fГјr die Klinik."},
{q:"Was gehГ¶rt zur 'letalen Trias'?",opts:["Schmerz, Angst, Atemnot","Hypothermie + Azidose + Koagulopathie","Hypotonie + Tachykardie + Oligurie","Nur Hypothermie mit anschlieГҹender Transportentscheidung"],correct:1,explanation:"Letale Trias: Hypothermie + Azidose + Koagulopathie. Alle drei verstГӨrken sich gegenseitig вҶ’ Teufelskreis."},
{q:"Welche TranexamsГӨure-Dosis geben Sie?",opts:["10 g i.v nach initialer Stabilisierung","5 g i.v gemГӨГҹ SOP des Rettungsdienstes","15 mg/kgKG i.v. (Kurzinfusion 15 min, max. 1000 mg)","100 mg i.v. Bolus bei fehlenden Kontraindikationen"],correct:2,explanation:"TranexamsГӨure SAA: 15 mg/kgKG langsam i.v. als Kurzinfusion Гјber 15 Minuten, max. 1000 mg. Nur innerhalb der ersten 3 Stunden nach Trauma."}
,
{q:"Гңbergabe (SINNHAFT): Handlungen (H) beim Polytrauma вҖ“ was wird oft vergessen?",opts:["Die Schmerztherapie unter BerГјcksichtigung des klinischen Bildes","Bewusst unterlassene MaГҹnahmen: z.B. keine Thoraxentlastung trotz V.a. Pneumothorax вҖ“ warum?","Das Wetter am Einsatzort mit Voranmeldung in der Zielklinik","Der Transportweg nach Ausschluss reversibler Ursachen"],correct:1,explanation:"Beim Polytrauma: Bewusst unterlassene MaГҹnahmen sind besonders wichtig! Z.B. 'Keine Intubation trotz GCS 7 вҖ“ suffiziente Eigenatmung, kurzer Transport.'."}]},
{id:67,title:"Akuter Schlaganfall mit Hemiparese",bpr:"schlaganfall",scenario:"72-jГӨhrige Frau, plГ¶tzlich SchwГӨche rechte KГ¶rperhГӨlfte, SprachstГ¶rung. Symptombeginn vor 45 Minuten. RR 190/100, BZ 120 mg/dl.",
steps:[
{q:"Welchen Screeningtest verwenden Sie?",opts:["qSOFA bei hГӨmodynamischer InstabilitГӨt","BE-FAST-Test","Wells-Score","GCS allein"],correct:1,explanation:"BE-FAST: Balance, Eyes, Face, Arm, Speech, Time вҶ’ Standardscreening fГјr Schlaganfall."},
{q:"RR 190/100. MГјssen Sie den RR senken?",opts:["Nur mit Glyceroltrinitrat unter Zeitdruck im Einsatzgeschehen","Ja, sofort Urapidil als initiale MaГҹnahme vor Transport","Ja, auf 120/80 bei gesicherter Diagnose und Indikation","Nein вҖ“ erst ab RRsyst > 220 und/oder RRdiast > 120"],correct:3,explanation:"Beim Schlaganfall: RR-Senkung erst ab RRsyst > 220 und/oder RRdiast > 120 mmHg."},
{q:"Was ist das Transportziel?",opts:["NГӨchstes Krankenhaus mit begleitender Sauerstofftherapie","Hausarzt nach differentialdiagnostischer AbwГӨgung","Stroke Unit nach regionalem Zuweisungskonzept","NГӨchste Notaufnahme im Rahmen der Notfallversorgung"],correct:2,explanation:"Transport zur Stroke Unit вҖ“ Kontakt aufnehmen. Time is brain!"},
{q:"Was bedeutet BE-FAST?",opts:["Blutdruck, EKG, Fieber bei persistierender Symptomatik trotz ErstmaГҹnahmen","Balance, Eyes, Face, Arm, Speech, Time","Schnell sein nach Anlage eines venГ¶sen Zugangs","Beatmung, EKG, Fieber gemГӨГҹ den Empfehlungen des Г„LRD"],correct:1,explanation:"BE-FAST: Balance (Gleichgewicht), Eyes (SehstГ¶rung), Face (GesichtslГӨhmung), Arm (ArmlГӨhmung), Speech (SprachstГ¶rung), Time (Zeit dokumentieren!)."},
{q:"Warum ist die Symptombeginn-Zeit so wichtig?",opts:["Egal unter Beachtung der Dosierungsgrenzen","Nur fГјr Statistik bei fortbestehender klinischer Verschlechterung","Nur Dokumentation mit paralleler Vorbereitung des Transports","Bestimmt ob Lysetherapie mГ¶glich ist (Zeitfenster!)"],correct:3,explanation:"Lysetherapie-Zeitfenster: i.v. rt-PA bis 4,5h nach Symptombeginn, mechanische Thrombektomie ggf. bis 24h. TIME IS BRAIN!"}
,
{q:"Гңbergabe (SINNHAFT): Welche Notfallereignis-Info (N) ist beim Schlaganfall am zeitkritischsten?",opts:["Wann der letzte Arztbesuch war nach dokumentierter Erstuntersuchung","Welche Medikamente zu Hause liegen unter Einbeziehung der Patientenanamnese","WANN: Exakter Symptombeginn oder Last-Seen-Well-Zeitpunkt (Lyse-Fenster!)","Ob ein Hausarzt bekannt ist bei fehlendem Ansprechen auf Ersttherapie, nach vorheriger AbklГӨrung aller reversiblen Ursachen gemГӨГҹ Algorithmus"],correct:2,explanation:"Beim Schlaganfall: Symptombeginn oder 'Last seen well'-Zeitpunkt bestimmt ob Lyse mГ¶glich ist (< 4,5h)! Die wichtigste Einzelinformation."}]},
{id:68,title:"Schlaganfall mit HypoglykГӨmie",bpr:"schlaganfall",scenario:"65-jГӨhriger Diabetiker, plГ¶tzliche Halbseitensymptomatik links. GCS 12. BZ 42 mg/dl!",
steps:[
{q:"Was ist hier die DD und muss SOFORT behandelt werden?",opts:["Nur Schlaganfall als EskalationsmaГҹnahme bei Therapieversagen","Intoxikation unter BerГјcksichtigung des Patientenalters","Epilepsie nach Erhebung eines Basis-Monitorings","HypoglykГӨmie вҖ“ kann Schlaganfall-Symptome imitieren!"],correct:3,explanation:"HypoglykГӨmie kann fokale neurologische Defizite verursachen und einen Schlaganfall imitieren! Sofort behandeln."},
{q:"BZ-Korrektur. Was erwarten Sie?",opts:["MГ¶gliche Besserung der Neurologie nach BZ-Normalisierung","Krampfanfall mit regelmГӨГҹiger Verlaufskontrolle","Keine Besserung bei Verdacht auf kritische Verschlechterung","Verschlechterung unter Beachtung mГ¶glicher Wechselwirkungen"],correct:0,explanation:"Nach BZ-Korrektur kГ¶nnen hypoglykГӨmie-bedingte neurologische Defizite sich rasch bessern."},
{q:"BZ normal, Hemiparese persistiert. Was nun?",opts:["Entlassung als leitliniengerechte NotfallmaГҹnahme","Abwarten nach klinischer EinschГӨtzung","Transport Stroke Unit вҖ“ echter Schlaganfall trotz HypoglykГӨmie mГ¶glich","Weitere Glucose gemГӨГҹ Behandlungspfad"],correct:2,explanation:"Persistierende Neurologie nach BZ-Normalisierung вҶ’ V.a. echten Schlaganfall вҶ’ Stroke Unit!"},
{q:"Wie hoch dosieren Sie Glucose bei HypoglykГӨmie?",opts:["100 g bei stabilen KreislaufverhГӨltnissen","50 g unter kontinuierlichem Monitoring","2 g nach ABCDE-Reevaluation","8-10 g i.v. (max. 20%ig)"],correct:3,explanation:"Erwachsene: 8-10 g Glucose i.v., max. 20%ig. BZ-Kontrolle nach 5 min. Ziel > 90 mg/dl."},
{q:"Was dokumentieren Sie fГјr die Stroke Unit?",opts:["Nur Medikamente bei gesichertem Atemweg","Nur Name laut aktuellem Algorithmus","BE-FAST-Ergebnis, Symptombeginn exakt, BZ, RR, GCS-Verlauf, Medikamente","Nur RR nach Sicherung der Vitalfunktionen"],correct:2,explanation:"Dokumentation: Exakter Symptombeginn(!), BE-FAST-Befunde, GCS, BZ (vor/nach Korrektur), RR, Medikamente, Antikoagulation."}
,
{q:"Гңbergabe (SINNHAFT): NotfallprioritГӨt (N) beim Stroke вҖ“ was gehГ¶rt zu D (Disability)?",opts:["Nur der GCS unter Beachtung der Kontraindikationen","GCS, BE-FAST-Befund, Pupillenstatus, Halbseitensymptomatik, BZ","Nur die Pupillen bei dokumentierter Indikation, wobei die Wirksamkeit engmaschig kontrolliert werden muss","Nur der BE-FAST-Test mit anschlieГҹender Transportentscheidung"],correct:1,explanation:"D beim Stroke: GCS, BE-FAST-Ergebnis (welche Defizite genau), Pupillen, Seite der Symptome, Blutzucker (HypoglykГӨmie ausschlieГҹen!)."}]},
{id:69,title:"Schlaganfall mit schwerem Bluthochdruck",bpr:"schlaganfall",scenario:"58-JГӨhriger, plГ¶tzlicher Vernichtungskopfschmerz, Erbrechen, GCS 9. RR 240/140. Nackensteifigkeit.",
steps:[
{q:"Woran denken Sie bei Vernichtungskopfschmerz + Nackensteifigkeit?",opts:["MigrГӨne nach initialer Stabilisierung, was jedoch in der aktuellen Situation kontraindiziert wГӨre","Spannungskopfschmerz gemГӨГҹ SOP des Rettungsdienstes","Sinusitis bei fehlenden Kontraindikationen","Subarachnoidalblutung (SAB) вҖ“ hГӨmorrhagischer Schlaganfall"],correct:3,explanation:"Vernichtungskopfschmerz + Meningismus вҶ’ V.a. Subarachnoidalblutung."},
{q:"RR 240/140 вҖ“ Senkung?",opts:["Nur Glyceroltrinitrat unter BerГјcksichtigung des klinischen Bildes","Aggressiv senken mit Voranmeldung in der Zielklinik","Ja, vorsichtig mit Urapidil (RRsyst > 220 und/oder RRdiast > 120)","Nein nach Ausschluss reversibler Ursachen"],correct:2,explanation:"RRsyst > 220: Urapidil i.v. vorsichtig. Ziel: Kontrollierte Senkung, nicht zu aggressiv."},
{q:"Ziel-SpOвӮӮ?",opts:["Egal","88-92%","100%","94-98%"],correct:3,explanation:"Schlaganfall: Ziel-SpOвӮӮ 94-98%. Ggf. Sauerstoff-Gabe."},
{q:"Warum ist Nackensteifigkeit ein Warnsignal?",opts:["Nur Alter bei hГӨmodynamischer InstabilitГӨt","Nur Zugluft unter Zeitdruck im Einsatzgeschehen","Verspannung als initiale MaГҹnahme vor Transport","Meningismus вҶ’ Blut/EntzГјndung im Subarachnoidalraum"],correct:3,explanation:"Meningismus (Nackensteifigkeit): Reizung der HirnhГӨute durch Blut (SAB) oder Infektion (Meningitis). Alarmzeichen!"},
{q:"DГјrfen Sie ASS bei V.a. hГӨmorrhagischen Schlaganfall geben?",opts:["Ja bei gesicherter Diagnose und Indikation","Halbe Dosis mit begleitender Sauerstofftherapie","NEIN вҖ“ ASS ist kontraindiziert bei Blutung! DD erst in Klinik (CT)","Immer nach differentialdiagnostischer AbwГӨgung"],correct:2,explanation:"KEIN ASS prГӨklinisch bei V.a. hГӨmorrhagischen Schlaganfall! Erst nach CT-Diagnostik in Klinik."}
,
{q:"Гңbergabe (SINNHAFT): Welche Handlung (H) ist beim Schlaganfall besonders zu dokumentieren?",opts:["Nur ob OвӮӮ gegeben wurde im Rahmen der Notfallversorgung","Nur der Transport bei persistierender Symptomatik trotz ErstmaГҹnahmen","Nur die Lagerung nach Anlage eines venГ¶sen Zugangs und anschlieГҹende Reevaluation nach spГӨtestens 5 Minuten","RR-Management: Urapidil gegeben? Ziel-RR? BZ-Korrektur? Stroke-Unit-Voranmeldung?"],correct:3,explanation:"Stroke-Handlungen: RR-Senkung (nur bei >220/120!), BZ-Korrektur, OвӮӮ-Gabe, Voranmeldung Stroke-Unit, bewusst unterlassene Lyse (warum?)."}]},
{id:70,title:"Septischer Schock bei Pneumonie",bpr:"sepsis",scenario:"68-jГӨhriger Mann, seit 5 Tagen Husten + Fieber 39,5В°C. Heute: verwirrt, RR 85/50, HF 130, AF 26/min, SpOвӮӮ 88%.",
steps:[
{q:"qSOFA-Score berechnen. Wie viele Punkte?",opts:["0 gemГӨГҹ den Empfehlungen des Г„LRD","2 unter Beachtung der Dosierungsgrenzen","3 (AF вүҘ22 + BewusstseinsverГӨnderung + RRsyst вүӨ100)","1 bei fortbestehender klinischer Verschlechterung, sofern keine allergischen Reaktionen in der Vorgeschichte bekannt sind"],correct:2,explanation:"qSOFA: AF вүҘ22 (ja) + BewusstseinsverГӨnderung (ja) + RRsyst вүӨ100 (ja) = 3 Punkte вүҘ 2 вҶ’ V.a. Sepsis."},
{q:"Wichtigste SofortmaГҹnahme?",opts:["Furosemid mit paralleler Vorbereitung des Transports","i.v.-Zugang (mГ¶glichst 2) + Volumentherapie VEL","Antibiotikum nach dokumentierter Erstuntersuchung","Urapidil unter Einbeziehung der Patientenanamnese"],correct:1,explanation:"Volumentherapie ist die wichtigste prГӨklinische MaГҹnahme beim septischen Schock."},
{q:"Woran denken Sie bei der Zugangsanlage?",opts:["Nur zentral bei fehlendem Ansprechen auf Ersttherapie","MГ¶glichst 2 groГҹlumige ZugГӨnge fГјr aggressive Volumentherapie","i.o. immer besser als EskalationsmaГҹnahme bei Therapieversagen","Nur ein Zugang reicht unter BerГјcksichtigung des Patientenalters"],correct:1,explanation:"MГ¶glichst 2 groГҹlumige i.v.-ZugГӨnge fГјr ausreichende Volumentherapie bei Sepsis."},
{q:"Was bedeutet qSOFA-Score вүҘ 2?",opts:["Nur Fieber nach Erhebung eines Basis-Monitorings","Normal mit regelmГӨГҹiger Verlaufskontrolle","Verdacht auf Sepsis вҖ“ erhГ¶hte MortalitГӨt","Nur dehydriert bei Verdacht auf kritische Verschlechterung"],correct:2,explanation:"qSOFA вүҘ 2: V.a. Sepsis mit erhГ¶hter MortalitГӨt. Kriterien: AF вүҘ22, BewusstseinsverГӨnderung, RRsyst вүӨ100."},
{q:"Welche OвӮӮ-Gabe bei Sepsis?",opts:["Bedarfsgerecht, Ziel SpOвӮӮ 92-96%","Nur bei SpOвӮӮ < 80% unter Beachtung mГ¶glicher Wechselwirkungen","Immer 15 l/min als leitliniengerechte NotfallmaГҹnahme","Keine nach klinischer EinschГӨtzung"],correct:0,explanation:"BPR Sepsis: Bedarfsgerechte Sauerstoffgabe, Ziel-SpOвӮӮ 92-96%. Nicht unkontrolliert, aber bei Hypoxie indiziert."}
,
{q:"Гңbergabe (SINNHAFT): NotfallprioritГӨt (N) bei Sepsis вҖ“ welche Scores sollten integriert werden?",opts:["APGAR-Score gemГӨГҹ Behandlungspfad","Nur der BMI bei stabilen KreislaufverhГӨltnissen","Nur der GCS unter kontinuierlichem Monitoring","qSOFA-Score вүҘ2 und/oder NEWS2 вүҘ5, Laktat falls bekannt"],correct:3,explanation:"Sepsis-PrioritГӨt: qSOFA (AF, RR, Bewusstsein) und NEWS2 in die ABCDE-Befunde integrieren. Laktat-Wert falls bekannt вҶ’ Schweregrad."}]},
{id:71,title:"Urosepsis bei ГӨlterer Patientin",bpr:"sepsis",scenario:"80-jГӨhrige Frau, Pflegeheim. Seit Tagen Harnwegsinfekt. Heute: somnolent, Fieber 38,8В°C, RR 90/55, HF 120, AF 24.",
steps:[
{q:"qSOFA-Score?",opts:["1 nach ABCDE-Reevaluation","2 (Somnolenz + AF вүҘ22)","3 bei gesichertem Atemweg","0 laut aktuellem Algorithmus"],correct:1,explanation:"qSOFA: BewusstseinsverГӨnderung (somnolent) + AF вүҘ22 = 2 Punkte. RR knapp Гјber 100. V.a. Sepsis!"},
{q:"Therapie prГӨklinisch?",opts:["BasismaГҹnahmen, i.v.-Zugang, VEL, OвӮӮ, Transport","Antibiotikum i.v nach Sicherung der Vitalfunktionen","Furosemid unter Beachtung der Kontraindikationen","Urapidil bei dokumentierter Indikation"],correct:0,explanation:"PrГӨklinisch: ABCDE, i.v.-Zugang, Volumentherapie mit VEL, bedarfsgerechte OвӮӮ-Gabe. Antibiotika erst klinisch."},
{q:"Temperaturmessung вҖ“ warum dokumentieren?",opts:["Routine mit anschlieГҹender Transportentscheidung","Nur bei Kindern nach initialer Stabilisierung mit sofortiger Dokumentation im Einsatzprotokoll und Voranmeldung","Nicht wichtig gemГӨГҹ SOP des Rettungsdienstes","Fieber + Hypothermie sind beide prognostisch relevant bei Sepsis"],correct:3,explanation:"Temperatur dokumentieren: Sowohl Fieber als auch Hypothermie sind Sepsis-Zeichen mit prognostischer Bedeutung."},
{q:"Was ist der Infektfokus bei Urosepsis?",opts:["Lunge bei fehlenden Kontraindikationen","Harntrakt (Harnwegsinfekt вҶ’ Sepsis)","Abdomen unter BerГјcksichtigung des klinischen Bildes","Haut mit Voranmeldung in der Zielklinik"],correct:1,explanation:"Urosepsis: Harnwegsinfekt als Ausgangspunkt der Sepsis. HГӨufig bei ГӨlteren Frauen, DauerkathetertrГӨgerinnen."},
{q:"Wie schnell muss Antibiotika gegeben werden?",opts:["So schnell wie mГ¶glich вҖ“ 'each hour delay increases mortality'","Nur ambulant","Erst morgen","Innerhalb 1h in Klinik"],correct:3,explanation:"Antibiotika innerhalb 1h nach Diagnosestellung in Klinik. Jede Stunde VerzГ¶gerung erhГ¶ht die MortalitГӨt signifikant!"}
,
{q:"Гңbergabe (SINNHAFT): Handlungen (H) bei V.a. Sepsis вҖ“ was ist fГјr die Klinik am relevantesten?",opts:["Nur die Temperatur nach Ausschluss reversibler Ursachen","Volumenmenge + Wirkung (MAP-Anstieg?), OвӮӮ-Therapie, bewusst KEINE Antibiotika prГӨklinisch (BegrГјndung!)","Nur die Volumentherapie bei hГӨmodynamischer InstabilitГӨt","Nur ob ein Zugang liegt unter Zeitdruck im Einsatzgeschehen, abhГӨngig vom klinischen Verlauf und den erhobenen Vitalparametern"],correct:1,explanation:"Sepsis-Handlungen: Volumen (ml + MAP-Effekt), OвӮӮ (Ziel SpOвӮӮ), bewusst keine Antibiotika prГӨklinisch (вҶ’ erst Blutkulturen in Klinik!)."}]},
{id:72,title:"Meningokokken-Sepsis beim Jugendlichen",bpr:"sepsis",scenario:"17-JГӨhriger, seit 12h Fieber, Kopfschmerzen, Erbrechen. Jetzt: Petechien am ganzen KГ¶rper, GCS 11, RR 75/40, HF 150.",
steps:[
{q:"Was zeigen die Petechien bei Fieber und Schock?",opts:["V.a. Meningokokken-Sepsis/DIC","Drogenausschlag als initiale MaГҹnahme vor Transport","Allergische Reaktion unter BerГјcksichtigung mГ¶glicher Differentialdiagnosen im Verlauf","Thrombozytose bei gesicherter Diagnose und Indikation"],correct:0,explanation:"Petechien + Fieber + Schock beim Jugendlichen вҶ’ V.a. Meningokokken-Sepsis mit DIC (Waterhouse-Friderichsen-Syndrom)."},
{q:"Wie aggressiv therapieren Sie den Volumenmangel?",opts:["Kein Volumen mit begleitender Sauerstofftherapie","Aggressiv вҖ“ groГҹzГјgige VEL-Gabe Гјber 2 ZugГӨnge","ZurГјckhaltend nach differentialdiagnostischer AbwГӨgung","Nur 250 ml im Rahmen der Notfallversorgung"],correct:1,explanation:"Septischer Schock erfordert aggressive Volumentherapie! MГ¶glichst 2 groГҹlumige ZugГӨnge."},
{q:"Eigenschutz?",opts:["Mundschutz/FFP2 вҖ“ Meningokokken sind per TrГ¶pfcheninfektion Гјbertragbar","Nur Handschuhe bei persistierender Symptomatik trotz ErstmaГҹnahmen","Egal nach Anlage eines venГ¶sen Zugangs, nach vorheriger AbklГӨrung aller reversiblen Ursachen gemГӨГҹ Algorithmus","Kein Schutz nГ¶tig gemГӨГҹ den Empfehlungen des Г„LRD"],correct:0,explanation:"Meningokokken: TrГ¶pfcheninfektion вҶ’ FFP2-Maske, Handschuhe, postexpositionelle Prophylaxe erwГӨgen."},
{q:"Was ist die postexpositionelle Prophylaxe bei Meningokokken?",opts:["Antibiotikum (z.B. Rifampicin/Ciprofloxacin) fГјr Kontaktpersonen","HГӨndewaschen unter Beachtung der Dosierungsgrenzen","Impfung sofort bei fortbestehender klinischer Verschlechterung","Keine nГ¶tig mit paralleler Vorbereitung des Transports"],correct:0,explanation:"Postexpositionsprophylaxe: Antibiotikum fГјr enge Kontaktpersonen (Haushalts-, Mund-zu-Mund-Kontakt). Gesundheitsamt informieren!"},
{q:"Welche Lagerung bei Meningokokken-Sepsis mit Schock?",opts:["OberkГ¶rper hoch nach dokumentierter Erstuntersuchung","Schocklage / flach mit BeinerhГ¶hung","Kopftieflage unter Einbeziehung der Patientenanamnese","Seitenlage bei fehlendem Ansprechen auf Ersttherapie"],correct:1,explanation:"Septischer Schock: Flache Lagerung, ggf. Beine hoch. Bei BewusstseinseinschrГӨnkung: stabile Seitenlage."}
,
{q:"Гңbergabe (SINNHAFT): Notfallereignis (N) bei Sepsis вҖ“ was beschreibt das WAS und WIE?",opts:["Nur: Patient hat Fieber als EskalationsmaГҹnahme bei Therapieversagen","Nur die TemperaturhГ¶he unter BerГјcksichtigung des Patientenalters","Nur den Infektionserreger nach Erhebung eines Basis-Monitorings","WAS: V.a. Sepsis/septischer Schock, WIE: wahrscheinlicher Fokus (Pneumonie, Harnwegsinfekt, Wunde)"],correct:3,explanation:"Notfallereignis bei Sepsis: Verdachtsdiagnose + vermuteter Fokus (Pneumonie? Urosepsis? Wundinfekt?). Bestimmt die empirische Antibiotikawahl in der Klinik."}]},
{id:73,title:"Niederspannungsunfall Haushalt",bpr:"stromunfall",scenario:"35-JГӨhrige, Stromschlag durch defektes HaushaltsgerГӨt (230V). Bei Bewusstsein, Strommarke an der Hand, Herzrasen, Muskelschmerzen.",
steps:[
{q:"Erste MaГҹnahme am Einsatzort?",opts:["Wasser geben mit regelmГӨГҹiger Verlaufskontrolle","Defibrillation bei Verdacht auf kritische Verschlechterung","Spannungsfreiheit sicherstellen (Sicherung raus!)","Sofort Patient anfassen unter Beachtung mГ¶glicher Wechselwirkungen"],correct:2,explanation:"EIGENSCHUTZ zuerst! Spannungsfreiheit herstellen. Bei Niederspannung <1kV: 1 m Sicherheitsabstand."},
{q:"Welche Diagnostik ist obligat?",opts:["BZ-Messung als leitliniengerechte NotfallmaГҹnahme","Temperatur nach klinischer EinschГӨtzung","Nur kГ¶rperliche Untersuchung","12-Kanal-EKG (HerzrhythmusstГ¶rungen!)"],correct:3,explanation:"12-Kanal-EKG obligat! StromunfГӨlle kГ¶nnen alle Formen von HRST auslГ¶sen (VF, VT, Bradykardie)."},
{q:"Transport auch bei aktuell unauffГӨlligem EKG?",opts:["Nein, wenn beschwerdefrei gemГӨГҹ Behandlungspfad","Ja вҖ“ verzГ¶gerte HRST mГ¶glich вҶ’ MonitorГјberwachung","Nur bei Kindern bei stabilen KreislaufverhГӨltnissen","Nur Hausarztempfehlung unter kontinuierlichem Monitoring"],correct:1,explanation:"Auch bei unauffГӨlligem EKG: Transport zur Гңberwachung вҖ“ verzГ¶gerte HRST und MyokardschГӨden mГ¶glich."},
{q:"Warum braucht jeder Stromunfall-Patient ein EKG?",opts:["Strom kann alle HRST auslГ¶sen вҖ“ auch zeitverzГ¶gert!","Nur bei Brustschmerz nach ABCDE-Reevaluation","Nur bei Hochspannung bei gesichertem Atemweg","Routine laut aktuellem Algorithmus, wobei die Wirksamkeit engmaschig kontrolliert werden muss"],correct:0,explanation:"Strom kann VF, VT, Bradykardie, AV-Blockierungen auslГ¶sen вҖ“ auch zeitverzГ¶gert. 12-Kanal-EKG obligat!"},
{q:"Wann kГ¶nnen Sie einen Stromunfall-Patienten vor Ort belassen?",opts:["Immer nach Sicherung der Vitalfunktionen","Sofort nach EKG unter Beachtung der Kontraindikationen","Nur bei Niederspannung bei dokumentierter Indikation","GrundsГӨtzlich Kliniktransport empfohlen вҖ“ auch bei unauffГӨlligem EKG"],correct:3,explanation:"GrundsГӨtzlich Kliniktransport empfohlen. VerzГ¶gerte HRST und MyokardschГӨden mГ¶glich."}
,
{q:"Гңbergabe (SINNHAFT): Notfallereignis (N) bei Stromunfall вҖ“ welche Kerninfo?",opts:["Nur ob der Patient Schmerzen hat mit anschlieГҹender Transportentscheidung","WAS: Verdachtsdiagnose, WIE: Ursache/AuslГ¶ser, WANN: Symptombeginn mit exakter Uhrzeit","Nur die Diagnose nennen nach initialer Stabilisierung","Nur den Transportweg gemГӨГҹ SOP des Rettungsdienstes"],correct:1,explanation:"Stromunfall: Beim Notfallereignis immer WAS (Verdachtsdiagnose), WIE (Ursache/AuslГ¶ser), WANN (exakter Zeitpunkt) strukturiert Гјbergeben."}]},
{id:74,title:"Hochspannungsunfall auf Baustelle",bpr:"stromunfall",scenario:"Bauarbeiter, Kontakt mit Hochspannungsleitung (20.000V). Schwere Verbrennungen Ein-/Austritt, bewusstlos, GCS 3.",
steps:[
{q:"Sicherheitsabstand bei Hochspannung >1kV?",opts:["10 Meter bei fehlenden Kontraindikationen","5 Meter вҖ“ Spannungsfreiheit durch Fachpersonal!","1 Meter unter BerГјcksichtigung des klinischen Bildes","50 Meter mit Voranmeldung in der Zielklinik"],correct:1,explanation:"Hochspannung >1kV: 5 Meter Sicherheitsabstand! Spannungsfreiheit nur durch Fachpersonal (Energieversorger/FW)."},
{q:"Patient bewusstlos, GCS 3. NГӨchster Schritt nach Spannungsfreiheit?",opts:["ABCDE вҖ“ Atemweg sichern, Kreislauf prГјfen","Erst 12-Kanal-EKG nach Ausschluss reversibler Ursachen","Erst Schmerztherapie bei hГӨmodynamischer InstabilitГӨt","Erst Verbrennungen versorgen"],correct:0,explanation:"ABCDE: Atemwegsicherung hat PrioritГӨt bei GCS 3. Kreislaufstillstand вҶ’ BPR Reanimation."},
{q:"Verbrennungen bei Hochspannung вҖ“ Besonderheit?",opts:["Nur oberflГӨchlich unter Zeitdruck im Einsatzgeschehen, was jedoch in der aktuellen Situation kontraindiziert wГӨre","Sichtbare Verletzungen unterschГӨtzen das AusmaГҹ вҖ“ innere SchГӨden!","Wie VerbrГјhungen als initiale MaГҹnahme vor Transport","Keine Verbrennung bei Strom bei gesicherter Diagnose und Indikation"],correct:1,explanation:"Hochspannung: Innere GewebeschГӨden weit Гјber sichtbare Strommarken hinaus! Rhabdomyolyse, OrganschГӨden."},
{q:"Was ist Rhabdomyolyse?",opts:["Knochenbruch mit begleitender Sauerstofftherapie","Zerfall von Skelettmuskulatur вҶ’ Myoglobinfreisetzung вҶ’ Nierenversagen","Hautschaden nach differentialdiagnostischer AbwГӨgung","NervenlГӨsion im Rahmen der Notfallversorgung"],correct:1,explanation:"Rhabdomyolyse: Muskelzerfall durch Strom вҶ’ Myoglobin im Blut вҶ’ verstopft Nierentubuli вҶ’ akutes Nierenversagen."},
{q:"Welche Volumentherapie bei Hochspannungsunfall?",opts:["Nur 100 ml bei persistierender Symptomatik trotz ErstmaГҹnahmen","GroГҹzГјgig VEL i.v. (Nierenschutz bei Rhabdomyolyse)","Keine nach Anlage eines venГ¶sen Zugangs und anschlieГҹende Reevaluation nach spГӨtestens 5 Minuten","Furosemid gemГӨГҹ den Empfehlungen des Г„LRD"],correct:1,explanation:"GroГҹzГјgige VEL-Gabe: VerdГјnnung des Myoglobins, Nierenperfusion aufrechterhalten вҶ’ Nierenschutz."}
,
{q:"Гңbergabe (SINNHAFT): NotfallprioritГӨt (N) bei Stromunfall вҖ“ nach welcher Struktur?",opts:["Alphabetisch nach Befunden unter Beachtung der Dosierungsgrenzen","Nach dem (x)ABCDE-Schema mit pathologischen Befunden und Vitalparametern","Nach Dringlichkeit der Diagnostik bei fortbestehender klinischer Verschlechterung","Nach persГ¶nlichem Ermessen mit paralleler Vorbereitung des Transports"],correct:1,explanation:"Stromunfall: NotfallprioritГӨt IMMER nach ABCDE strukturiert. Pathologische Befunde + Vitalparameter pro Buchstabe, auffГӨllige Befunde hervorheben."}]},
{id:75,title:"Blitzschlag",bpr:"stromunfall",scenario:"Wandergruppe, Blitzschlag. 2 Personen betroffen. Person A: bewusstlos, keine Atmung. Person B: bei Bewusstsein, verwirrt, Trommelfellruptur.",
steps:[
{q:"Bei Person A ohne Vitalzeichen вҖ“ wie gehen Sie vor?",opts:["BPR Reanimation вҖ“ Blitzschlag kann reversiblen Kreislaufstillstand verursachen","Nur Person B behandeln nach dokumentierter Erstuntersuchung","Tot, keine Reanimation unter Einbeziehung der Patientenanamnese","Abwarten bei fehlendem Ansprechen auf Ersttherapie"],correct:0,explanation:"Blitzschlag: HГӨufig reversibel! Reanimation hat gute Erfolgsaussichten вҖ“ sofort CPR beginnen."},
{q:"Person B вҖ“ welche Untersuchung?",opts:["Nur Ohren anschauen als EskalationsmaГҹnahme bei Therapieversagen","Keine unter BerГјcksichtigung des Patientenalters","12-Kanal-EKG + Neurologie + Bewusstsein Гјberwachen","Nur Trommelfell nach Erhebung eines Basis-Monitorings"],correct:2,explanation:"12-Kanal-EKG (HRST), neurologische Untersuchung, GCS-Verlauf. Trommelfellruptur ist hГӨufig."},
{q:"Beide Patienten: Transport?",opts:["Keiner mit regelmГӨГҹiger Verlaufskontrolle","Beide in Klinik mit MonitorГјberwachung","Nur Person A bei Verdacht auf kritische Verschlechterung","Nur Person B unter Beachtung mГ¶glicher Wechselwirkungen"],correct:1,explanation:"ALLE Blitzschlag-Opfer mГјssen klinisch Гјberwacht werden вҖ“ auch bei initial gutem Zustand."},
{q:"Warum gilt bei Blitzschlag 'Reverse Triage'?",opts:["Leichtverletzte zuerst als leitliniengerechte NotfallmaГҹnahme","Normal triagieren nach klinischer EinschГӨtzung","Scheinbar Tote zuerst behandeln вҖ“ Blitzschlag hat hohe ROSC-Rate!","Wie immer gemГӨГҹ Behandlungspfad"],correct:2,explanation:"Reverse Triage bei Blitzschlag: Patienten ohne Vitalzeichen zuerst behandeln! Hohe Chance auf erfolgreiche Reanimation."},
{q:"Welche Verletzungen sind typisch bei Blitzschlag?",opts:["HRST, Trommelfellruptur, Lichtenberg-Figuren, neurologische SchГӨden","Nur Frakturen bei stabilen KreislaufverhГӨltnissen, sofern keine allergischen Reaktionen in der Vorgeschichte bekannt sind","Nur Bewusstlosigkeit unter kontinuierlichem Monitoring","Nur Verbrennungen nach ABCDE-Reevaluation"],correct:0,explanation:"Blitzschlag: HRST (VF!), Trommelfellruptur, Lichtenberg-Figuren (Hautzeichnung), Augenverletungen, neurologische SchГӨden."}
,
{q:"Гңbergabe (SINNHAFT): Handlungen (H) bei Stromunfall вҖ“ was wird oft vergessen?",opts:["Die Einsatznummer bei gesichertem Atemweg","Bewusst unterlassene MaГҹnahmen und deren BegrГјndung","Der Name des Fahrers laut aktuellem Algorithmus mit sofortiger Dokumentation im Einsatzprotokoll und Voranmeldung","Die Transportzeit nach Sicherung der Vitalfunktionen"],correct:1,explanation:"Stromunfall: Bei Handlungen nicht nur WAS getan wurde, sondern auch was bewusst NICHT getan wurde + BegrГјndung. ErmГ¶glicht dem Team die Entscheidung zu prГјfen."}]},
{id:76,title:"VerbrГјhung Kleinkind",bpr:"thermisch",scenario:"2-jГӨhriges Kind hat Topf mit heiГҹem Wasser vom Herd gezogen. VerbrГјhung Brust und Arme, ca. 15% VKOF. Schreit, starke Schmerzen.",
steps:[
{q:"KГјhlung durch Rettungsdienst?",opts:["10 min kaltes Wasser unter Beachtung der Kontraindikationen","Eis auflegen bei dokumentierter Indikation","NEIN вҖ“ keine aktive KГјhlung! Bereits durchgefГјhrte KГјhlung beenden","Ja, sofort mit kaltem Wasser mit anschlieГҹender Transportentscheidung"],correct:2,explanation:"BPR: Keine aktive KГјhlung durch Rettungsdienstpersonal! Hypothermiegefahr v.a. bei Kindern!"},
{q:"Volumentherapie beim Kind mit 15% VKOF (12 kgKG)?",opts:["Max. 10 ml/kgKG/h = max. 120 ml/h","500 ml Bolus nach initialer Stabilisierung","1 Liter/h gemГӨГҹ SOP des Rettungsdienstes","Kein Volumen nГ¶tig bei fehlenden Kontraindikationen"],correct:0,explanation:"Kinder: max. 10 ml/kgKG/h. Bei <10% VKOF und Klinik <30 min вҶ’ kann auf Zugang verzichtet werden."},
{q:"Was ist essenziell bei Kindern mit Verbrennungen?",opts:["Nur sterile Abdeckung unter BerГјcksichtigung des klinischen Bildes","WГӨrmeerhalt (Normothermie > 36В°C) + Schmerztherapie","Nur Wundversorgung mit Voranmeldung in der Zielklinik","Nur Schmerztherapie nach Ausschluss reversibler Ursachen"],correct:1,explanation:"WГӨrmeerhalt hat hГ¶chste PrioritГӨt bei Kindern! Thermomonitoring, Rettungsdecke, vorgeheizter RTW."},
{q:"Wie schГӨtzen Sie die VKOF beim Kind?",opts:["Nur raten bei hГӨmodynamischer InstabilitГӨt","9er-Regel wie Erwachsener unter Zeitdruck im Einsatzgeschehen","Kindliche HandflГӨchenregel (1 HandflГӨche вүҲ 1% VKOF) oder Lund-Browder","Immer 50% als initiale MaГҹnahme vor Transport"],correct:2,explanation:"Kinder: HandflГӨchenregel (1 HandflГӨche = 1% VKOF) oder Lund-Browder-Schema (altersadaptiert). 9er-Regel erst ab ~15 Jahren."},
{q:"Ab welcher VKOF ist die Verbrennung beim Kind schwer?",opts:["Ab 30% bei gesicherter Diagnose und Indikation","Ab ca. 10% вҶ’ schwere Verbrennung beim Kind","Ab 5% mit begleitender Sauerstofftherapie","Ab 50% nach differentialdiagnostischer AbwГӨgung"],correct:1,explanation:"Kinder: Ab ca. 10% VKOF gilt die Verbrennung als schwer. Ab 15% VKOF вҶ’ immer Verbrennungszentrum."}
,
{q:"Гңbergabe (SINNHAFT): Notfallereignis (N) bei Thermische Verletzung/Verbrennung вҖ“ welche Kerninfo?",opts:["Nur den Transportweg im Rahmen der Notfallversorgung","WAS: Verdachtsdiagnose, WIE: Ursache/AuslГ¶ser, WANN: Symptombeginn mit exakter Uhrzeit","Nur die Diagnose nennen bei persistierender Symptomatik trotz ErstmaГҹnahmen","Nur ob der Patient Schmerzen hat nach Anlage eines venГ¶sen Zugangs"],correct:1,explanation:"Thermische Verletzung/Verbrennung: Beim Notfallereignis immer WAS (Verdachtsdiagnose), WIE (Ursache/AuslГ¶ser), WANN (exakter Zeitpunkt) strukturiert Гјbergeben."}]},
]);
